INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS3HM9KDXYRYKQEDN1YMNX60','services','audiology-services','{"title":"Audiology Services | JC Audiology","route":"/audiology-services/","excerpt":"JC Audiology provides expert hearing care to help you stay connected to the sounds that matter most.","body_html":"<div class=\"astro-element astro-element-69dc79d e-con-full e-flex e-con e-child\" data-id=\"69dc79d\" data-element_type=\"container\" data-e-type=\"container\">\n\t\t\t\t<div class=\"astro-element astro-element-b5bc4fa astro-widget astro-widget-theme-post-content\" data-id=\"b5bc4fa\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"theme-post-content.default\">\n\t\t\t\t\t\t\t<div data-astro-type=\"astro-page\" data-astro-id=\"4953\" class=\"astro astro-4953\" data-astro-post-type=\"page\">\n\t\t\t\t<div class=\"astro-element astro-element-78a0079 e-flex e-con-boxed e-con e-parent\" data-id=\"78a0079\" data-element_type=\"container\" data-e-type=\"container\">\n\t\t\t\t\t<div class=\"e-con-inner\">\n\t\t\t\t<div class=\"astro-element astro-element-6405f18 astro-widget astro-widget-text-editor\" data-id=\"6405f18\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>JC Audiology provides expert hearing care to help you stay connected to the sounds that matter most.</p><p>From comprehensive hearing evaluations, hearing aid fittings, and excellent after-care services, our Lutz, FL, audiologists are here to support you with compassionate and personalized hearing care.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t<div class=\"astro-element astro-element-dc07a18 astro-widget-divider--view-line astro-widget astro-widget-divider\" data-id=\"dc07a18\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"divider.default\">\n\t\t\t\t\t\t\t<div class=\"astro-divider\">\n\t\t\t<span class=\"astro-divider-separator\">\n\t\t\t\t\t\t</span>\n\t\t</div>\n\t\t\t\t\t\t</div>\n\t\t\t\t<div class=\"astro-element astro-element-0a9bc56 astro-widget astro-widget-text-editor\" data-id=\"0a9bc56\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<h2 id=\"audiology-services-in-lutz-fl\">Audiology Services in Lutz, FL</h2><h3 id=\"hearing-evaluations\">Hearing Evaluations</h3><p>At JC Audiology, your journey to better hearing starts with a thorough hearing evaluation.</p><p>Our Lutz, FL audiologist and hearing aid specialist use safe, non-invasive tests to check how well you hear.</p><p style=\"font-family: Arial, Helvetica, sans-serif !important; font-style: normal !important; font-synthesis: none !important;\"><strong style=\"font-family: Arial, Helvetica, sans-serif !important; font-style: normal !important; font-synthesis: none !important; font-weight: 700 !important;\">Which hearing test is the best?</strong></p><p>The right hearing test depends on your needs or concerns. When needed, a comprehensive hearing evaluation may be performed. Below are some of the most common hearing tests:</p><ul><li>Pure-tone audiometry</li><li>Speech audiometry</li><li>Tympanometry</li><li>Auditory brainstem response (ABR)</li></ul>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t<div class=\"astro-element astro-element-f24c5ef custom-accordion astro-widget astro-widget-n-accordion\" data-id=\"f24c5ef\" data-element_type=\"widget\" data-e-type=\"widget\" data-settings=\"{&quot;default_state&quot;:&quot;all_collapsed&quot;,&quot;max_items_expended&quot;:&quot;one&quot;,&quot;n_accordion_animation_duration&quot;:{&quot;unit&quot;:&quot;ms&quot;,&quot;size&quot;:400,&quot;sizes&quot;:[]}}\" data-widget_type=\"nested-accordion.default\">\n\t\t\t\t\t\t\t<div class=\"e-n-accordion\" aria-label=\"Accordion. Open links with Enter or Space, close with Escape, and navigate with Arrow Keys\">\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-2540\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"1\" tabindex=\"0\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-2540\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"can-i-test-my-own-hearing\"> Can I test my own hearing? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-2540\" class=\"astro-element astro-element-93f3929 e-con-full e-flex e-con e-child\" data-id=\"93f3929\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-65b65e0 astro-widget astro-widget-text-editor\" data-id=\"65b65e0\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>You <em>can</em> test your own hearing through online hearing tests and apps that offer basic screening. However, these tests donâ€™t replace the accuracy of a professional hearing test. Getting a professional hearing test from an audiologist is still the best option.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-2541\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"2\" tabindex=\"-1\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-2541\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"are-online-hearing-tests-any-good\"> Are online hearing tests any good? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-2541\" class=\"astro-element astro-element-3080a78 e-con-full e-flex e-con e-child\" data-id=\"3080a78\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-a39331e astro-widget astro-widget-text-editor\" data-id=\"a39331e\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>Again, online hearing tests can give you a general idea of how well you hear, but they cannot replace a full evaluation by an audiologist.</p><p>Online hearing tests just check if you can hear tones through headphones or speakers. They canâ€™t identify the exact type or cause of hearing loss, assess how clearly you understand speech, and detect underlying medical conditions that may be affecting your hearing.</p><p>At JC Audiology, we offer accurate, comprehensive testing to help you hear your best.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t</div>\n\t\t\t\t\t\t</div>\n\t\t\t\t<div class=\"astro-element astro-element-9695b32 astro-widget astro-widget-text-editor\" data-id=\"9695b32\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<h3 id=\"tinnitus-evaluations-and-treatment\">Tinnitus Evaluations and Treatment</h3><p>If you are hearing ringing, buzzing, or other disturbing sounds in your ears, you just might be dealing with tinnitus.</p><p>At JC Audiology, we provide thorough evaluations to determine the cause of your tinnitus. We also offer personalized treatment plans to help reduce the symptoms and improve your overall quality of life.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t<div class=\"astro-element astro-element-12685c9 custom-accordion astro-widget astro-widget-n-accordion\" data-id=\"12685c9\" data-element_type=\"widget\" data-e-type=\"widget\" data-settings=\"{&quot;default_state&quot;:&quot;all_collapsed&quot;,&quot;max_items_expended&quot;:&quot;one&quot;,&quot;n_accordion_animation_duration&quot;:{&quot;unit&quot;:&quot;ms&quot;,&quot;size&quot;:400,&quot;sizes&quot;:[]}}\" data-widget_type=\"nested-accordion.default\">\n\t\t\t\t\t\t\t<div class=\"e-n-accordion\" aria-label=\"Accordion. Open links with Enter or Space, close with Escape, and navigate with Arrow Keys\">\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-1930\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"1\" tabindex=\"0\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-1930\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"should-i-go-to-an-audiologist-for-tinnitus\"> Should I go to an audiologist for tinnitus? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-1930\" class=\"astro-element astro-element-5b1a192 e-con-full e-flex e-con e-child\" data-id=\"5b1a192\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-4b926c0 astro-widget astro-widget-text-editor\" data-id=\"4b926c0\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>Yes! An audiologist is trained to evaluate and treat tinnitus. If youâ€™re hearing phantom sounds or the typical â€œringing in the earsâ€, an audiologist at JC Audiology can perform a thorough examination to identify potential triggers and determine whether your tinnitus is connected to hearing loss.</p><p>Based on the results, we may recommend helpful tools like sound therapy, hearing aids with built-in masking features, or relaxation techniques to address tinnitus symptoms. Weâ€™ll also teach you how to manage the daily effects of tinnitus on your focus, sleep, and emotional well-being. </p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-1931\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"2\" tabindex=\"-1\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-1931\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"is-tinnitus-a-brain-problem\"> Is tinnitus a brain problem? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-1931\" class=\"astro-element astro-element-bbd4035 e-con-full e-flex e-con e-child\" data-id=\"bbd4035\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-25e8b3a astro-widget astro-widget-text-editor\" data-id=\"25e8b3a\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>While tinnitus often begins with the ears, it also involves the brainâ€™s auditory system. When hearing loss or damage limits the sound input to the brain, the brain may compensate by creating its own sound. This is where tinnitus enters the scene.</p><p>Many treatments for tinnitus are programmed to reduce the brainâ€™s perception of that sound. Approaches like sound therapy, hearing aids, or cognitive behavioral therapy (CBT) help retrain your brain and reduce how noticeable the ringing or buzzing becomes.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-1932\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"3\" tabindex=\"-1\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-1932\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"what-happens-if-tinnitus-is-not-treated\"> What happens if tinnitus is not treated? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-1932\" class=\"astro-element astro-element-1f452c9 e-con-full e-flex e-con e-child\" data-id=\"1f452c9\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-4682479 astro-widget astro-widget-text-editor\" data-id=\"4682479\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>Over time, untreated tinnitus may increase stress, anxiety, or frustration. Many people with tinnitus struggle to fall asleep or stay focused during the day.</p><p>If tinnitus is linked to untreated hearing loss, ignoring it can also lead to worsening hearing problems. By addressing tinnitus early, you can improve your comfort and prevent tinnitus from interfering with daily activities. Let our Lutz, FL audiologists guide you toward tinnitus relief!</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t</div>\n\t\t\t\t\t\t</div>\n\t\t\t\t<div class=\"astro-element astro-element-a739cc7 astro-widget-divider--view-line astro-widget astro-widget-divider\" data-id=\"a739cc7\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"divider.default\">\n\t\t\t\t\t\t\t<div class=\"astro-divider\">\n\t\t\t<span class=\"astro-divider-separator\">\n\t\t\t\t\t\t</span>\n\t\t</div>\n\t\t\t\t\t\t</div>\n\t\t\t\t<div class=\"astro-element astro-element-2ee7303 astro-widget astro-widget-text-editor\" data-id=\"2ee7303\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<h2 id=\"hearing-aid-services\">Hearing Aid Services</h2><p>Our friendly and compassionate team from JC Audiology is with you every step of your hearing journey. From your first appointment to follow-up appointments, you can count on our unwavering expertise and care. We want you to enjoy the best performance from your hearing aids. We offer a wide selection of <a href=\"../index.html\">hearing aids in Lutz, FL</a>.</p><h3 id=\"hearing-aid-fittings\"><strong>Hearing Aid Fittings</strong></h3><p>Hearing aids, no matter how â€œsmartâ€ they are designed to be, are not merely â€œplug and playâ€ devices. A proper fit is essential for comfort and better hearing. Our audiologists at JC Audiology tailor your hearing aids to your unique hearing profile. We understand that every hearing loss is unique, and we make sure that we perform real ear measurements to ensure each patient gets the best hearing improvement possible!</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t<div class=\"astro-element astro-element-463d492 custom-accordion astro-widget astro-widget-n-accordion\" data-id=\"463d492\" data-element_type=\"widget\" data-e-type=\"widget\" data-settings=\"{&quot;default_state&quot;:&quot;all_collapsed&quot;,&quot;max_items_expended&quot;:&quot;one&quot;,&quot;n_accordion_animation_duration&quot;:{&quot;unit&quot;:&quot;ms&quot;,&quot;size&quot;:400,&quot;sizes&quot;:[]}}\" data-widget_type=\"nested-accordion.default\">\n\t\t\t\t\t\t\t<div class=\"e-n-accordion\" aria-label=\"Accordion. Open links with Enter or Space, close with Escape, and navigate with Arrow Keys\">\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-7360\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"1\" tabindex=\"0\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-7360\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"how-long-does-it-take-to-get-fitted-for-a-hearing-aid\"> How long does it take to get fitted for a hearing aid? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-7360\" class=\"astro-element astro-element-68ffd89 e-con-full e-flex e-con e-child\" data-id=\"68ffd89\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-7c64daa astro-widget astro-widget-text-editor\" data-id=\"7c64daa\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>The hearing aid fitting process typically takes about one to two hours. After completing a thorough hearing evaluation, our audiologist will discuss your results and recommend hearing aids that best fit your hearing needs, lifestyle, and preferences.</p><p>Once a hearing aid is chosen, an audiologist will program it with precise measurements (including real-ear measurements) to ensure optimal sound quality and performance.</p><p>We will also show you how to properly insert, remove, and care for your new device, answering any questions you may have.</p><p>While the hearing aid fitting is usually completed in a single visit, follow-up appointments are expected. These follow-up appointments ensure comfort and are aimed to assist you in adjusting to amplified sounds over time.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-7361\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"2\" tabindex=\"-1\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-7361\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"how-does-an-audiologist-fit-a-hearing-aid\"> How does an audiologist fit a hearing aid? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-7361\" class=\"astro-element astro-element-ab8abf7 e-con-full e-flex e-con e-child\" data-id=\"ab8abf7\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-4971733 astro-widget astro-widget-text-editor\" data-id=\"4971733\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>The process of hearing aid fitting begins after a complete hearing evaluation. Based on the hearing test result, an audiologist will select the most appropriate hearing aid model and program it to meet your hearing profile.</p><p>During the fitting session, an audiologist will perform real-ear measurements to ensure the hearing aid provides the correct amplification for your ear canalâ€™s acoustics. The audiologist will also adjust the physical fit of the device.</p><p>When the right (and most comfortable) fit is achieved, youâ€™ll be taught how to insert and remove the hearing aid, clean and maintain it. This will also be the perfect time to discuss any related apps or accessories.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-7362\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"3\" tabindex=\"-1\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-7362\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"can-you-get-a-hearing-aid-without-a-test\"> Can you get a hearing aid without a test? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-7362\" class=\"astro-element astro-element-cc0b9d9 e-con-full e-flex e-con e-child\" data-id=\"cc0b9d9\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-b90124e astro-widget astro-widget-text-editor\" data-id=\"b90124e\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>Yes, you can purchase over-the-counter (OTC) hearing aids without a hearing test. However, OTC hearing aids donâ€™t offer the same personalized fitting or professional support as prescription hearing aids provided by an audiologist.</p><p>By having a professional hearing evaluation at JC Audiology, youâ€™ll receive expert advice, a customized solution, and the ability to identify any underlying medical conditions that could affect your hearing.</p><p>If youâ€™re uncertain about your hearing, starting with a comprehensive diagnostic test is the best way to ensure you get the right care.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t</div>\n\t\t\t\t\t\t</div>\n\t\t\t\t<div class=\"astro-element astro-element-67d9280 astro-widget astro-widget-text-editor\" data-id=\"67d9280\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<h3 id=\"hearing-aid-repair-and-cleaning\">Hearing Aid Repair and Cleaning</h3><p>Are your hearing aids not working as they should? We can help! Our audiologist and hearing aid specialists are trained to evaluate hearing aid issues and perform minor repairs in-office.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t<div class=\"astro-element astro-element-717bce0 custom-accordion astro-widget astro-widget-n-accordion\" data-id=\"717bce0\" data-element_type=\"widget\" data-e-type=\"widget\" data-settings=\"{&quot;default_state&quot;:&quot;all_collapsed&quot;,&quot;max_items_expended&quot;:&quot;one&quot;,&quot;n_accordion_animation_duration&quot;:{&quot;unit&quot;:&quot;ms&quot;,&quot;size&quot;:400,&quot;sizes&quot;:[]}}\" data-widget_type=\"nested-accordion.default\">\n\t\t\t\t\t\t\t<div class=\"e-n-accordion\" aria-label=\"Accordion. Open links with Enter or Space, close with Escape, and navigate with Arrow Keys\">\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-1180\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"1\" tabindex=\"0\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-1180\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"what-are-the-common-problems-that-require-hearing-aid-repair\"> What are the common problems that require hearing aid repair? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-1180\" class=\"astro-element astro-element-68215d5 e-con-full e-flex e-con e-child\" data-id=\"68215d5\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-014aec3 astro-widget astro-widget-text-editor\" data-id=\"014aec3\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>Some common issues that may need repair include:</p><ul><li>No sound or low volume</li><li>Distorted or fuzzy sound</li><li>Feedback or whistling</li><li>Visible damage</li></ul>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-1181\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"2\" tabindex=\"-1\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-1181\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"how-long-does-it-take-to-repair-a-hearing-aid\"> How long does it take to repair a hearing aid? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-1181\" class=\"astro-element astro-element-b1bb045 e-con-full e-flex e-con e-child\" data-id=\"b1bb045\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-c96c4db astro-widget astro-widget-text-editor\" data-id=\"c96c4db\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>The turnaround time for hearing aid repair depends on the issue. Minor fixes, such as replacing wax guards or cleaning tubing, can be completed in-house within a few minutes.</p><p>However, if your device has bigger issues that need manufacturer service, repairs might take several days to two weeks. </p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-1182\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"3\" tabindex=\"-1\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-1182\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"can-i-fix-my-hearing-aid-at-home\"> Can I fix my hearing aid at home? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-1182\" class=\"astro-element astro-element-c852914 e-con-full e-flex e-con e-child\" data-id=\"c852914\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-14135fb astro-widget astro-widget-text-editor\" data-id=\"14135fb\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>Technically, yes, you can fix some minor hearing aid issues at home. However, more complex device issues should be handled by a professional.</p><p>If your hearing aid isnâ€™t working properly, you can run basic troubleshooting. Most manufacturers also provide troubleshooting guides in their user manuals or apps.</p><p>If your hearing device still isnâ€™t working even after troubleshooting, it would be best to contact your audiologist or hearing aid provider.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t</div>\n\t\t\t\t\t\t</div>\n\t\t\t\t<div class=\"astro-element astro-element-27fbf67 astro-widget astro-widget-text-editor\" data-id=\"27fbf67\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<h3 id=\"hearing-protection\">Hearing Protection</h3><p>Noise can sneak up on your ears and cause lasting damage. At JC Audiology, we provide a wide selection of hearing protection. Whether itâ€™s for music, water activities, work, or recreation, hearing protection help you enjoy life while keeping your hearing healthy.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t<div class=\"astro-element astro-element-c6506d6 custom-accordion astro-widget astro-widget-n-accordion\" data-id=\"c6506d6\" data-element_type=\"widget\" data-e-type=\"widget\" data-settings=\"{&quot;default_state&quot;:&quot;all_collapsed&quot;,&quot;max_items_expended&quot;:&quot;one&quot;,&quot;n_accordion_animation_duration&quot;:{&quot;unit&quot;:&quot;ms&quot;,&quot;size&quot;:400,&quot;sizes&quot;:[]}}\" data-widget_type=\"nested-accordion.default\">\n\t\t\t\t\t\t\t<div class=\"e-n-accordion\" aria-label=\"Accordion. Open links with Enter or Space, close with Escape, and navigate with Arrow Keys\">\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-2070\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"1\" tabindex=\"0\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-2070\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"why-should-i-use-hearing-protection\"> Why should I use hearing protection? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-2070\" class=\"astro-element astro-element-d8caf6e e-con-full e-flex e-con e-child\" data-id=\"d8caf6e\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-c647c1b astro-widget astro-widget-text-editor\" data-id=\"c647c1b\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>Exposure to loud sounds can permanently damage your hearing. Wearing proper protection reduces your risk of damage and helps you maintain your hearing health for the long run.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-2071\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"2\" tabindex=\"-1\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-2071\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"are-custom-earplugs-better-than-store-bought-ones\"> Are custom earplugs better than store-bought ones? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-2071\" class=\"astro-element astro-element-9815a30 e-con-full e-flex e-con e-child\" data-id=\"9815a30\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-f7e21b5 astro-widget astro-widget-text-editor\" data-id=\"f7e21b5\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>Yes. Custom earplugs are made to fit the unique ear shape so they provide a more secure and comfortable fit compared to generic options. The snug fit also helps block out noise or water more effectively.</p><p>Another benefit of custom earplugs is the opportunity for customization. If you want reliable performance, comfort, and long-term value, custom earplugs are worth the investment.</p><p>Our Lutz, FL audiologist and hearing aid specialist can help you choose the right type and ensure the perfect fit.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t\t<details id=\"e-n-accordion-item-2072\" class=\"e-n-accordion-item\">\n\t\t\t\t<summary class=\"e-n-accordion-item-title\" data-accordion-index=\"3\" tabindex=\"-1\" aria-expanded=\"false\" aria-controls=\"e-n-accordion-item-2072\">\n\t\t\t\t\t<span class=\"e-n-accordion-item-title-header\"><h4 class=\"e-n-accordion-item-title-text\" id=\"can-i-still-hear-people-talking-with-earplugs-in\"> Can I still hear people talking with earplugs in? </h4></span>\n\t\t\t\t\t\t\t<span class=\"e-n-accordion-item-title-icon\">\n\t\t\t<span class=\"e-opened\"><i aria-hidden=\"true\" class=\"far fa-chevron-down\"></i></span>\n\t\t\t<span class=\"e-closed\"><i aria-hidden=\"true\" class=\"far fa-chevron-up\"></i></span>\n\t\t</span>\n\n\t\t\t\t\t\t</summary>\n\t\t\t\t<div role=\"region\" aria-labelledby=\"e-n-accordion-item-2072\" class=\"astro-element astro-element-fddf672 e-con-full e-flex e-con e-child\" data-id=\"fddf672\" data-element_type=\"container\" data-e-type=\"container\" data-settings=\"{&quot;background_background&quot;:&quot;classic&quot;}\">\n\t\t\t\t<div class=\"astro-element astro-element-223f7e5 astro-widget astro-widget-text-editor\" data-id=\"223f7e5\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"text-editor.default\">\n\t\t\t\t\t\t\t\t\t<p>Yes, many custom earplugs are smartly designed to reduce loud background noise while still letting speech remain clear. Theyâ€™re a great choice for musicians or anyone who needs to protect their hearing without losing the ability to communicate.</p>\t\t\t\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t</details>\n\t\t\t\t\t</div>\n\t\t\t\t\t\t</div>\n\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t\t\t\t</div>\n\t\t\t\t</div>","hero_title":"Audiology Services","body_content":[{"_type":"block","_key":"b-msuogv63","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-p2pihvz6","text":"JC Audiology provides expert hearing care to help you stay connected to the sounds that matter most.","marks":[]}]},{"_type":"block","_key":"b-ftgltz9v","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-zsf7wsfq","text":"From comprehensive hearing evaluations, hearing aid fittings, and excellent after-care services, our Lutz, FL, audiologists are here to support you with compassionate and personalized hearing care.","marks":[]}]},{"_type":"block","_key":"b-r5vxmcxk","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-n9fnxq25","text":"Audiology Services in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-j428qkn3","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-n7g0jlmu","text":"Hearing Evaluations","marks":[]}]},{"_type":"block","_key":"b-uso5p64o","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-r3ax06s0","text":"At JC Audiology, your journey to better hearing starts with a thorough hearing evaluation.","marks":[]}]},{"_type":"block","_key":"b-d7dzcido","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-sqc7hn4g","text":"Our Lutz, FL audiologist and hearing aid specialist use safe, non-invasive tests to check how well you hear.","marks":[]}]},{"_type":"block","_key":"b-qgh96ry5","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-hnzwn1bs","text":"Which hearing test is the best?","marks":["strong"]}]},{"_type":"block","_key":"b-7ejqdntf","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9c407fis","text":"The right hearing test depends on your needs or concerns. When needed, a comprehensive hearing evaluation may be performed. Below are some of the most common hearing tests:","marks":[]}]},{"_type":"block","_key":"b-lnbk0x5g","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-yfeodn8k","text":"Pure-tone audiometry","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-2dtq1yju","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-jdl3nrsi","text":"Speech audiometry","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-d9jp68he","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-x4uyq6a7","text":"Tympanometry","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-gaf4nl1t","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-h895el4r","text":"Auditory brainstem response (ABR)","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-9llkj3sk","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-7rre68b6","text":"Tinnitus Evaluations and Treatment","marks":[]}]},{"_type":"block","_key":"b-2iir7iue","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-4j93p2gv","text":"If you are hearing ringing, buzzing, or other disturbing sounds in your ears, you just might be dealing with tinnitus.","marks":[]}]},{"_type":"block","_key":"b-3fxynwri","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-hzdbc8oo","text":"At JC Audiology, we provide thorough evaluations to determine the cause of your tinnitus. We also offer personalized treatment plans to help reduce the symptoms and improve your overall quality of life.","marks":[]}]},{"_type":"block","_key":"b-uk11c5ov","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-1xcpf962","text":"Hearing Aid Services","marks":[]}]},{"_type":"block","_key":"b-r93qz62e","style":"normal","markDefs":[{"_key":"link-1hhmc6ju","_type":"link","href":"../index.html"}],"children":[{"_type":"span","_key":"s-2l7melcq","text":"Our friendly and compassionate team from JC Audiology is with you every step of your hearing journey. From your first appointment to follow-up appointments, you can count on our unwavering expertise and care. We want you to enjoy the best performance from your hearing aids. We offer a wide selection of ","marks":[]},{"_type":"span","_key":"s-mqwx6b5h","text":"hearing aids in Lutz, FL","marks":["link-1hhmc6ju"]},{"_type":"span","_key":"s-7xvz7eyf","text":".","marks":[]}]},{"_type":"block","_key":"b-ii5ev3zq","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-wqffk0xr","text":"Hearing Aid Fittings","marks":["strong"]}]},{"_type":"block","_key":"b-vaarov6t","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-vp433td3","text":"Hearing aids, no matter how \"smart\" they are designed to be, are not merely \"plug and play\" devices. A proper fit is essential for comfort and better hearing. Our audiologists at JC Audiology tailor your hearing aids to your unique hearing profile. We understand that every hearing loss is unique, and we make sure that we perform real ear measurements to ensure each patient gets the best hearing improvement possible!","marks":[]}]},{"_type":"block","_key":"b-x1ajrwvd","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-7emieavt","text":"Hearing Aid Repair and Cleaning","marks":[]}]},{"_type":"block","_key":"b-80jpoy8y","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-95lpiix4","text":"Are your hearing aids not working as they should? We can help! Our audiologist and hearing aid specialists are trained to evaluate hearing aid issues and perform minor repairs in-office.","marks":[]}]},{"_type":"block","_key":"b-aylmufin","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-2kfjjcdr","text":"Hearing Protection","marks":[]}]},{"_type":"block","_key":"b-18wa5emh","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-uhinz9tr","text":"Noise can sneak up on your ears and cause lasting damage. At JC Audiology, we provide a wide selection of hearing protection. Whether it''s for music, water activities, work, or recreation, hearing protection help you enjoy life while keeping your hearing healthy.","marks":[]}]}]}',NULL,'2026-05-20 20:35:56');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS4FC5SXKE0W56GDB1KK244Z','services','audiology-services','{"title":"Audiology Services test","route":"/audiology-services/","meta_description":"JC Audiology provides expert hearing care to help you stay connected to the sounds that matter most.","body_content":[{"_type":"block","_key":"b-f00dd4c2","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-fd098e84","text":"JC Audiology provides expert hearing care to help you stay connected to the sounds that matter most.","marks":[]}]},{"_type":"block","_key":"b-911d62ee","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-35c49127","text":"From comprehensive hearing evaluations, hearing aid fittings, and excellent after-care services, our Lutz, FL, audiologists are here to support you with compassionate and personalized hearing care.","marks":[]}]},{"_type":"block","_key":"b-ae52ce3f","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-2e139c7b","text":"Audiology Services in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-879a42bd","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-92eca765","text":"Hearing Evaluations","marks":[]}]},{"_type":"block","_key":"b-03cd99b6","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3fefc48b","text":"At JC Audiology, your journey to better hearing starts with a thorough hearing evaluation.","marks":[]}]},{"_type":"block","_key":"b-52c9248f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-92f66dae","text":"Our Lutz, FL audiologist and hearing aid specialist use safe, non-invasive tests to check how well you hear.","marks":[]}]},{"_type":"block","_key":"b-5b9d64ec","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-936536c4","text":"Which hearing test is the best?","marks":["strong"]}]},{"_type":"block","_key":"b-5f56351d","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a160db87","text":"The right hearing test depends on your needs or concerns. When needed, a comprehensive hearing evaluation may be performed. Below are some of the most common hearing tests:","marks":[]}]},{"_type":"block","_key":"b-ec2e3be7","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9d39b0f0","text":"Pure-tone audiometry","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-7358cfe0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-cbcf5e8f","text":"Speech audiometry","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-be37734e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-64aa6c0a","text":"Tympanometry","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-02b3aede","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3a607032","text":"Auditory brainstem response (ABR)","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-51791282","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-c71d9d29","text":"Can I test my own hearing?","marks":[]}]},{"_type":"block","_key":"b-507619d6","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0b305369","text":"You ","marks":[]},{"_type":"span","_key":"s-e87753de","text":"can","marks":["em"]},{"_type":"span","_key":"s-77e132b6","text":" test your own hearing through online hearing tests and apps that offer basic screening. However, these tests don’t replace the accuracy of a professional hearing test. Getting a professional hearing test from an audiologist is still the best option.","marks":[]}]},{"_type":"block","_key":"b-85be3c98","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-bf41b979","text":"Are online hearing tests any good?","marks":[]}]},{"_type":"block","_key":"b-e8ed4df3","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a190ad94","text":"Again, online hearing tests can give you a general idea of how well you hear, but they cannot replace a full evaluation by an audiologist.","marks":[]}]},{"_type":"block","_key":"b-620a317a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b987eee6","text":"Online hearing tests just check if you can hear tones through headphones or speakers. They can’t identify the exact type or cause of hearing loss, assess how clearly you understand speech, and detect underlying medical conditions that may be affecting your hearing.","marks":[]}]},{"_type":"block","_key":"b-3053f8fb","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-852fb293","text":"At JC Audiology, we offer accurate, comprehensive testing to help you hear your best.","marks":[]}]},{"_type":"block","_key":"b-a9c8af5d","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-a6362648","text":"Tinnitus Evaluations and Treatment","marks":[]}]},{"_type":"block","_key":"b-43e53b44","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e0cdf3e4","text":"If you are hearing ringing, buzzing, or other disturbing sounds in your ears, you just might be dealing with tinnitus.","marks":[]}]},{"_type":"block","_key":"b-ecedc316","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8554f224","text":"At JC Audiology, we provide thorough evaluations to determine the cause of your tinnitus. We also offer personalized treatment plans to help reduce the symptoms and improve your overall quality of life.","marks":[]}]},{"_type":"block","_key":"b-c100ee5b","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-f253405d","text":"Should I go to an audiologist for tinnitus?","marks":[]}]},{"_type":"block","_key":"b-5b12030c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1c90e2c0","text":"Yes! An audiologist is trained to evaluate and treat tinnitus. If you\"re hearing phantom sounds or the typical Sringing in the ears⬝, an audiologist at JC Audiology can perform a thorough examination to identify potential triggers and determine whether your tinnitus is connected to hearing loss.","marks":[]}]},{"_type":"block","_key":"b-51e3aa98","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e955c42f","text":"Based on the results, we may recommend helpful tools like sound therapy, hearing aids with built-in masking features, or relaxation techniques to address tinnitus symptoms. We’ll also teach you how to manage the daily effects of tinnitus on your focus, sleep, and emotional well-being. ","marks":[]}]},{"_type":"block","_key":"b-50906f34","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-3efc2838","text":"Is tinnitus a brain problem?","marks":[]}]},{"_type":"block","_key":"b-2e8d298e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9620499b","text":"While tinnitus often begins with the ears, it also involves the brain’s auditory system. When hearing loss or damage limits the sound input to the brain, the brain may compensate by creating its own sound. This is where tinnitus enters the scene.","marks":[]}]},{"_type":"block","_key":"b-786549c7","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ddfb4550","text":"Many treatments for tinnitus are programmed to reduce the brain’s perception of that sound. Approaches like sound therapy, hearing aids, or cognitive behavioral therapy (CBT) help retrain your brain and reduce how noticeable the ringing or buzzing becomes.","marks":[]}]},{"_type":"block","_key":"b-41eff698","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-92003f7d","text":"What happens if tinnitus is not treated?","marks":[]}]},{"_type":"block","_key":"b-b47440ee","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6fb6781f","text":"Over time, untreated tinnitus may increase stress, anxiety, or frustration. Many people with tinnitus struggle to fall asleep or stay focused during the day.","marks":[]}]},{"_type":"block","_key":"b-23e0e2b5","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-7cb46992","text":"If tinnitus is linked to untreated hearing loss, ignoring it can also lead to worsening hearing problems. By addressing tinnitus early, you can improve your comfort and prevent tinnitus from interfering with daily activities. Let our Lutz, FL audiologists guide you toward tinnitus relief!","marks":[]}]},{"_type":"block","_key":"b-4ea93b6c","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-36184b70","text":"Hearing Aid Services","marks":[]}]},{"_type":"block","_key":"b-a4a47624","style":"normal","markDefs":[{"_key":"link-8974fa74","_type":"link","href":"../index.html"}],"children":[{"_type":"span","_key":"s-a626d476","text":"Our friendly and compassionate team from JC Audiology is with you every step of your hearing journey. From your first appointment to follow-up appointments, you can count on our unwavering expertise and care. We want you to enjoy the best performance from your hearing aids. We offer a wide selection of ","marks":[]},{"_type":"span","_key":"s-34598220","text":"hearing aids in Lutz, FL","marks":["link-8974fa74"]},{"_type":"span","_key":"s-fc02a992","text":".","marks":[]}]},{"_type":"block","_key":"b-b443780d","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-a1d9ec66","text":"Hearing Aid Fittings","marks":["strong"]}]},{"_type":"block","_key":"b-d1562f34","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-394b4fb2","text":"Hearing aids, no matter how Ssmart⬝ they are designed to be, are not merely Splug and play⬝ devices. A proper fit is essential for comfort and better hearing. Our audiologists at JC Audiology tailor your hearing aids to your unique hearing profile. We understand that every hearing loss is unique, and we make sure that we perform real ear measurements to ensure each patient gets the best hearing improvement possible!","marks":[]}]},{"_type":"block","_key":"b-0eeb4197","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-467375e6","text":"How long does it take to get fitted for a hearing aid?","marks":[]}]},{"_type":"block","_key":"b-387468b4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-79c98f58","text":"The hearing aid fitting process typically takes about one to two hours. After completing a thorough hearing evaluation, our audiologist will discuss your results and recommend hearing aids that best fit your hearing needs, lifestyle, and preferences.","marks":[]}]},{"_type":"block","_key":"b-cf1ab52b","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a99681f3","text":"Once a hearing aid is chosen, an audiologist will program it with precise measurements (including real-ear measurements) to ensure optimal sound quality and performance.","marks":[]}]},{"_type":"block","_key":"b-3d2ef139","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-bfd8f115","text":"We will also show you how to properly insert, remove, and care for your new device, answering any questions you may have.","marks":[]}]},{"_type":"block","_key":"b-85e5ea1a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-45f3cc29","text":"While the hearing aid fitting is usually completed in a single visit, follow-up appointments are expected. These follow-up appointments ensure comfort and are aimed to assist you in adjusting to amplified sounds over time.","marks":[]}]},{"_type":"block","_key":"b-cc86a2ed","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-51f7c4d3","text":"How does an audiologist fit a hearing aid?","marks":[]}]},{"_type":"block","_key":"b-2efe7582","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-39d9dfde","text":"The process of hearing aid fitting begins after a complete hearing evaluation. Based on the hearing test result, an audiologist will select the most appropriate hearing aid model and program it to meet your hearing profile.","marks":[]}]},{"_type":"block","_key":"b-3fc7c445","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ee62880f","text":"During the fitting session, an audiologist will perform real-ear measurements to ensure the hearing aid provides the correct amplification for your ear canal’s acoustics. The audiologist will also adjust the physical fit of the device.","marks":[]}]},{"_type":"block","_key":"b-15ecec2d","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-63af2586","text":"When the right (and most comfortable) fit is achieved, you’ll be taught how to insert and remove the hearing aid, clean and maintain it. This will also be the perfect time to discuss any related apps or accessories.","marks":[]}]},{"_type":"block","_key":"b-9ea7a529","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-c921a78e","text":"Can you get a hearing aid without a test?","marks":[]}]},{"_type":"block","_key":"b-78cee386","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-33ed03c2","text":"Yes, you can purchase over-the-counter (OTC) hearing aids without a hearing test. However, OTC hearing aids don’t offer the same personalized fitting or professional support as prescription hearing aids provided by an audiologist.","marks":[]}]},{"_type":"block","_key":"b-db5af057","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2a20f32b","text":"By having a professional hearing evaluation at JC Audiology, you’ll receive expert advice, a customized solution, and the ability to identify any underlying medical conditions that could affect your hearing.","marks":[]}]},{"_type":"block","_key":"b-afde3550","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-edd8c5b8","text":"If you’re uncertain about your hearing, starting with a comprehensive diagnostic test is the best way to ensure you get the right care.","marks":[]}]},{"_type":"block","_key":"b-773f1c83","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-0077a46a","text":"Hearing Aid Repair and Cleaning","marks":[]}]},{"_type":"block","_key":"b-c4fd627d","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ded2d4aa","text":"Are your hearing aids not working as they should? We can help! Our audiologist and hearing aid specialists are trained to evaluate hearing aid issues and perform minor repairs in-office.","marks":[]}]},{"_type":"block","_key":"b-72cfaa4f","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-a449c7fa","text":"What are the common problems that require hearing aid repair?","marks":[]}]},{"_type":"block","_key":"b-1e29aebc","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-36e833be","text":"Some common issues that may need repair include:","marks":[]}]},{"_type":"block","_key":"b-15f4dac1","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-7cdef57b","text":"No sound or low volume","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-0d61bf6a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-efde7e72","text":"Distorted or fuzzy sound","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-dc7048f4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-5353d513","text":"Feedback or whistling","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-ee3b292a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1fa1a29a","text":"Visible damage","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-e1f7c6f8","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-c142a17b","text":"How long does it take to repair a hearing aid?","marks":[]}]},{"_type":"block","_key":"b-5542eded","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-abadb2dc","text":"The turnaround time for hearing aid repair depends on the issue. Minor fixes, such as replacing wax guards or cleaning tubing, can be completed in-house within a few minutes.","marks":[]}]},{"_type":"block","_key":"b-bd63f807","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6ed85f18","text":"However, if your device has bigger issues that need manufacturer service, repairs might take several days to two weeks. ","marks":[]}]},{"_type":"block","_key":"b-32bfa110","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-cef326e9","text":"Can I fix my hearing aid at home?","marks":[]}]},{"_type":"block","_key":"b-80c3ca8f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c2e71260","text":"Technically, yes, you can fix some minor hearing aid issues at home. However, more complex device issues should be handled by a professional.","marks":[]}]},{"_type":"block","_key":"b-7c70ce50","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c629ae40","text":"If your hearing aid isn’t working properly, you can run basic troubleshooting. Most manufacturers also provide troubleshooting guides in their user manuals or apps.","marks":[]}]},{"_type":"block","_key":"b-5be5e86f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-d3fd1dc8","text":"If your hearing device still isn’t working even after troubleshooting, it would be best to contact your audiologist or hearing aid provider.","marks":[]}]},{"_type":"block","_key":"b-96c50398","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-410454ba","text":"Hearing Protection","marks":[]}]},{"_type":"block","_key":"b-ffb2fd74","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6c2a9717","text":"Noise can sneak up on your ears and cause lasting damage. At JC Audiology, we provide a wide selection of hearing protection. Whether it’s for music, water activities, work, or recreation, hearing protection help you enjoy life while keeping your hearing healthy.","marks":[]}]},{"_type":"block","_key":"b-40d7957b","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-f02c42b9","text":"Why should I use hearing protection?","marks":[]}]},{"_type":"block","_key":"b-931ba098","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-471b4206","text":"Exposure to loud sounds can permanently damage your hearing. Wearing proper protection reduces your risk of damage and helps you maintain your hearing health for the long run.","marks":[]}]},{"_type":"block","_key":"b-2e531077","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-329f9794","text":"Are custom earplugs better than store-bought ones?","marks":[]}]},{"_type":"block","_key":"b-65f88bf4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1be3475c","text":"Yes. Custom earplugs are made to fit the unique ear shape so they provide a more secure and comfortable fit compared to generic options. The snug fit also helps block out noise or water more effectively.","marks":[]}]},{"_type":"block","_key":"b-639e9449","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-11dbd257","text":"Another benefit of custom earplugs is the opportunity for customization. If you want reliable performance, comfort, and long-term value, custom earplugs are worth the investment.","marks":[]}]},{"_type":"block","_key":"b-c7b83829","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-867cd0cd","text":"Our Lutz, FL audiologist and hearing aid specialist can help you choose the right type and ensure the perfect fit.","marks":[]}]},{"_type":"block","_key":"b-484eec3a","style":"h4","markDefs":[],"children":[{"_type":"span","_key":"s-f7fa9c64","text":"Can I still hear people talking with earplugs in?","marks":[]}]},{"_type":"block","_key":"b-7ff7d482","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-24c1fa19","text":"Yes, many custom earplugs are smartly designed to reduce loud background noise while still letting speech remain clear. They’re a great choice for musicians or anyone who needs to protect their hearing without losing the ability to communicate.","marks":[]}]}]}',NULL,'2026-05-21 05:15:47');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS4GM46MKSNHR4JXW7ZZ4DWG','services','hearing-aids-products','{"title":"Hearing Aids & Products","route":"/hearing-aids-products/","meta_description":"Browse quality hearing aids from trusted brands with support from our audiologists. Find the right hearing solution and contact us to get started. test","body_content":[{"_type":"block","_key":"60rvnvto8","style":"normal","children":[{"_type":"span","_key":"gy3dktdul","text":"JC Audiology provides quality hearing aids and products in Lutz, FL.","marks":["strong","em"]}]},{"_type":"block","_key":"7zzwb22j2","style":"normal","children":[{"_type":"span","_key":"xu8p6qpww","text":"At JC Audiology, we want you to hear for life. Hearing your best helps you live your best! That’s why we are proud to offer and service many of today’s most trusted hearing aid brands. test"}]},{"_type":"block","_key":"ig25d668y","style":"normal","children":[{"_type":"span","_key":"bqr2jtq08","text":"Whether you already wear hearing aids or are just starting to explore your options, our caring audiologist and hearing aid specialist in Lutz, FL are here to help."}]},{"_type":"block","_key":"acpkgm3m2","style":"normal","children":[{"_type":"span","_key":"ulayobb8g","text":"We work with a variety of reliable hearing aid brands to make sure you get the right technology for your needs, your lifestyle, and your comfort."}]},{"_type":"block","_key":"zo1516osn","style":"h2","children":[{"_type":"span","_key":"5w94lojp4","text":"Hearing Aid Brands We Offer tset"}]},{"_type":"block","_key":"09xq3guxe","style":"h3","children":[{"_type":"span","_key":"75qeo5nvl","text":"test"}]},{"_type":"block","_key":"ue9k9appz","style":"h3","children":[{"_type":"span","_key":"k835prwru","text":"Oticon Hearing Aids"}]},{"_type":"block","_key":"oeymvr1u8","style":"normal","children":[{"_type":"span","_key":"5vhiuyfwz","text":"Oticon has been creating hearing solutions for more than 100 years. Their BrainHearing™ technology helps your brain process sound more easily, so you feel less tired and hear more clearly, even in noisy places. Models like Oticon Intent and Oticon Real offer Bluetooth, tinnitus relief, and a natural, comfortable listening experience. Oticon Intent 2, released in late 2024, builds on their Intent line with even better sound clarity and personalized listening."}]},{"_type":"block","_key":"cexy5t7q2","style":"h3","children":[{"_type":"span","_key":"aa65uekww","text":"Widex Hearing Aids"}]},{"_type":"block","_key":"dzzkw0emj","style":"normal","children":[{"_type":"span","_key":"r9k1tcxh5","text":"Widex is known for clear, natural sound. Their hearing aids process sound quickly with almost no delay. Popular models like Widex Moment and Widex SmartRIC help with tinnitus through Zen Therapy and work easily with smartphones for custom adjustments. Widex Allure, launched in early 2025, brings a new chip and the world’s first cloud-based fitting software (Compass Cloud) for a more natural hearing experience."}]},{"_type":"block","_key":"ds1tl0efs","style":"h3","children":[{"_type":"span","_key":"buqyj7bl3","text":"Phonak Hearing Aids"}]},{"_type":"block","_key":"7i5lrfmbq","style":"normal","children":[{"_type":"span","_key":"r7sbtmo61","text":"Phonak is a worldwide leader in hearing technology. Models like Phonak Lumity make speech clearer, while Phonak Naída provides strong amplification for people with severe hearing loss. The Phonak Audéo Sphere Infinio uses a deep neural network chip for excellent speech clarity, even in noisy places. Many Phonak aids are rechargeable, stream through Bluetooth, and resist water for daily convenience. Looking for the latest Phonak device? The Infinio platform was expanded in January 2025 with new custom in-the-ear models: Virto Titanium Infinio and Virto 10 NW O Infinio."}]},{"_type":"block","_key":"48saamqig","style":"h3","children":[{"_type":"span","_key":"th8o63etq","text":"Starkey Hearing Aids"}]},{"_type":"block","_key":"ex9yegv48","style":"normal","children":[{"_type":"span","_key":"sayj53f4q","text":"Starkey hearing aids combine great sound with wellness features such as fall alerts, activity tracking, and tinnitus relief. Models like Starkey Genesis AI and Evolv AI allow hands-free calling, app control, and come with rechargeable options—perfect for active lifestyles. The Edge AI line brings AI sound processing with an ultra-fast neuroprocessor chip and easier wireless streaming via LE Audio."}]},{"_type":"block","_key":"18co3y1ye","style":"h3","children":[{"_type":"span","_key":"3ln8t9fwk","text":"ReSound Hearing Aids"}]},{"_type":"block","_key":"ldvlmzry3","style":"normal","children":[{"_type":"span","_key":"2glrga0bx","text":"ReSound devices provide natural sound and strong wireless performance. Models like ReSound Vivia and ReSound ONE have personal sound settings, help you hear better in noisy places, and include tinnitus management. Many are rechargeable and work with iOS and Android for streaming. ReSound Vivia, launched in early February 2025, uses Deep Neural Network (DNN) artificial intelligence to improve hearing in noisy places. The ReSound Enzo IA, the world’s smallest rechargeable Super Power hearing aid, ideal for severe to profound loss."}]},{"_type":"block","_key":"fhqfwkep8","style":"h3","children":[{"_type":"span","_key":"sqx87j613","text":"Unitron Hearing Aids"}]},{"_type":"block","_key":"ro453dkvv","style":"normal","children":[{"_type":"span","_key":"smbswkud9","text":"Unitron focuses on comfort and easy use. Their technology changes with your surroundings for smoother listening. The Unitron Blu line includes Bluetooth streaming, app adjustments, and rechargeable batteries. The Smile platform is the newest batch for Unitron. It uses AI-powered sound tuning, improved Bluetooth, and a comfy design for an easy hearing experience."}]},{"_type":"block","_key":"nu01rk7gf","style":"h3","children":[{"_type":"span","_key":"fe0n9igg0","text":"Signia Hearing Aids"}]},{"_type":"block","_key":"1t3sqial1","style":"normal","children":[{"_type":"span","_key":"v30yu7jst","text":"Signia blends sleek design with strong performance. Models like Pure Charge&Go and Silk X offer clear speech in noise, Bluetooth connection, and discreet styles. Some have Own Voice Processing (OVP) so your voice sounds more natural to you. The Integrated Xperience (IX) platform includes popular models like Styletto AX, Pure Charge&Go AX, and Motion Charge&Go X."}]},{"_type":"block","_key":"mpir9a9xv","style":"h2","children":[{"_type":"span","_key":"40c6thqlt","text":"Frequently Asked Questions"}]},{"_type":"block","_key":"v7me0w1cg","style":"h3","children":[{"_type":"span","_key":"0x6j7bslz","text":"Which hearing aids are the most advanced?"}]},{"_type":"block","_key":"2ennywbdy","style":"normal","children":[{"_type":"span","_key":"fnavxcgme","text":"The best hearing aid for you depends on your hearing needs and lifestyle. Many top models have speech clarity features, rechargeability, Bluetooth, and noise reduction."}]},{"_type":"block","_key":"uq1s34avn","style":"h3","children":[{"_type":"span","_key":"7icloin7m","text":"Which brands help with tinnitus?"}]},{"_type":"block","_key":"8gp5xo8nz","style":"normal","children":[{"_type":"span","_key":"v0k4taqyl","text":"Oticon, Widex, and Starkey have special sound therapy programs to ease ringing in the ears."}]},{"_type":"block","_key":"7knxrn7g4","style":"h3","children":[{"_type":"span","_key":"h87619cuu","text":"What hearing aids work best for severe hearing loss?"}]},{"_type":"block","_key":"xckxyfvbx","style":"normal","children":[{"_type":"span","_key":"h9a3w6x34","text":"Powerful models from Oticon, Phonak, and Starkey are great for people with severe hearing loss."}]},{"_type":"block","_key":"k1nl3jasb","style":"h2","children":[{"_type":"span","_key":"5kxq4soro","text":"Custom Hearing Protection"}]},{"_type":"block","_key":"o7srq05ym","style":"normal","children":[{"_type":"span","_key":"1vy9edxc3","text":"We make custom-molded earplugs for work, hobbies, and daily life. They’re great for concerts, riding motorcycles, construction work, or sleeping. Custom plugs fit comfortably and reduce harmful noise without blocking all sounds."}]},{"_type":"block","_key":"pjpvfprsg","style":"h2","children":[{"_type":"span","_key":"7ojac8xlc","text":"Custom Ear Molds"}]},{"_type":"block","_key":"9xmndtcrx","style":"normal","children":[{"_type":"span","_key":"v64ts5v4g","text":"Custom ear molds are shaped just for your ears, giving you a better fit and improved sound quality. They work well for hearing aids, in ear monitors (IEM) for musicians, headsets, and swim and sleep plugs."}]},{"_type":"block","_key":"2nlksokaa","style":"normal","children":[{"_type":"span","_key":"moqti4r4a","text":"With the right ear molds, you can enjoy perfect fit with less chances of whistling, improved comfort, and confidence that your device stays put all day."}]},{"_type":"block","_key":"0zrtois0c","style":"h3","children":[{"_type":"span","_key":"0t2d025zh","text":"Frequently Asked Questions"}]},{"_type":"block","_key":"qjm9evxnq","style":"h3","children":[{"_type":"span","_key":"frmgmgg06","text":"Is it safe to sleep with earplugs?"}]},{"_type":"block","_key":"xmsy3i0rr","style":"normal","children":[{"_type":"span","_key":"579gnp9bj","text":"Yes, it is safe. Just make sure they are clean and fit well."}]},{"_type":"block","_key":"fz5yy5s51","style":"h3","children":[{"_type":"span","_key":"be7sx2494","text":"How long do custom ear molds last?"}]},{"_type":"block","_key":"308iggrw6","style":"normal","children":[{"_type":"span","_key":"k6442jru1","text":"Usually 2–5 years, depending on care and changes in your ears."}]},{"_type":"block","_key":"nks91xmai","style":"h3","children":[{"_type":"span","_key":"xm7awtwt1","text":"How do I clean my custom earplugs or ear molds?"}]},{"_type":"block","_key":"zd91ch28v","style":"normal","children":[{"_type":"span","_key":"msh87eban","text":"Wipe them daily with a soft, dry cloth. For a deeper clean, use mild soap and warm water, making sure they are completely dry before using them again. Avoid harsh chemicals, as they can damage the material."}]},{"_type":"block","_key":"katj75sj8","style":"h2","children":[{"_type":"span","_key":"re99cwk6a","text":"Assistive Listening Devices (ALDs)"}]},{"_type":"block","_key":"iw4buuxp6","style":"normal","children":[{"_type":"span","_key":"lvg0g014h","text":"ALDs help you hear better in certain situations-like watching TV, going to a meeting, or talking on the phone. They work with or without hearing aids and make sound clearer by reducing background noise. Examples include:"}]},{"_type":"block","_key":"vd39z0b0u","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ngrmyumu3","text":"TV Streamers: Send TV sound straight to your hearing aids"}]},{"_type":"block","_key":"gdm6qpugu","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"sflqrq1yl","text":"FM Systems: Make a teacher’s or speaker’s voice clearer in class or meetings"}]},{"_type":"block","_key":"5ptdugtoo","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"lvjktaunw","text":"Personal Amplifiers: Handheld devices for one-on-one or small group chats"}]},{"_type":"block","_key":"hrjj89uqr","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ky5gkk5w6","text":"Hearing Loop Systems: Installed in public places and work with telecoil hearing aids"}]},{"_type":"block","_key":"5kk70x0a3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"3l1gs8q1b","text":"Bluetooth Microphones: Clip-on mics that stream a person’s voice directly to your aids"}]},{"_type":"block","_key":"ewmkgvgpr","style":"h3","children":[{"_type":"span","_key":"m404ffzwr","text":"Frequently Asked Questions"}]},{"_type":"block","_key":"o9nc3r83q","style":"h3","children":[{"_type":"span","_key":"hhozs2mc1","text":"What is the most common type of ALD?"}]},{"_type":"block","_key":"vy6acnv8h","style":"normal","children":[{"_type":"span","_key":"2s08ie9sy","text":"TV streamers and personal amplifiers are very popular because they make voices and sound clearer at home, especially when there’s background noise."}]},{"_type":"block","_key":"15c1imhle","style":"h3","children":[{"_type":"span","_key":"fjhw5xu5y","text":"Can I use my smartphone as an ALD?"}]},{"_type":"block","_key":"6gxxrvlfc","style":"normal","children":[{"_type":"span","_key":"bwmvzlymm","text":"Yes. Some hearing aids work with smartphone features like Apple’s Live Listen, which turns your phone into a microphone and sends sound directly to your hearing aids."}]},{"_type":"block","_key":"ppesuloux","style":"h3","children":[{"_type":"span","_key":"ngcak4u8h","text":"Do ALDs work without hearing aids?"}]},{"_type":"block","_key":"vayl44umc","style":"normal","children":[{"_type":"span","_key":"ko1bouj1l","text":"Yes. While many ALDs connect to hearing aids, some (like personal amplifiers) can be used with regular headphones or earbuds."}]},{"_type":"block","_key":"olo7kbdga","style":"h2","children":[{"_type":"span","_key":"akgi4klhe","text":"Hearing Aids and Custom Hearing Protection in Lutz, FL"}]},{"_type":"block","_key":"f0epvwxj6","style":"normal","children":[{"_type":"span","_key":"bp0xm14z4","text":"If you need hearing aids, custom ear protection, or help with your current devices, JC Audiology is here for you. We’ll help you choose the right solution so you can hear and live better every day."}]},{"_type":"block","_key":"8thd40h93","style":"normal","children":[{"_type":"span","_key":"lea9g5gvx","text":"Call us today to schedule your appointment!"}]}]}',NULL,'2026-05-21 05:37:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS4GSGC57T47N46RGFFZXDZT','blog_posts','swimmers-ear-causes-symptoms-treatment-prevention','{"title":"Swimmer’s Ear Explained","route":"/swimmers-ear-causes-symptoms-treatment-prevention/","meta_description":"Swimmer’s ear causes pain, itching, and swelling. Learn symptoms, treatment, and prevention. Schedule with JC Audiology in Lutz, FL today. test","featured_image":{"id":"media-blog-c318f878-rechargeable-hearing-aids","provider":"local","width":800,"height":532,"alt":"Three friends sitting together at a café table, smiling and talking while enjoying drinks","meta":{"storageKey":"blog/c318f878-Rechargeable-Hearing-Aids.jpg","caption":null,"blurhash":null,"dominantColor":null},"filename":"c318f878-Rechargeable-Hearing-Aids.jpg","mimeType":"image/jpeg"},"body_content":[{"_type":"block","_key":"r0xmjawp8","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"u50buu2zk","text":"Swimmer’s ear is a common outer ear infection caused by trapped moisture, especially after swimming or bathing."}]},{"_type":"block","_key":"v76zqe79i","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"q6c2djc8q","text":"Early treatment helps relieve pain, itching, and swelling and prevents the infection from getting worse."}]},{"_type":"block","_key":"v9juczpvy","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"6gl3kea6o","text":"Simple prevention steps and professional care from an audiology clinic can keep your ears healthy and comfortable."}]},{"_type":"block","_key":"5m6awu7vh","style":"normal","children":[{"_type":"span","_key":"m1aj56rv0","text":"Swimmer’s ear is a painful and irritating ear condition that affects people of all ages. If you live in a warm, humid area like Florida or spend time around pools, lakes, or the beach, swimmer’s ear is something you should understand. In this guide, we explain what swimmer’s ear is, why it happens, how to treat it, and how to prevent it. Knowing the signs early can help you avoid discomfort and protect your hearing. test"}]},{"_type":"block","_key":"b79ull4ba","style":"normal","children":[{"_type":"span","_key":"c3esi9zw4","text":"At JC Audiology in Lutz, FL, we help patients recognize swimmer’s ear symptoms and provide safe, "},{"_type":"span","_key":"wjcuyw34m","text":"professional audiology care","marks":["gvbwkv4s4"]},{"_type":"span","_key":"bxkma9sws","text":" to restore ear health."}],"markDefs":[{"_type":"link","_key":"gvbwkv4s4","href":"../audiology-services/hearing-tests/index.html","blank":false}]},{"_type":"block","_key":"fcr9db19e","style":"h2","children":[{"_type":"span","_key":"p1s7n82me","text":"What Is Swimmer’s Ear?"}]},{"_type":"block","_key":"sqh0fchwq","style":"normal","children":[{"_type":"span","_key":"8tso7l4jf","text":"Swimmer’s ear, also called otitis externa, is an infection of the outer ear canal. This is the part of the ear that runs from the outside opening down to the eardrum. The infection usually starts when water gets trapped in the ear canal, creating a moist space where bacteria or fungus can grow."}]},{"_type":"block","_key":"34ukz6kfw","style":"normal","children":[{"_type":"span","_key":"0xdc9bxql","text":"Although the name suggests it only affects swimmers, swimmer’s ear can happen to anyone. Bathing, showering, sweating, or living in a humid climate can all increase the risk. Even people who have not been near a pool can develop swimmer’s ear."}]},{"_type":"block","_key":"72ynancta","style":"h2","children":[{"_type":"span","_key":"g07aj0mkg","text":"Why Swimmer’s Ear Is Common in Florida"}]},{"_type":"block","_key":"8t4d89wns","style":"normal","children":[{"_type":"span","_key":"5bclf9zw5","text":"Florida’s warm weather and high humidity make swimmer’s ear more common. Moisture stays in the ear longer, especially after swimming in a pool, lake, or ocean. The skin inside the ear canal becomes soft and more likely to get irritated or infected."}]},{"_type":"block","_key":"k617182si","style":"normal","children":[{"_type":"span","_key":"uaz6nycx2","text":"People who swim often, wear earbuds, or use hearing aids may also trap moisture in the ear. This increases the risk of irritation and infection over time."}]},{"_type":"block","_key":"ucqv2r4xc","style":"h2","children":[{"_type":"span","_key":"ar7go51h1","text":"Common Symptoms of Swimmer’s Ear"}]},{"_type":"block","_key":"u1ykggjj9","style":"normal","children":[{"_type":"span","_key":"20c418cpa","text":"Swimmer’s ear symptoms can start mild and get worse quickly if not treated. Common signs include:"}]},{"_type":"block","_key":"gt77635u3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ygg8neuoc","text":"Itchiness inside the ear canal"}]},{"_type":"block","_key":"03urmpz6o","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"jp05z7kat","text":"Redness or swelling around the ear opening"}]},{"_type":"block","_key":"a1qlk3itl","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"9281hn31c","text":"Ear pain that gets worse when touching or pulling the ear"}]},{"_type":"block","_key":"n45e1hyjd","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"3sjxzp1q5","text":"Drainage of clear fluid, pus, or a bad-smelling discharge"}]},{"_type":"block","_key":"004b679s0","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"mcdaehjes","text":"A feeling of fullness or blockage in the ear"}]},{"_type":"block","_key":"ur9nhv8pp","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"sdg97abp4","text":"Temporary hearing loss or muffled sound"}]},{"_type":"block","_key":"ben5lvcgg","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"05049y21e","text":"Increased discomfort when chewing or moving the jaw"}]},{"_type":"block","_key":"ce3e2fvk1","style":"normal","children":[{"_type":"span","_key":"pwdpx371r","text":"Swimmer’s ear pain often feels stronger than a middle ear infection. If symptoms last more than a day or two, it is important to seek care."}]},{"_type":"block","_key":"6d0thjceg","style":"h2","children":[{"_type":"span","_key":"v006r00rf","text":"What Causes Swimmer’s Ear?"}]},{"_type":"block","_key":"nqj3xdbm3","style":"normal","children":[{"_type":"span","_key":"zqwavrf0s","text":"Swimmer’s ear usually starts when moisture stays inside the ear canal. This breaks down the ear’s natural protection and allows bacteria or fungus to grow. Other causes include:"}]},{"_type":"block","_key":"0t5vyp0d3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"cpbe7jzfo","text":"Swimming in pools, lakes, or oceans"}]},{"_type":"block","_key":"22b53b0jj","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"or6n9dy70","text":"Bathing or showering without drying the ears well"}]},{"_type":"block","_key":"ffnyzpwqv","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"pubqfszq9","text":"Using cotton swabs or hairpins inside the ear"}]},{"_type":"block","_key":"prlxhy5hv","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"38r6xuo7d","text":"Scratching the ear canal"}]},{"_type":"block","_key":"4ficpjdo3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"l3mg5ra5j","text":"Wearing earbuds or hearing aids for long periods"}]},{"_type":"block","_key":"seit059qf","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"p2hz809jb","text":"Skin conditions like eczema or psoriasis"}]},{"_type":"block","_key":"enz7j7tmq","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"28ecgpvzd","text":"Too much or too little earwax"}]},{"_type":"block","_key":"sqsyhe93g","style":"normal","children":[{"_type":"span","_key":"jog1d3hlg","text":"Earwax normally helps protect the ear. Removing too much wax can leave the ear canal dry and open to infection."}]},{"_type":"block","_key":"30bi6penf","style":"h2","children":[{"_type":"span","_key":"36vq2fh9a","text":"Who Is Most at Risk for Swimmer’s Ear?"}]},{"_type":"block","_key":"c3l20dtmx","style":"normal","children":[{"_type":"span","_key":"xsxg0bx2f","text":"Anyone can get swimmer’s ear, but some people are more likely to develop it:"}]},{"_type":"block","_key":"kj0595m4y","style":"h3","children":[{"_type":"span","_key":"280v3tghi","text":"Frequent Swimmers"}]},{"_type":"block","_key":"bhzhufb3e","style":"normal","children":[{"_type":"span","_key":"b37dsgzj5","text":"People who swim often are exposed to water regularly. Pools, lakes, and oceans can all carry bacteria."}]},{"_type":"block","_key":"bj39xco50","style":"h3","children":[{"_type":"span","_key":"ltbs7ryr2","text":"Children and Teens"}]},{"_type":"block","_key":"eh5p7r4nu","style":"normal","children":[{"_type":"span","_key":"lsgn1r73d","text":"Kids and teens spend more time in pools during warm months and may not dry their ears well."}]},{"_type":"block","_key":"cx2gj1qpr","style":"h3","children":[{"_type":"span","_key":"502v3h6hb","text":"Hearing Aid and Earbud Users"}]},{"_type":"block","_key":"1ou2ngv0l","style":"normal","children":[{"_type":"span","_key":"0miqkrgs3","text":"Devices worn in the ear can trap moisture and cause irritation."}]},{"_type":"block","_key":"ynhj1sr2f","style":"h3","children":[{"_type":"span","_key":"70pad8y0m","text":"People in Humid Climates"}]},{"_type":"block","_key":"970ct65px","style":"normal","children":[{"_type":"span","_key":"1ad7blll9","text":"Living in a humid area like Lutz, FL increases the risk because moisture does not dry as easily."}]},{"_type":"block","_key":"nxvkzop61","style":"h3","children":[{"_type":"span","_key":"7knz5xqhw","text":"People Who Clean Ears Improperly"}]},{"_type":"block","_key":"7kn1vo7oe","style":"normal","children":[{"_type":"span","_key":"44eib1cge","text":"Using cotton swabs can scratch the ear canal and push wax deeper, leading to infection."}]},{"_type":"block","_key":"qiyhay5ax","style":"h2","children":[{"_type":"span","_key":"v7fnpmpbp","text":"How Swimmer’s Ear Is Diagnosed"}]},{"_type":"block","_key":"p3w7y03x1","style":"normal","children":[{"_type":"span","_key":"woppn2msq","text":"A hearing care professional or doctor can usually diagnose swimmer’s ear with a simple exam. They look inside the ear canal to check for redness, swelling, drainage, or blockage."}]},{"_type":"block","_key":"5v9jrgq5p","style":"normal","children":[{"_type":"span","_key":"43klkhmmm","text":"At JC Audiology, we carefully examine the ear to make sure the symptoms are caused by swimmer’s ear and not another condition like earwax buildup or a middle ear infection."}]},{"_type":"block","_key":"lpxs55yu6","style":"normal","children":[{"_type":"span","_key":"pmve4dl68","text":"Contact us today to schedule an appointment with an "},{"_type":"span","_key":"v0pjhwrx3","text":"audiologist in Lutz, FL","marks":["fuxodi1nw"]},{"_type":"span","_key":"s6bz1vbwc","text":"."}],"markDefs":[{"_type":"link","_key":"fuxodi1nw","href":"../index.html","blank":false}]},{"_type":"block","_key":"j53vvpi8a","style":"h2","children":[{"_type":"span","_key":"2w2egw33c","text":"How Swimmer’s Ear Is Treated"}]},{"_type":"block","_key":"e3x2rofwf","style":"normal","children":[{"_type":"span","_key":"ki1hzqpgc","text":"Swimmer’s ear should not be ignored. Without treatment, it can become more painful and harder to treat."}]},{"_type":"block","_key":"mxd6wiwdz","style":"h3","children":[{"_type":"span","_key":"quul14wr7","text":"Common Treatments Include:"}]},{"_type":"block","_key":"nqshk29w8","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"wkp8dg6wn","text":"Prescription ear drops with antibiotics or antifungal medicine"}]},{"_type":"block","_key":"wyrivgg7u","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"c4dwtml86","text":"Drops that reduce swelling and irritation"}]},{"_type":"block","_key":"j3n6xfa51","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"t1yiofdel","text":"Professional ear cleaning to remove blockage safely"}]},{"_type":"block","_key":"d3d1xulfe","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"6kqvrq6jz","text":"Pain relief when needed"}]},{"_type":"block","_key":"tg5ewbn1y","style":"normal","children":[{"_type":"span","_key":"et9lmxqq5","text":"Most people feel better within a few days of starting treatment. It is important to use all prescribed drops as directed, even if symptoms improve quickly."}]},{"_type":"block","_key":"998oku3lm","style":"h2","children":[{"_type":"span","_key":"td83gukzh","text":"What Not to Do if You Have Swimmer’s Ear"}]},{"_type":"block","_key":"fluat9k5l","style":"normal","children":[{"_type":"span","_key":"ge8t6hpwi","text":"Avoid these actions, as they can make the infection worse:"}]},{"_type":"block","_key":"yisnufn3u","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"jbbd2odnp","text":"Do not insert cotton swabs or tissues into the ear"}]},{"_type":"block","_key":"fmf9wus2w","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"dtokb0ibj","text":"Do not try to “dry out” the ear with sharp objects"}]},{"_type":"block","_key":"ngfhsh5iv","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"rqhts8ypt","text":"Avoid swimming until the infection is gone"}]},{"_type":"block","_key":"pdn88zfq0","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"46mrc4a4b","text":"Do not ignore worsening pain or drainage"}]},{"_type":"block","_key":"kl0qaxp15","style":"normal","children":[{"_type":"span","_key":"n9i17k85t","text":"If pain increases or spreads, see a doctor or audiology clinic right away."}]},{"_type":"block","_key":"jv9z1fble","style":"h2","children":[{"_type":"span","_key":"mc0faafyr","text":"Can Swimmer’s Ear Go Away on Its Own?"}]},{"_type":"block","_key":"z11nnjonq","style":"normal","children":[{"_type":"span","_key":"r92cprz1a","text":"Mild cases may improve, but most swimmer’s ear infections need treatment. Without care, the infection can spread deeper into the ear canal or become chronic."}]},{"_type":"block","_key":"ghn14zfez","style":"normal","children":[{"_type":"span","_key":"f7zockljd","text":"Seeing a hearing professional early helps shorten recovery time and reduce discomfort."}]},{"_type":"block","_key":"s7dr158ei","style":"h2","children":[{"_type":"span","_key":"oq4tsvf82","text":"How to Prevent Swimmer’s Ear"}]},{"_type":"block","_key":"6m6i20i7r","style":"normal","children":[{"_type":"span","_key":"gpo52z7ob","text":"Prevention is one of the best ways to avoid swimmer’s ear. Simple steps can protect your ears:"}]},{"_type":"block","_key":"pc4tv02x2","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"al18om47a","text":"Dry ears well after swimming or bathing"}]},{"_type":"block","_key":"0yekpuynl","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"tqoxq9h2p","text":"Tilt your head to let water drain out"}]},{"_type":"block","_key":"nsn4x7ltg","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"cd78xiqdi","text":"Use a towel to dry the outer ear"}]},{"_type":"block","_key":"jni5oixm6","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"p2pbkx9as","text":"Wear swim earplugs if you are prone to infections"}]},{"_type":"block","_key":"1gabsba3h","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"m4t5cyjnw","text":"Avoid cotton swabs inside the ear canal"}]},{"_type":"block","_key":"rn666ovvs","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"dxevq8wtu","text":"Use a hairdryer on the lowest setting, held several inches away"}]},{"_type":"block","_key":"vz45hvpxc","style":"normal","children":[{"_type":"span","_key":"96oexpqnf","text":"If you swim often, custom swim molds from an audiology clinic can help keep water out."}]},{"_type":"block","_key":"euyml2nm4","style":"h2","children":[{"_type":"span","_key":"ds7ckd67l","text":"Swimmer’s Ear and Hearing Loss"}]},{"_type":"block","_key":"0bogomy6k","style":"normal","children":[{"_type":"span","_key":"b28k7a34l","text":"Temporary hearing loss is common with swimmer’s ear due to swelling and fluid in the ear canal. Once the infection clears, hearing usually returns to normal."}]},{"_type":"block","_key":"azo75b3fm","style":"normal","children":[{"_type":"span","_key":"yirfqd8bg","text":"If hearing does not improve, a professional hearing evaluation may be needed to rule out other problems."}]},{"_type":"block","_key":"m8xdelbtb","style":"h2","children":[{"_type":"span","_key":"37nkgcq5q","text":"When to See a Doctor or Audiologist"}]},{"_type":"block","_key":"91jehtci8","style":"normal","children":[{"_type":"span","_key":"2vtm9smvh","text":"You should seek care if you notice:"}]},{"_type":"block","_key":"mbge4ep35","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"oci03sxw5","text":"Pain lasting more than 24–48 hours"}]},{"_type":"block","_key":"sjmfikhr4","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"hs1gwhmsa","text":"Increasing swelling or redness"}]},{"_type":"block","_key":"gc2ids5z9","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"bqmvrnt7u","text":"Drainage that looks yellow, green, or bloody"}]},{"_type":"block","_key":"uwcdg133l","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"t46u0alsk","text":"Fever or spreading pain"}]},{"_type":"block","_key":"rdvg7uhhl","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"fcrm2jizj","text":"Trouble hearing that does not improve"}]},{"_type":"block","_key":"oizfe8goj","style":"normal","children":[{"_type":"span","_key":"05rw08jlr","text":"Prompt care helps prevent complications and speeds healing."}]},{"_type":"block","_key":"7qfvgfa5i","style":"h2","children":[{"_type":"span","_key":"nh8v3oy0d","text":"Swimmer’s Ear in Adults vs. Children"}]},{"_type":"block","_key":"s8u1tdgvi","style":"normal","children":[{"_type":"span","_key":"ln6v6kige","text":"Both adults and children can get swimmer’s ear. Children may have a harder time explaining pain or itchiness, so parents should watch for ear pulling, crying, or drainage."}]},{"_type":"block","_key":"mcj3bcic8","style":"normal","children":[{"_type":"span","_key":"y4lxupcw4","text":"Adults may delay care, thinking symptoms will go away. Early treatment is always best."}]},{"_type":"block","_key":"e1k08xmbg","style":"h2","children":[{"_type":"span","_key":"lzvh2fbbv","text":"How JC Audiology Can Help"}]},{"_type":"block","_key":"f2mka7eb8","style":"normal","children":[{"_type":"span","_key":"4zzoyxxg2","text":"At JC Audiology in Lutz, FL, we provide caring, professional support for ear health concerns, including swimmer’s ear. Our services include:"}]},{"_type":"block","_key":"lh91x5na5","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"pi0xsde2s","text":"Ear examinations"}]},{"_type":"block","_key":"c3bsa0odn","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"paxfkgd1s","text":"Safe ear cleaning"}]},{"_type":"block","_key":"5lxpfvnvx","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"6jx65pwzs","text":"Guidance on treatment and prevention"}]},{"_type":"block","_key":"bmofl6vsz","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"il4ge5yt2","text":"Hearing evaluations if needed"}]},{"_type":"block","_key":"zdsrxfraf","style":"normal","children":[{"_type":"span","_key":"iut3dmxg6","text":"We do more than just provide "},{"_type":"span","_key":"kun0o5qpy","text":"hearing aids in Lutz, FL","marks":["fovm91yw6"]},{"_type":"span","_key":"nsykqw501","text":". We focus on patient comfort and clear answers, so you know exactly what is happening with your ears."}],"markDefs":[{"_type":"link","_key":"fovm91yw6","href":"../index.html","blank":false}]},{"_type":"block","_key":"5uvjkw676","style":"h2","children":[{"_type":"span","_key":"yd91qypqn","text":"Living Comfortably After Swimmer’s Ear"}]},{"_type":"block","_key":"orn5zzwwe","style":"normal","children":[{"_type":"span","_key":"veyf8ih9x","text":"Once swimmer’s ear clears, taking preventive steps helps reduce future infections. Keeping ears dry and avoiding irritation goes a long way toward healthy ears."}]},{"_type":"block","_key":"r27vg3gup","style":"normal","children":[{"_type":"span","_key":"exrpyc46x","text":"If swimmer’s ear happens often, a hearing care provider can help identify triggers and recommend long-term solutions."}]},{"_type":"block","_key":"iyj88ocqw","style":"h2","children":[{"_type":"span","_key":"z5quqxbld","text":"Schedule An Appointment With An Audiologist in Lutz, FL"}]},{"_type":"block","_key":"fkqsa1p73","style":"normal","children":[{"_type":"span","_key":"tpjh4gww3","text":"Swimmer’s ear is a common but painful condition that should be taken seriously. It can affect swimmers and non-swimmers alike, especially in warm, humid environments. "}]},{"_type":"block","_key":"lvqkspaqm","style":"normal","children":[{"_type":"span","_key":"84vq6ppxj","text":"Recognizing symptoms early and getting the right care helps relieve pain, protect hearing, and prevent repeat infections."}]},{"_type":"block","_key":"f9nunhutk","style":"normal","children":[{"_type":"span","_key":"33opbj7dt","text":"If you are experiencing ear pain, itchiness, drainage, or discomfort, do not wait. "}]},{"_type":"block","_key":"8n8xbdqmj","style":"normal","children":[{"_type":"span","_key":"ds84wv2wb","text":"Swimmer’s ear is easier to treat when caught early, and professional care makes a big difference."}]},{"_type":"block","_key":"b76yjit79","style":"normal","children":[{"_type":"span","_key":"k330mzq46","text":"Contact us ","marks":["a9ucq25hu"]},{"_type":"span","_key":"q0u7al949","text":"today to schedule an appointment!"}],"markDefs":[{"_type":"link","_key":"a9ucq25hu","href":"../schedule-appointment/index.html","blank":false}]}]}',NULL,'2026-05-21 05:40:33');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS4JG7CF1JHCX4MT0HFRKR3S','blog_posts','swimmers-ear-causes-symptoms-treatment-prevention','{"title":"Swimmer’s Ear Explained test","route":"/swimmers-ear-causes-symptoms-treatment-prevention/","meta_title":"Swimmer’s Ear Explained","meta_description":"Swimmer’s ear causes pain, itching, and swelling. Learn symptoms, treatment, and prevention. Schedule with JC Audiology in Lutz, FL today. test","category":"Hearing Health, Hearing Problems","featured_image":{"id":"media-blog-aae515ca-featured-featured","provider":"local","width":800,"height":532,"alt":"","meta":{"storageKey":"blog/aae515ca-featured_featured.jpg","caption":null,"blurhash":null,"dominantColor":null},"filename":"aae515ca-featured_featured.jpg","mimeType":"image/jpeg"},"body_content":[{"_type":"block","_key":"r0xmjawp8","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"u50buu2zk","text":"Swimmer’s ear is a common outer ear infection caused by trapped moisture, especially after swimming or bathing."}]},{"_type":"block","_key":"v76zqe79i","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"q6c2djc8q","text":"Early treatment helps relieve pain, itching, and swelling and prevents the infection from getting worse."}]},{"_type":"block","_key":"v9juczpvy","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"6gl3kea6o","text":"Simple prevention steps and professional care from an audiology clinic can keep your ears healthy and comfortable."}]},{"_type":"block","_key":"5m6awu7vh","style":"normal","children":[{"_type":"span","_key":"m1aj56rv0","text":"Swimmer’s ear is a painful and irritating ear condition that affects people of all ages. If you live in a warm, humid area like Florida or spend time around pools, lakes, or the beach, swimmer’s ear is something you should understand. In this guide, we explain what swimmer’s ear is, why it happens, how to treat it, and how to prevent it. Knowing the signs early can help you avoid discomfort and protect your hearing. test"}]},{"_type":"block","_key":"b79ull4ba","style":"normal","children":[{"_type":"span","_key":"c3esi9zw4","text":"At JC Audiology in Lutz, FL, we help patients recognize swimmer’s ear symptoms and provide safe, "},{"_type":"span","_key":"wjcuyw34m","text":"professional audiology care","marks":["gvbwkv4s4"]},{"_type":"span","_key":"bxkma9sws","text":" to restore ear health."}],"markDefs":[{"_type":"link","_key":"gvbwkv4s4","href":"../audiology-services/hearing-tests/index.html","blank":false}]},{"_type":"block","_key":"fcr9db19e","style":"h2","children":[{"_type":"span","_key":"p1s7n82me","text":"What Is Swimmer’s Ear?"}]},{"_type":"block","_key":"sqh0fchwq","style":"normal","children":[{"_type":"span","_key":"8tso7l4jf","text":"Swimmer’s ear, also called otitis externa, is an infection of the outer ear canal. This is the part of the ear that runs from the outside opening down to the eardrum. The infection usually starts when water gets trapped in the ear canal, creating a moist space where bacteria or fungus can grow."}]},{"_type":"block","_key":"34ukz6kfw","style":"normal","children":[{"_type":"span","_key":"0xdc9bxql","text":"Although the name suggests it only affects swimmers, swimmer’s ear can happen to anyone. Bathing, showering, sweating, or living in a humid climate can all increase the risk. Even people who have not been near a pool can develop swimmer’s ear."}]},{"_type":"block","_key":"72ynancta","style":"h2","children":[{"_type":"span","_key":"g07aj0mkg","text":"Why Swimmer’s Ear Is Common in Florida"}]},{"_type":"block","_key":"8t4d89wns","style":"normal","children":[{"_type":"span","_key":"5bclf9zw5","text":"Florida’s warm weather and high humidity make swimmer’s ear more common. Moisture stays in the ear longer, especially after swimming in a pool, lake, or ocean. The skin inside the ear canal becomes soft and more likely to get irritated or infected."}]},{"_type":"block","_key":"k617182si","style":"normal","children":[{"_type":"span","_key":"uaz6nycx2","text":"People who swim often, wear earbuds, or use hearing aids may also trap moisture in the ear. This increases the risk of irritation and infection over time."}]},{"_type":"block","_key":"ucqv2r4xc","style":"h2","children":[{"_type":"span","_key":"ar7go51h1","text":"Common Symptoms of Swimmer’s Ear"}]},{"_type":"block","_key":"u1ykggjj9","style":"normal","children":[{"_type":"span","_key":"20c418cpa","text":"Swimmer’s ear symptoms can start mild and get worse quickly if not treated. Common signs include:"}]},{"_type":"block","_key":"gt77635u3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ygg8neuoc","text":"Itchiness inside the ear canal"}]},{"_type":"block","_key":"03urmpz6o","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"jp05z7kat","text":"Redness or swelling around the ear opening"}]},{"_type":"block","_key":"a1qlk3itl","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"9281hn31c","text":"Ear pain that gets worse when touching or pulling the ear"}]},{"_type":"block","_key":"n45e1hyjd","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"3sjxzp1q5","text":"Drainage of clear fluid, pus, or a bad-smelling discharge"}]},{"_type":"block","_key":"004b679s0","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"mcdaehjes","text":"A feeling of fullness or blockage in the ear"}]},{"_type":"block","_key":"ur9nhv8pp","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"sdg97abp4","text":"Temporary hearing loss or muffled sound"}]},{"_type":"block","_key":"ben5lvcgg","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"05049y21e","text":"Increased discomfort when chewing or moving the jaw"}]},{"_type":"block","_key":"ce3e2fvk1","style":"normal","children":[{"_type":"span","_key":"pwdpx371r","text":"Swimmer’s ear pain often feels stronger than a middle ear infection. If symptoms last more than a day or two, it is important to seek care."}]},{"_type":"block","_key":"6d0thjceg","style":"h2","children":[{"_type":"span","_key":"v006r00rf","text":"What Causes Swimmer’s Ear?"}]},{"_type":"block","_key":"nqj3xdbm3","style":"normal","children":[{"_type":"span","_key":"zqwavrf0s","text":"Swimmer’s ear usually starts when moisture stays inside the ear canal. This breaks down the ear’s natural protection and allows bacteria or fungus to grow. Other causes include:"}]},{"_type":"block","_key":"0t5vyp0d3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"cpbe7jzfo","text":"Swimming in pools, lakes, or oceans"}]},{"_type":"block","_key":"22b53b0jj","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"or6n9dy70","text":"Bathing or showering without drying the ears well"}]},{"_type":"block","_key":"ffnyzpwqv","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"pubqfszq9","text":"Using cotton swabs or hairpins inside the ear"}]},{"_type":"block","_key":"prlxhy5hv","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"38r6xuo7d","text":"Scratching the ear canal"}]},{"_type":"block","_key":"4ficpjdo3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"l3mg5ra5j","text":"Wearing earbuds or hearing aids for long periods"}]},{"_type":"block","_key":"seit059qf","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"p2hz809jb","text":"Skin conditions like eczema or psoriasis"}]},{"_type":"block","_key":"enz7j7tmq","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"28ecgpvzd","text":"Too much or too little earwax"}]},{"_type":"block","_key":"sqsyhe93g","style":"normal","children":[{"_type":"span","_key":"jog1d3hlg","text":"Earwax normally helps protect the ear. Removing too much wax can leave the ear canal dry and open to infection."}]},{"_type":"block","_key":"30bi6penf","style":"h2","children":[{"_type":"span","_key":"36vq2fh9a","text":"Who Is Most at Risk for Swimmer’s Ear?"}]},{"_type":"block","_key":"c3l20dtmx","style":"normal","children":[{"_type":"span","_key":"xsxg0bx2f","text":"Anyone can get swimmer’s ear, but some people are more likely to develop it:"}]},{"_type":"block","_key":"kj0595m4y","style":"h3","children":[{"_type":"span","_key":"280v3tghi","text":"Frequent Swimmers"}]},{"_type":"block","_key":"bhzhufb3e","style":"normal","children":[{"_type":"span","_key":"b37dsgzj5","text":"People who swim often are exposed to water regularly. Pools, lakes, and oceans can all carry bacteria."}]},{"_type":"block","_key":"bj39xco50","style":"h3","children":[{"_type":"span","_key":"ltbs7ryr2","text":"Children and Teens"}]},{"_type":"block","_key":"eh5p7r4nu","style":"normal","children":[{"_type":"span","_key":"lsgn1r73d","text":"Kids and teens spend more time in pools during warm months and may not dry their ears well."}]},{"_type":"block","_key":"cx2gj1qpr","style":"h3","children":[{"_type":"span","_key":"502v3h6hb","text":"Hearing Aid and Earbud Users"}]},{"_type":"block","_key":"1ou2ngv0l","style":"normal","children":[{"_type":"span","_key":"0miqkrgs3","text":"Devices worn in the ear can trap moisture and cause irritation."}]},{"_type":"block","_key":"ynhj1sr2f","style":"h3","children":[{"_type":"span","_key":"70pad8y0m","text":"People in Humid Climates"}]},{"_type":"block","_key":"970ct65px","style":"normal","children":[{"_type":"span","_key":"1ad7blll9","text":"Living in a humid area like Lutz, FL increases the risk because moisture does not dry as easily."}]},{"_type":"block","_key":"nxvkzop61","style":"h3","children":[{"_type":"span","_key":"7knz5xqhw","text":"People Who Clean Ears Improperly"}]},{"_type":"block","_key":"7kn1vo7oe","style":"normal","children":[{"_type":"span","_key":"44eib1cge","text":"Using cotton swabs can scratch the ear canal and push wax deeper, leading to infection."}]},{"_type":"block","_key":"qiyhay5ax","style":"h2","children":[{"_type":"span","_key":"v7fnpmpbp","text":"How Swimmer’s Ear Is Diagnosed"}]},{"_type":"block","_key":"p3w7y03x1","style":"normal","children":[{"_type":"span","_key":"woppn2msq","text":"A hearing care professional or doctor can usually diagnose swimmer’s ear with a simple exam. They look inside the ear canal to check for redness, swelling, drainage, or blockage."}]},{"_type":"block","_key":"5v9jrgq5p","style":"normal","children":[{"_type":"span","_key":"43klkhmmm","text":"At JC Audiology, we carefully examine the ear to make sure the symptoms are caused by swimmer’s ear and not another condition like earwax buildup or a middle ear infection."}]},{"_type":"block","_key":"lpxs55yu6","style":"normal","children":[{"_type":"span","_key":"pmve4dl68","text":"Contact us today to schedule an appointment with an "},{"_type":"span","_key":"v0pjhwrx3","text":"audiologist in Lutz, FL","marks":["fuxodi1nw"]},{"_type":"span","_key":"s6bz1vbwc","text":"."}],"markDefs":[{"_type":"link","_key":"fuxodi1nw","href":"../index.html","blank":false}]},{"_type":"block","_key":"j53vvpi8a","style":"h2","children":[{"_type":"span","_key":"2w2egw33c","text":"How Swimmer’s Ear Is Treated"}]},{"_type":"block","_key":"e3x2rofwf","style":"normal","children":[{"_type":"span","_key":"ki1hzqpgc","text":"Swimmer’s ear should not be ignored. Without treatment, it can become more painful and harder to treat."}]},{"_type":"block","_key":"mxd6wiwdz","style":"h3","children":[{"_type":"span","_key":"quul14wr7","text":"Common Treatments Include:"}]},{"_type":"block","_key":"nqshk29w8","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"wkp8dg6wn","text":"Prescription ear drops with antibiotics or antifungal medicine"}]},{"_type":"block","_key":"wyrivgg7u","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"c4dwtml86","text":"Drops that reduce swelling and irritation"}]},{"_type":"block","_key":"j3n6xfa51","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"t1yiofdel","text":"Professional ear cleaning to remove blockage safely"}]},{"_type":"block","_key":"d3d1xulfe","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"6kqvrq6jz","text":"Pain relief when needed"}]},{"_type":"block","_key":"tg5ewbn1y","style":"normal","children":[{"_type":"span","_key":"et9lmxqq5","text":"Most people feel better within a few days of starting treatment. It is important to use all prescribed drops as directed, even if symptoms improve quickly."}]},{"_type":"block","_key":"998oku3lm","style":"h2","children":[{"_type":"span","_key":"td83gukzh","text":"What Not to Do if You Have Swimmer’s Ear"}]},{"_type":"block","_key":"fluat9k5l","style":"normal","children":[{"_type":"span","_key":"ge8t6hpwi","text":"Avoid these actions, as they can make the infection worse:"}]},{"_type":"block","_key":"yisnufn3u","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"jbbd2odnp","text":"Do not insert cotton swabs or tissues into the ear"}]},{"_type":"block","_key":"fmf9wus2w","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"dtokb0ibj","text":"Do not try to “dry out” the ear with sharp objects"}]},{"_type":"block","_key":"ngfhsh5iv","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"rqhts8ypt","text":"Avoid swimming until the infection is gone"}]},{"_type":"block","_key":"pdn88zfq0","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"46mrc4a4b","text":"Do not ignore worsening pain or drainage"}]},{"_type":"block","_key":"kl0qaxp15","style":"normal","children":[{"_type":"span","_key":"n9i17k85t","text":"If pain increases or spreads, see a doctor or audiology clinic right away."}]},{"_type":"block","_key":"jv9z1fble","style":"h2","children":[{"_type":"span","_key":"mc0faafyr","text":"Can Swimmer’s Ear Go Away on Its Own?"}]},{"_type":"block","_key":"z11nnjonq","style":"normal","children":[{"_type":"span","_key":"r92cprz1a","text":"Mild cases may improve, but most swimmer’s ear infections need treatment. Without care, the infection can spread deeper into the ear canal or become chronic."}]},{"_type":"block","_key":"ghn14zfez","style":"normal","children":[{"_type":"span","_key":"f7zockljd","text":"Seeing a hearing professional early helps shorten recovery time and reduce discomfort."}]},{"_type":"block","_key":"s7dr158ei","style":"h2","children":[{"_type":"span","_key":"oq4tsvf82","text":"How to Prevent Swimmer’s Ear"}]},{"_type":"block","_key":"6m6i20i7r","style":"normal","children":[{"_type":"span","_key":"gpo52z7ob","text":"Prevention is one of the best ways to avoid swimmer’s ear. Simple steps can protect your ears:"}]},{"_type":"block","_key":"pc4tv02x2","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"al18om47a","text":"Dry ears well after swimming or bathing"}]},{"_type":"block","_key":"0yekpuynl","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"tqoxq9h2p","text":"Tilt your head to let water drain out"}]},{"_type":"block","_key":"nsn4x7ltg","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"cd78xiqdi","text":"Use a towel to dry the outer ear"}]},{"_type":"block","_key":"jni5oixm6","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"p2pbkx9as","text":"Wear swim earplugs if you are prone to infections"}]},{"_type":"block","_key":"1gabsba3h","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"m4t5cyjnw","text":"Avoid cotton swabs inside the ear canal"}]},{"_type":"block","_key":"rn666ovvs","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"dxevq8wtu","text":"Use a hairdryer on the lowest setting, held several inches away"}]},{"_type":"block","_key":"vz45hvpxc","style":"normal","children":[{"_type":"span","_key":"96oexpqnf","text":"If you swim often, custom swim molds from an audiology clinic can help keep water out."}]},{"_type":"block","_key":"euyml2nm4","style":"h2","children":[{"_type":"span","_key":"ds7ckd67l","text":"Swimmer’s Ear and Hearing Loss"}]},{"_type":"block","_key":"0bogomy6k","style":"normal","children":[{"_type":"span","_key":"b28k7a34l","text":"Temporary hearing loss is common with swimmer’s ear due to swelling and fluid in the ear canal. Once the infection clears, hearing usually returns to normal."}]},{"_type":"block","_key":"azo75b3fm","style":"normal","children":[{"_type":"span","_key":"yirfqd8bg","text":"If hearing does not improve, a professional hearing evaluation may be needed to rule out other problems."}]},{"_type":"block","_key":"m8xdelbtb","style":"h2","children":[{"_type":"span","_key":"37nkgcq5q","text":"When to See a Doctor or Audiologist"}]},{"_type":"block","_key":"91jehtci8","style":"normal","children":[{"_type":"span","_key":"2vtm9smvh","text":"You should seek care if you notice:"}]},{"_type":"block","_key":"mbge4ep35","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"oci03sxw5","text":"Pain lasting more than 24–48 hours"}]},{"_type":"block","_key":"sjmfikhr4","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"hs1gwhmsa","text":"Increasing swelling or redness"}]},{"_type":"block","_key":"gc2ids5z9","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"bqmvrnt7u","text":"Drainage that looks yellow, green, or bloody"}]},{"_type":"block","_key":"uwcdg133l","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"t46u0alsk","text":"Fever or spreading pain"}]},{"_type":"block","_key":"rdvg7uhhl","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"fcrm2jizj","text":"Trouble hearing that does not improve"}]},{"_type":"block","_key":"oizfe8goj","style":"normal","children":[{"_type":"span","_key":"05rw08jlr","text":"Prompt care helps prevent complications and speeds healing."}]},{"_type":"block","_key":"7qfvgfa5i","style":"h2","children":[{"_type":"span","_key":"nh8v3oy0d","text":"Swimmer’s Ear in Adults vs. Children"}]},{"_type":"block","_key":"s8u1tdgvi","style":"normal","children":[{"_type":"span","_key":"ln6v6kige","text":"Both adults and children can get swimmer’s ear. Children may have a harder time explaining pain or itchiness, so parents should watch for ear pulling, crying, or drainage."}]},{"_type":"block","_key":"mcj3bcic8","style":"normal","children":[{"_type":"span","_key":"y4lxupcw4","text":"Adults may delay care, thinking symptoms will go away. Early treatment is always best."}]},{"_type":"block","_key":"e1k08xmbg","style":"h2","children":[{"_type":"span","_key":"lzvh2fbbv","text":"How JC Audiology Can Help"}]},{"_type":"block","_key":"f2mka7eb8","style":"normal","children":[{"_type":"span","_key":"4zzoyxxg2","text":"At JC Audiology in Lutz, FL, we provide caring, professional support for ear health concerns, including swimmer’s ear. Our services include:"}]},{"_type":"block","_key":"lh91x5na5","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"pi0xsde2s","text":"Ear examinations"}]},{"_type":"block","_key":"c3bsa0odn","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"paxfkgd1s","text":"Safe ear cleaning"}]},{"_type":"block","_key":"5lxpfvnvx","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"6jx65pwzs","text":"Guidance on treatment and prevention"}]},{"_type":"block","_key":"bmofl6vsz","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"il4ge5yt2","text":"Hearing evaluations if needed"}]},{"_type":"block","_key":"zdsrxfraf","style":"normal","children":[{"_type":"span","_key":"iut3dmxg6","text":"We do more than just provide "},{"_type":"span","_key":"kun0o5qpy","text":"hearing aids in Lutz, FL","marks":["fovm91yw6"]},{"_type":"span","_key":"nsykqw501","text":". We focus on patient comfort and clear answers, so you know exactly what is happening with your ears."}],"markDefs":[{"_type":"link","_key":"fovm91yw6","href":"../index.html","blank":false}]},{"_type":"block","_key":"5uvjkw676","style":"h2","children":[{"_type":"span","_key":"yd91qypqn","text":"Living Comfortably After Swimmer’s Ear"}]},{"_type":"block","_key":"orn5zzwwe","style":"normal","children":[{"_type":"span","_key":"veyf8ih9x","text":"Once swimmer’s ear clears, taking preventive steps helps reduce future infections. Keeping ears dry and avoiding irritation goes a long way toward healthy ears."}]},{"_type":"block","_key":"r27vg3gup","style":"normal","children":[{"_type":"span","_key":"exrpyc46x","text":"If swimmer’s ear happens often, a hearing care provider can help identify triggers and recommend long-term solutions."}]},{"_type":"block","_key":"iyj88ocqw","style":"h2","children":[{"_type":"span","_key":"z5quqxbld","text":"Schedule An Appointment With An Audiologist in Lutz, FL"}]},{"_type":"block","_key":"fkqsa1p73","style":"normal","children":[{"_type":"span","_key":"tpjh4gww3","text":"Swimmer’s ear is a common but painful condition that should be taken seriously. It can affect swimmers and non-swimmers alike, especially in warm, humid environments. "}]},{"_type":"block","_key":"lvqkspaqm","style":"normal","children":[{"_type":"span","_key":"84vq6ppxj","text":"Recognizing symptoms early and getting the right care helps relieve pain, protect hearing, and prevent repeat infections."}]},{"_type":"block","_key":"f9nunhutk","style":"normal","children":[{"_type":"span","_key":"33opbj7dt","text":"If you are experiencing ear pain, itchiness, drainage, or discomfort, do not wait. "}]},{"_type":"block","_key":"8n8xbdqmj","style":"normal","children":[{"_type":"span","_key":"ds84wv2wb","text":"Swimmer’s ear is easier to treat when caught early, and professional care makes a big difference."}]},{"_type":"block","_key":"b76yjit79","style":"normal","children":[{"_type":"span","_key":"k330mzq46","text":"Contact us ","marks":["a9ucq25hu"]},{"_type":"span","_key":"q0u7al949","text":"today to schedule an appointment!"}],"markDefs":[{"_type":"link","_key":"a9ucq25hu","href":"../schedule-appointment/index.html","blank":false}]}]}',NULL,'2026-05-21 06:10:26');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS4JQK3W8ES9V337836JGPP6','hearing_aid_brands','hearing-aids__oticon','{"brand_name":"Oticon Hearing Aidstes","route":"/hearing-aids/oticon/","meta_title":"Oticon Hearing Aids test","meta_description":"JC Audiology is an authorized provider of Oticon hearing aids in Lutz, FL. test","body_content":[{"_type":"block","_key":"7y3v9c94n","style":"normal","children":[{"_type":"span","_key":"lyk4sen7z","text":"JC Audiology is an authorized provider of Oticon hearing aids in Lutz, FL.","marks":["strong","em"]}]},{"_type":"block","_key":"44xhxp8kd","style":"normal","children":[{"_type":"span","_key":"uul6ins6i","text":"Oticon is a world leader in hearing aid technology, helping people stay engaged, confident, and connected in every part of life. Through decades of innovation and research, they’ve developed advanced hearing solutions that deliver clear, natural sound in a variety of listening environments."}]},{"_type":"block","_key":"pc4xg28dq","style":"normal","children":[{"_type":"span","_key":"zg1vc0bc9","text":"At JC Audiology, we want you to "},{"_type":"span","_key":"cg6tmgcjm","text":"hear for life","marks":["strong","em"]},{"_type":"span","_key":"awxi3ehl4","text":". Our Lutz, FL audiologist and hearing aid specialist will work closely with you to match the right Oticon device to your needs, preferences, and hearing goals."}]},{"_type":"block","_key":"wpyh8smgs","style":"normal","children":[{"_type":"span","_key":"lgqoekg8f","text":"With our years of expertise and Oticon’s state-of-the-art technology, you can enjoy a hearing experience designed for comfort, clarity, and confidence every day."}]},{"_type":"block","_key":"nd0xe5l1p","style":"h2","children":[{"_type":"span","_key":"ac3m3qlwq","text":"Oticon Hearing Aids in Lutz, FL"}]},{"_type":"block","_key":"dtu46tp3w","style":"h3","children":[{"_type":"span","_key":"3epwmw98f","text":"Oticon Zeal"}]},{"_type":"block","_key":"bk1mx26yn","style":"normal","children":[{"_type":"span","_key":"tt1lseoy9","text":"Oticon Zeal is the first hearing aid designed to "},{"_type":"span","_key":"la9unc2gh","text":"do it all","marks":["em"]},{"_type":"span","_key":"8syyma48d","text":" while staying completely unseen. Built for people who want powerful technology in an ultra-discreet design, Zeal delivers exceptional sound clarity, all-day comfort, and seamless connectivity in one tiny device no one will notice."}]},{"_type":"block","_key":"c5eiordmz","style":"normal","children":[{"_type":"span","_key":"28iq4pw5p","text":"Zeal transforms the idea of what a hearing aid should be. Its small, nearly invisible design sits comfortably in your ear, giving you the confidence to live fully without drawing attention to your device. Powered by Oticon’s advanced BrainHearing™ technology, Zeal supports the brain’s natural way of processing sound. Enjoy clear, balanced, and comfortable hearing, even in noisy places."}]},{"_type":"block","_key":"t3jc0u88z","style":"normal","children":[{"_type":"span","_key":"2a5l1ol0o","text":"Unique Features:","marks":["strong"]}]},{"_type":"block","_key":"5kwyw2moh","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"nycrpyj7s","text":"Made to Connect","marks":["strong"]},{"_type":"span","_key":"scckgzhcw","text":": Stream calls, meetings, music, and more directly from your phone, Apple Watch, TV, computer, or tablet. Zeal brings your digital world to life with smooth, high-quality wireless audio."}]},{"_type":"block","_key":"f85svwjqr","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"u579dk1gh","text":"Reliable Rechargeability:","marks":["strong"]},{"_type":"span","_key":"bwtasewu3","text":" No disposable batteries. With fast, dependable charging, you get all-day power that keeps up with your lifestyle."}]},{"_type":"block","_key":"htiklzvf6","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"lpwxndm1a","text":"wSame-Day Fitting:","marks":["strong"]},{"_type":"span","_key":"iggj4e589","text":" Zeal is designed for convenience, offering the option for same-day fitting so you can begin hearing better right away."}]},{"_type":"block","_key":"cq8zeyk2v","style":"h3","children":[{"_type":"span","_key":"o407unoqy","text":"Oticon Jet PX"}]},{"_type":"block","_key":"n8qg5nriv","style":"normal","children":[{"_type":"span","_key":"hf5aando3","text":"Oticon Jet PX uses advanced technology called Deep Neural Network or DNN to help you hear clearly. It comes with Wind Noise Management and Speech Guard, helping block out sounds that get in the way of talking to and listening to others."}]},{"_type":"block","_key":"bf3m6bnw8","style":"normal","children":[{"_type":"span","_key":"q4qymrimq","text":"If you have ringing in your ears (tinnitus), Oticon Jet PX has built-in sounds to help you feel and hear better. You can also connect it to your phone to listen to music, take calls, or change settings using the Oticon app."}]},{"_type":"block","_key":"e45n2nl65","style":"normal","children":[{"_type":"span","_key":"55dm1aheg","text":"Unique Features:","marks":["strong"]}]},{"_type":"block","_key":"roojtgsy1","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"0dabrotdp","text":"AI-powered OpenSound Navigator with DNN","marks":["strong"]},{"_type":"span","_key":"j9s3j6mav","text":": Improves hearing with clear, natural sound."}]},{"_type":"block","_key":"dde5xra7o","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"zt3f985ic","text":"Tinnitus SoundSupport:","marks":["strong"]},{"_type":"span","_key":"83rvallfp","text":" Ideal for users with tinnitus as it gives access to customizable relief sounds."}]},{"_type":"block","_key":"ic1e2cuvb","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"30mguai5l","text":"SuperShield","marks":["strong"]},{"_type":"span","_key":"4lmsegg3k","text":": Quickly adapts and prevents feedback before it occurs."}]},{"_type":"block","_key":"hs7vmpsxd","style":"h3","children":[{"_type":"span","_key":"0ygp246n6","text":"test"}]},{"_type":"block","_key":"3owodie4n","style":"h3","children":[{"_type":"span","_key":"3hemsbiws","text":"Oticon Own SI"}]},{"_type":"block","_key":"0fhl5slrn","style":"normal","children":[{"_type":"span","_key":"pvu7u7bs1","text":"Oticon Own SI hearing aids are fit snugly inside your ears with IIC (Invisible-in-Canal) and CIC (Completely-in-Canal) styles."}]},{"_type":"block","_key":"nx0olsxsq","style":"normal","children":[{"_type":"span","_key":"al6bkr7ps","text":"These are custom-made hearing aids so you can wear them confidently all day without worrying about their fit. Oticon Own SI is built with special BrainHearing technology to support how your brain naturally understands sound."}]},{"_type":"block","_key":"s5fu7e3st","style":"normal","children":[{"_type":"span","_key":"jf6s5nwc0","text":"Unique Features:","marks":["strong"]}]},{"_type":"block","_key":"8qrsmplgu","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"6zgyahh8h","text":"Discreet and sophisticated:","marks":["strong"]},{"_type":"span","_key":"yps3g88tu","text":" Super small styles (IIC and CIC) that fit fully in your ear"}]},{"_type":"block","_key":"xuxjj1hla","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"3o81lyapu","text":"BrainHearing™ technology","marks":["strong"]},{"_type":"span","_key":"truocmdp4","text":": Helps your brain make sense of sound."}]},{"_type":"block","_key":"mr8ctdi61","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ffw9mnome","text":"Custom-fit:","marks":["strong"]},{"_type":"span","_key":"f9kvbo3s7","text":" Built for all-day comfort, even with glasses or masks."}]},{"_type":"block","_key":"ea84cxb9d","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"7hyaeabbo","text":"Strong and durabl","marks":["strong"]},{"_type":"span","_key":"3xtqmcu2m","text":"e: Water- and dust-resistant to last through busy days."}]},{"_type":"block","_key":"zwtp7k8zf","style":"h3","children":[{"_type":"span","_key":"5ixa5ivqz","text":"Oticon Intent"}]},{"_type":"block","_key":"vyny3wvas","style":"normal","children":[{"_type":"span","_key":"mn1f0bo2i","text":"Oticon Intent uses 4D Sensor Technology to adapt to your surroundings, speech patterns, and head movements – all in real-time!"}]},{"_type":"block","_key":"28tpa1me6","style":"normal","children":[{"_type":"span","_key":"ng1e10j80","text":"It delivers an amazing sound experience thanks to the built-in Deep Neural Network (DNN). Enjoy a smart hearing aid that processes sound the way your brain naturally would. Communicate easier and break free from listening fatigue with the Oticon Intent."}]},{"_type":"block","_key":"5wmgupsqz","style":"normal","children":[{"_type":"span","_key":"i0v4mctsa","text":"Key Features:","marks":["strong"]}]},{"_type":"block","_key":"26k7xldlv","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"syfa0x9a2","text":"Bluetooth® LE Audio for seamless, low-energy streaming"}]},{"_type":"block","_key":"q2mgqp5rg","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"fbjwv26kt","text":"Self-Calibrating Speaker for optimized sound clarity"}]},{"_type":"block","_key":"fgvny1dqe","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"xj9dfhnb6","text":"Fast Charging: 33% quicker recharge for all-day use"}]},{"_type":"block","_key":"dvu13g85m","style":"h3","children":[{"_type":"span","_key":"otc45l930","text":"Oticon Real"}]},{"_type":"block","_key":"xuk6hz3tk","style":"normal","children":[{"_type":"span","_key":"t2e45v71p","text":"Get in touch with the real world and make meaningful connections with Oticon Real. This intelligent hearing aid helps you focus on speech by reducing disruptive sounds like sudden noise or wind."}]},{"_type":"block","_key":"948dat6ca","style":"normal","children":[{"_type":"span","_key":"8du184wzn","text":"It is available in miniRITE and miniBTE styles, with rechargeable or traditional battery options."}]},{"_type":"block","_key":"9bl9xeia7","style":"normal","children":[{"_type":"span","_key":"lajykw98p","text":"Key Features:","marks":["strong"]}]},{"_type":"block","_key":"s1mo0uhoh","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"v8k05pem8","text":"Bluetooth® streaming for iPhone® and Android™"}]},{"_type":"block","_key":"j9d39pffx","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"1kdcdi3k9","text":"App control via Oticon Companion or ON app"}]},{"_type":"block","_key":"lod3kz3hz","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"m0lycvuou","text":"Tinnitus SoundSupport™ for calming tinnitus relief"}]},{"_type":"block","_key":"0f7sg7ce4","style":"h3","children":[{"_type":"span","_key":"l8snum7f7","text":"Oticon Own"}]},{"_type":"block","_key":"e5krmnyj9","style":"normal","children":[{"_type":"span","_key":"qx33vr5ex","text":"Hearing loss is personal. Experience custom-fit hearing solutions with Oticon Own!"}]},{"_type":"block","_key":"bmsi72u6k","style":"normal","children":[{"_type":"span","_key":"11syziorf","text":"This custom-molded, in-the-ear solution is designed to provide clear sound and effective listening even in noisy environments. It smartly distinguishes speech from background noise while staying virtually invisible."}]},{"_type":"block","_key":"erxrdinbl","style":"normal","children":[{"_type":"span","_key":"lpami3raf","text":"Key Features:","marks":["strong"]}]},{"_type":"block","_key":"gvj8wcfqc","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"0u0vd0i2j","text":"Bluetooth® compatibility with iPhone® and Android™"}]},{"_type":"block","_key":"185wfmcbv","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"56o8yp7ff","text":"Remote adjustments via Oticon apps"}]},{"_type":"block","_key":"r16luhf69","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"44zib6vtz","text":"Built-in tinnitus relief with SoundSupport™"}]},{"_type":"block","_key":"ot4mloo0w","style":"h3","children":[{"_type":"span","_key":"43iapyj73","text":"Oticon Zircon"}]},{"_type":"block","_key":"7som2a2ky","style":"normal","children":[{"_type":"span","_key":"xn8pqgmdp","text":"Fully experience the world around you with Oticon Zircon. Offering 360° sound awareness, Zircon helps you engage in conversations by adjusting and detecting sounds coming from all sides."}]},{"_type":"block","_key":"sxjr33nws","style":"normal","children":[{"_type":"span","_key":"x1j2qqcay","text":"Powered by Oticon’s advanced BrainHearing™ technology, Zircon helps your brain process sound more naturally. Less stress on listening, more time to build connections and be present in each conversation."}]},{"_type":"block","_key":"ygq4vxnbf","style":"normal","children":[{"_type":"span","_key":"1ta7aoou3","text":"Key Features:","marks":["strong"]}]},{"_type":"block","_key":"lk2bluwm1","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"iyyv8ppwr","text":"Direct Bluetooth® streaming"}]},{"_type":"block","_key":"jqusajiax","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"5ve3eyfjw","text":"Control through Oticon Companion and ON app"}]},{"_type":"block","_key":"fk3qu300a","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"b4bhd8980","text":"SoundSupport™ for tinnitus management"}]},{"_type":"block","_key":"59dhimn61","style":"h3","children":[{"_type":"span","_key":"3d04ge43h","text":"Oticon CROS"}]},{"_type":"block","_key":"7dxox9jj3","style":"normal","children":[{"_type":"span","_key":"cu52on6bk","text":"Single-sided deafness is when one ear has little or no usable hearing. The Oticon CROS is engineered for people with single-sided deafness. It works by wirelessly sending sound from your poorer ear to your better ear, so you can hear voices and sounds coming from all directions."}]},{"_type":"block","_key":"yaddwywkm","style":"normal","children":[{"_type":"span","_key":"5flbrelfa","text":"Compatible With:","marks":["strong"]}]},{"_type":"block","_key":"inpg6b996","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"usqpgr0d6","text":"Oticon Real™"}]},{"_type":"block","_key":"g0q6jrjsw","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"4a6l9iigu","text":"More™"}]},{"_type":"block","_key":"pn9rd7s7h","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"6h49polaf","text":"Zircon™"}]},{"_type":"block","_key":"l7x5z0hnl","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"29auqg49f","text":"Opn S™"}]},{"_type":"block","_key":"tlvi2vfk8","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"m1gjtw63o","text":"Play PX™"}]},{"_type":"block","_key":"pvaw9nd4z","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"g5tdaea8r","text":"Xceed™"}]},{"_type":"block","_key":"d2g389d0p","style":"normal","children":[{"_type":"span","_key":"dujd3qnkh","text":"Key Features:","marks":["strong"]}]},{"_type":"block","_key":"rvdsghkcr","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"46fhfx4ov","text":"TwinLink™ Bluetooth® for streaming and sound transmission"}]},{"_type":"block","_key":"g5um6imia","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"uv7cbmk0j","text":"App-based remote control"}]},{"_type":"block","_key":"ynp54rkmy","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"s0n34elfv","text":"Built-in tinnitus support"}]},{"_type":"block","_key":"ro7kol90c","style":"h3","children":[{"_type":"span","_key":"7opbn9fnt","text":"Oticon Play PX"}]},{"_type":"block","_key":"bp4tofqmx","style":"normal","children":[{"_type":"span","_key":"m7zyyvt28","text":"The Oticon Play PX is the first pediatric hearing aid built with Oticon’s polaris™ platform and advanced BrainHearing™ technology. This is a highly-recommended hearing support specially designed for children of all ages."}]},{"_type":"block","_key":"u2mb6ixqp","style":"normal","children":[{"_type":"span","_key":"p4pvkypmw","text":"Give your child the key to unlimited learning through effective hearing. Let them develop speech, language, and learning skills by giving them access to clear, detailed sound in all listening environments."}]},{"_type":"block","_key":"qxvd9p0m7","style":"normal","children":[{"_type":"span","_key":"o9uonhl97","text":"Key Features:","marks":["strong"]}]},{"_type":"block","_key":"8z21csyxl","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"bs5l1tlsn","text":"Tamper-resistant battery doors"}]},{"_type":"block","_key":"fvkfw71mx","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"qapiywsng","text":"Water & dust resistance (IP68-rated)"}]},{"_type":"block","_key":"ftyw53zoo","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"vdx6mserh","text":"LED indicators for battery status"}]},{"_type":"block","_key":"n5po1b5h3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ayjprwhof","text":"Bluetooth® streaming to smartphones and tablets"}]},{"_type":"block","_key":"pzzswxyjh","style":"normal","children":[{"_type":"span","_key":"64jnn6yaq","text":"Accessories for Kids:","marks":["strong"]}]},{"_type":"block","_key":"ypw8tgwfn","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"rgs267an4","text":"EduMic","marks":["strong"]},{"_type":"span","_key":"xai4ykmyy","text":" – A teacher-worn mic for classroom clarity"}]},{"_type":"block","_key":"j95mwfgx4","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"guxkgj6j9","text":"Amigo FM","marks":["strong"]},{"_type":"span","_key":"nsf98ndrb","text":" – Enhances understanding in noisy settings"}]},{"_type":"block","_key":"ts4lv3ee3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"xujike9ve","text":"ConnectClip","marks":["strong"]},{"_type":"span","_key":"aa5zpj6d6","text":" – Wireless streaming up to 65 feet"}]},{"_type":"block","_key":"5b30b9wsj","style":"h3","children":[{"_type":"span","_key":"yx412jqx5","text":"Oticon Xceed"}]},{"_type":"block","_key":"ut5hfoahi","style":"normal","children":[{"_type":"span","_key":"82zkqi4r5","text":"Oticon Xceed is recommended for individuals with severe to profound hearing loss. It offers strong amplification and full 360° sound awareness. BrainHearing™ technology helps the brain focus on speech while reducing background noise and overall listening effort."}]},{"_type":"block","_key":"wcgxoqrbx","style":"normal","children":[{"_type":"span","_key":"wvh1z17r7","text":"Key Features:","marks":["strong"]}]},{"_type":"block","_key":"53gp9frhr","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"lqao03v0f","text":"Bluetooth® streaming for calls and media"}]},{"_type":"block","_key":"15m16b87y","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"x9jmcxy7c","text":"Real-time adjustments via app"}]},{"_type":"block","_key":"ttnha8yfn","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"cemx01vk3","text":"Tinnitus relief with SoundSupport™"}]},{"_type":"block","_key":"e5cnxlrea","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"7vgtwd8yi","text":"Available in rechargeable and disposable models"}]},{"_type":"block","_key":"ew59us7hl","style":"h2","children":[{"_type":"span","_key":"insawv2uy","text":"Assistive Listening Devices & Technology by Oticon"}]},{"_type":"block","_key":"2k0lszpqt","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"z4f4vv3ql","text":"ConnectClip"}]},{"_type":"block","_key":"y6n7smo64","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"npd53lzff","text":"Remote Control"}]},{"_type":"block","_key":"mp5rrob35","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"2z4m83i23","text":"Streamer Pro"}]},{"_type":"block","_key":"s0uoj0pb3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ctts7f0nj","text":"TV Adapter"}]},{"_type":"block","_key":"z9ylyh9op","style":"h2","children":[{"_type":"span","_key":"acrfth9vw","text":"Older Oticon Models We Service"}]},{"_type":"block","_key":"an77n3v79","style":"normal","children":[{"_type":"span","_key":"oegfv9dhs","text":"At JC Audiology, we also provide repairs and maintenance for many previous-generation Oticon hearing aids, including:"}]},{"_type":"block","_key":"j5ek6a3c5","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"3hskpeo0v","text":"Oticon Opn"}]},{"_type":"block","_key":"e8hp4m2u4","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ola9zwint","text":"Oticon Opn Play"}]},{"_type":"block","_key":"ecynjzrht","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"9v4zu5ue7","text":"Oticon Opn S"}]},{"_type":"block","_key":"brg1x8x2k","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"h1ccmttq7","text":"Oticon Ruby"}]},{"_type":"block","_key":"f7cr4mj2u","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"nc2ptm6f4","text":"Oticon Siya"}]},{"_type":"block","_key":"usfctpml8","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"6p8gxim5v","text":"Oticon More"}]},{"_type":"block","_key":"6ziu7fw8w","style":"normal","children":[{"_type":"span","_key":"aywzdyj9z","text":"If you have an older Oticon model and need support, we’re here to help!"}]},{"_type":"block","_key":"0ozwlynja","style":"h2","children":[{"_type":"span","_key":"fwv5hd9ok","text":"FAQs – Oticon Hearing Aids"}]},{"_type":"block","_key":"arxxjas2i","style":"h3","children":[{"_type":"span","_key":"7xxuuh426","text":"How long do Oticon hearing aids last?"}]},{"_type":"block","_key":"ywzma4p4h","style":"normal","children":[{"_type":"span","_key":"u4hf2pkvb","text":"On average, Oticon hearing aids last about 5 to 7 years with proper care."}]},{"_type":"block","_key":"sxjpl9usy","style":"normal","children":[{"_type":"span","_key":"hpesmyqja","text":"Their lifespan can vary depending on daily use, maintenance, environment, and tech updates. With good care and professional checkups, Oticon hearing aids can provide many years of reliable hearing support before needing replacement."}]},{"_type":"block","_key":"3zu1duf77","style":"h3","children":[{"_type":"span","_key":"luy0b3jil","text":"What is Oticon’s newest hearing aid?"}]},{"_type":"block","_key":"zjylkczcg","style":"normal","children":[{"_type":"span","_key":"sq9ykl6ir","text":"As of 2026, the Oticon Zeal is the most recent addition to the company’s device line-up. It debuted in January 2026. It is the first discreet custom hearing aid to integrate second-generation Deep Neural Network (DNN 2.0) technology for superior speech clarity in noise."}]},{"_type":"block","_key":"zw8m69620","style":"h3","children":[{"_type":"span","_key":"mqmibbpa4","text":"Which Oticon hearing aids offer tinnitus relief?"}]},{"_type":"block","_key":"4aqb60385","style":"normal","children":[{"_type":"span","_key":"x547i2uyk","text":"Most modern Oticon hearing aids include built-in tinnitus relief features through the Oticon Tinnitus SoundSupport™ system."}]},{"_type":"block","_key":"kreiz3u4k","style":"normal","children":[{"_type":"span","_key":"2p7p2p7r8","text":"This feature plays soothing background sounds such as white noise, soft ocean waves, or other custom tones that help reduce the perception of tinnitus. These sounds can be adjusted by an audiologist or hearing aid specialist to fit your personal comfort and listening needs."}]},{"_type":"block","_key":"jjgkh5hl9","style":"normal","children":[{"_type":"span","_key":"2q8k413o4","text":"Oticon models that offer tinnitus relief include:"}]},{"_type":"block","_key":"7d0l9ciab","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"1jenw4fy0","text":"Oticon Intent (premium)"}]},{"_type":"block","_key":"g2dre48th","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"tcsb2ci58","text":"Oticon Real"}]},{"_type":"block","_key":"od8zq0l5r","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"2rcoifcdm","text":"Oticon More"}]},{"_type":"block","_key":"fyveqioxq","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"9lazh5a0v","text":"Oticon Own (custom in-the-ear styles)"}]},{"_type":"block","_key":"ng3c608e4","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"8q7dalqvc","text":"Oticon Zircon"}]},{"_type":"block","_key":"8hcox9ubx","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ph9qa6u8q","text":"Oticon Play PX (pediatric model)"}]},{"_type":"block","_key":"fdkc912u3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"cvm1lpnda","text":"Oticon Xceed (for severe to profound hearing loss)"}]},{"_type":"block","_key":"s1cp8rqir","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"fbrr9lytt","text":"Oticon Ruby"}]},{"_type":"block","_key":"z96zge07r","style":"normal","children":[{"_type":"span","_key":"2or1kf0d5","text":"Nearly all current Oticon models with the BrainHearing™ platform can be programmed for tinnitus management, making it easier to pair relief with your daily hearing correction."}]},{"_type":"block","_key":"ydiuce2t8","style":"normal","children":[{"_type":"span","_key":"0v2g7jmsq","text":"If you’re experiencing tinnitus, our Lutz, FL audiologist and hearing aid specialist can recommend the best Oticon device to support your hearing and provide relief."}]},{"_type":"block","_key":"k7vl23lsl","style":"h2","children":[{"_type":"span","_key":"zlg453fjz","text":"Find the Right Oticon Hearing Aid in Lutz, FL"}]},{"_type":"block","_key":"1gxqe6s8w","style":"normal","children":[{"_type":"span","_key":"ptlfmyn78","text":"At JC Audiology, we can help you find the Oticon hearing aid that fits your hearing needs and lifestyle. As an authorized Oticon provider in Lutz, FL, we offer the latest models, expert fittings, and personalized care."}]},{"_type":"block","_key":"li58t8er4","style":"normal","children":[{"_type":"span","_key":"nac3cvbf8","text":"Schedule your consultation today and take the next step toward clearer hearing and greater confidence."}]}]}',NULL,'2026-05-21 06:14:27');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS4JT4KF2F1HFAA4RKG3SX95','services','audiology-services__real-ear-measurement','{"title":"Real Ear Measurement test","route":"/audiology-services/real-ear-measurement/","meta_title":"Real Ear Measurement","meta_description":"JC Audiology provides real ear measurements as part of hearing aid fitting best practices in Lutz, FL.","body_content":[{"_type":"block","_key":"b-ad89363e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-da617dec","text":"JC Audiology provides real ear measurements as part of hearing aid fitting best practices in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-eb3e7739","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-11ed9b98","text":"Real Ear Measurement, or REM, is one of the most important steps in making sure your hearing aids give you the clearest and most comfortable sound possible.","marks":[]}]},{"_type":"block","_key":"b-1426eb81","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3b4eae85","text":"Everyone’s ears are shaped differently. Some are narrow, some are wider, and some have twists and turns. Because of these differences, sound travels through each person’s ear in a unique way.","marks":[]}]},{"_type":"block","_key":"b-36546a5b","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-68366f46","text":"At JC Audiology, our audiologists and hearing aid specialists use REM to see exactly how sound behaves inside your ear canal. Once we have this information, we can adjust your hearing aids so they match your exact hearing needs. This means you can hear speech more clearly, enjoy everyday sounds, and listen more comfortably in noisy places.","marks":[]}]},{"_type":"block","_key":"b-1a9588e2","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-ea4f4c49","text":"Why Is REM Important?","marks":[]}]},{"_type":"block","_key":"b-25838006","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0cc7c575","text":"REM is often called the gold standard for hearing aid fittings because it makes the process much more accurate than using factory settings or “best guess” adjustments.","marks":[]}]},{"_type":"block","_key":"b-c154d9a8","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-15507ef6","text":"Without REM, your hearing aids might be too loud, too soft, or not give you the clarity you need in conversations. This can lead to frustration, listening fatigue, or the feeling that your hearing aids just aren’t working as well as they should.","marks":[]}]},{"_type":"block","_key":"b-c7ebc092","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-af116237","text":"How Does Real Ear Measurement Work?","marks":[]}]},{"_type":"block","_key":"b-d1098db7","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-01e10fe7","text":"The process is simple and comfortable. First, the audiologist or hearing aid specialist will gently place a very thin probe microphone in your ear canal. This is done while you are wearing your hearing aid. The microphone sits close to your eardrum but does not touch it, so you should not feel any pain.","marks":[]}]},{"_type":"block","_key":"b-61bf306f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0ff553c4","text":"Next, a speaker nearby plays different test sounds. The microphone measures how these sounds behave inside your ear canal. This gives us a real ear response, which is like a fingerprint of your ear’s unique acoustics.","marks":[]}]},{"_type":"block","_key":"b-d5f83f2e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2da86a2a","text":"We then compare these measurements to your ideal hearing levels, based on your hearing test results. If your hearing aids are not delivering the right amount of amplification, we make changes on the spot. You can hear the difference instantly.","marks":[]}]},{"_type":"block","_key":"b-3b8b8e32","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3142f529","text":"Once everything sounds balanced, we verify the results one last time to ensure accuracy.","marks":[]}]},{"_type":"block","_key":"b-32fb1691","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-9d916f4b","text":"Why Real Ear Measurement Is Better Than Automatic Programming","marks":[]}]},{"_type":"block","_key":"b-07a02a04","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ce59e8b3","text":"Most hearing aids today come with automatic programming, also known as first fit.","marks":[]},{"_type":"span","_key":"s-97e05c52","text":"This refers to preset settings of hearing devices. These settings don’t factor in the exact shape and size of your ears.","marks":[]}]},{"_type":"block","_key":"b-40efe7d3","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ea07d78f","text":"Think of it as buying shoes in your size without actually trying them on. They might fit okay, but they won’t give a perfect fit!","marks":[]}]},{"_type":"block","_key":"b-418119f4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a4fa0936","text":"REM, on the other hand, is like having your shoes custom-fitted. It measures sound in your ears, not in a test box or computer simulation. By making adjustments based on these real measurements, we can improve your sound quality, comfort, and ability to follow conversations.","marks":[]}]},{"_type":"block","_key":"b-55128228","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-2cce1c69","text":"Hearing Aid Fitting in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-7dd2f0a4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-97ba2503","text":"At JC Audiology, we believe every hearing aid fitting should include Real Ear Measurement.","marks":[]}]},{"_type":"block","_key":"b-a86d4e5b","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-aadf1208","text":"Whether you are getting your first pair of hearing aids or replacing older ones, this process helps you get the most from your investment in better hearing.","marks":[]}]},{"_type":"block","_key":"b-f8d16339","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-7b07180b","text":"Our audiologist and hearing aid specialist are trained to make precise adjustments using REM so that your devices match your unique hearing needs. We’re here to make sure you hear your best, every day, in every situation.","marks":[]}]},{"_type":"block","_key":"b-92971fb9","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-981dd75a","text":"Call JC Audiology today to schedule your professional hearing aid fitting with Real Ear Measurement in Lutz, FL!","marks":[]}]}]}',NULL,'2026-05-21 06:15:51');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS4QBTKMVVK3NBQ1X0567ZB9','homepage_services_section','our-services','{"section_title":"Audiology Services in Lutz, FL","section_subheading":"Our Services","featured_image":{"id":"media-homepage-bcc71369-jc-audiology-services-01","src":"/_emdash/api/media/file/homepage-sections/bcc71369-jc-audiology-services-01.webp","alt":"Clinician uses otoscope to examine woman’s ear in exam room","provider":"local","meta":{"storageKey":"homepage-sections/bcc71369-jc-audiology-services-01.webp"}},"services":[{"service_title":"Hearing Evaluations","description":"JC Audiology offers comprehensive hearing assessments to accurately diagnose your hearing health. These tests help identify the degree and type of hearing loss you may have. Trust us to provide tailored solutions to match your unique hearing needs.","service_url":"/audiology-services/hearing-tests/"},{"service_title":"Tinnitus Evaluation and Support","description":"If you experience ringing, buzzing, or other “phantom sounds” in your ears, we can help. Our tinnitus evaluations help identify the root causes of your symptoms. We provide personalized treatment plans designed to ease the discomfort and help you regain peace and clarity.","service_url":"/audiology-services/tinnitus-evaluation-support/"},{"service_title":"Hearing Aid Services","description":"From helping you select the right hearing aid to expert fitting, cleaning, and repairs, we support you throughout your hearing aid journey. Our goal is to ensure that you have the best hearing experience possible, no matter where you are.","service_url":"/audiology-services/hearing-aid-services/"},{"service_title":"Hearing Aid Fittings","description":"A proper hearing aid fitting is essential to achieving the best results. At JC Audiology, we focus on fitting each device precisely to your unique needs, ensuring maximum comfort and performance for enhanced hearing and quality of life.","service_url":"/audiology-services/hearing-aid-fittings/"},{"service_title":"Hearing Aid Cleaning and Repair","description":"If your hearing aid isn’t performing at its best, we’re here to help. Our quick and reliable cleaning and repair services will restore your device’s functionality. Enjoy clear and comfortable hearing with JC Audiology.","service_url":"/audiology-services/sensorineural-hearing-loss/"}]}',NULL,'2026-05-21 07:35:25');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS4QK8DWWPCG1WQJ0A4SNVQX','homepage_hearing_solutions_section','our-hearing-solutions','{"section_title":"Our Hearing Aids & Protection Solutions in Lutz, FL test","section_subheading":"Our Hearing Solutions test","featured_image":{"id":"media-blog-af831a2a-hearing-test-online-helpful-or-risky-featured","provider":"local","filename":"af831a2a-hearing_test_online_helpful_or_risky_featured.jpg","mimeType":"image/jpeg","width":800,"height":532,"alt":"Hearing Test Online: Helpful First Step or Risky Shortcut?","meta":{"storageKey":"blog/af831a2a-hearing_test_online_helpful_or_risky_featured.jpg","caption":null,"blurhash":null,"dominantColor":null}},"brands_label":"Supported Hearing Aid Brands test","brand_logo_1":{"id":"media-homepage-76fb611a-signia-logo-300x300","provider":"local","filename":"76fb611a-signia-logo-300x300.webp","mimeType":"image/webp","width":300,"height":300,"alt":"signia-logo","meta":{"storageKey":"homepage-sections/76fb611a-signia-logo-300x300.webp","caption":null,"blurhash":null,"dominantColor":null}},"brand_logo_2":{"id":"media-homepage-e4d08723-oticon-logo-300x300","provider":"local","filename":"e4d08723-oticon-logo-300x300.webp","mimeType":"image/webp","width":300,"height":300,"alt":"oticon-logo","meta":{"storageKey":"homepage-sections/e4d08723-oticon-logo-300x300.webp","caption":null,"blurhash":null,"dominantColor":null}},"brand_logo_3":{"id":"media-homepage-8ee33448-widex-logo-300x300","provider":"local","filename":"8ee33448-widex-logo-300x300.webp","mimeType":"image/webp","width":300,"height":300,"alt":"widex-logo","meta":{"storageKey":"homepage-sections/8ee33448-widex-logo-300x300.webp","caption":null,"blurhash":null,"dominantColor":null}},"brand_logo_4":{"id":"media-homepage-2572bb02-starkey-logo-300x300","provider":"local","filename":"2572bb02-starkey-logo-300x300.webp","mimeType":"image/webp","width":300,"height":300,"alt":"starkey-logo","meta":{"storageKey":"homepage-sections/2572bb02-starkey-logo-300x300.webp","caption":null,"blurhash":null,"dominantColor":null}},"brand_logo_5":{"id":"media-homepage-c826ce45-resound-logo-300x300","provider":"local","filename":"c826ce45-resound-logo-300x300.webp","mimeType":"image/webp","width":300,"height":300,"alt":"resound-logo","meta":{"storageKey":"homepage-sections/c826ce45-resound-logo-300x300.webp","caption":null,"blurhash":null,"dominantColor":null}},"brand_logo_6":{"id":"media-homepage-76fb611a-signia-logo-300x300","provider":"local","filename":"76fb611a-signia-logo-300x300.webp","mimeType":"image/webp","width":300,"height":300,"alt":"signia-logo","meta":{"storageKey":"homepage-sections/76fb611a-signia-logo-300x300.webp","caption":null,"blurhash":null,"dominantColor":null}},"brand_logo_7":{"id":"media-homepage-62cc30e4-unitron-logo-300x300","provider":"local","filename":"62cc30e4-unitron-logo-300x300.webp","mimeType":"image/webp","width":300,"height":300,"alt":"unitron-logo","meta":{"storageKey":"homepage-sections/62cc30e4-unitron-logo-300x300.webp","caption":null,"blurhash":null,"dominantColor":null}},"brand_logo_8":{"id":"media-homepage-6846f282-lyric-logo-300x300","provider":"local","filename":"6846f282-lyric-logo-300x300.webp","mimeType":"image/webp","width":300,"height":300,"alt":"lyric-logo","meta":{"storageKey":"homepage-sections/6846f282-lyric-logo-300x300.webp","caption":null,"blurhash":null,"dominantColor":null}},"services":[{"service_title":"Hearing Aids test","description":"test We offer a wide selection of high-quality, hearing aids from trusted manufacturers like Phonak, Oticon, ReSound, Unitron, Widex, Starkey, Signia, and Lyric. Our expert team will help you choose the best hearing aid for your unique needs and lifestyle.","service_url":"/hearing-tests/"},{"service_title":"Hearing Aid Batteries and Accessories","description":"To keep your hearing aids performing their best, we provide a variety of essential accessories, including batteries, cleaning tools, and more. Count on us to make maintaining your hearing aids simple, ensuring their longevity and superior performance.","service_url":"/hearing-aids-products/hearing-aid-batteries/"},{"service_title":"Assistive Listening Devices","description":"If you struggle to hear clearly in noisy places or during phone calls, our assistive listening devices can help. These tools are designed to enhance your hearing in challenging environments. Whether you’re at home, at work, or on the go, you can enjoy clearer conversations with ALDs.","service_url":"/hearing-aids-products/hearing-aid-alternatives/"},{"service_title":"Custom Ear Protection","description":"Whether you’re a musician, a swimmer, or an employee constantly exposed to a noisy environment, our custom-fit earplugs offer the best protection you need. We provide custom ear protection tailored to fit your ears perfectly!","service_url":"/custom-hearing-protection/"}]}',NULL,'2026-05-21 07:39:28');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS50EEVYQEA5PQKEHWGR6JKB','homepage','home','{"hero_intro":"Hearing For Life","hero_content":"Let''s help you make meaningful connections with expert hearing care!","appointment_cta_url":"/schedule-appointment/","intro_section_intro":"JC Audiology","intro_h1_title":"LUTZ, FL AUDIOLOGIST, HEARING AID SPECIALIST & HEARING AIDS","intro_body_content":[{"_type":"block","_key":"b-9a3f95ec","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6735a33b","text":"At JC Audiology, we understand how hearing loss can creep up on you and affect your daily life in subtle, frustrating ways. Hearing loss can feel isolating, and over time, it can even affect your mental sharpness. The good news is that treating your hearing loss can help.","marks":[]}]},{"_type":"block","_key":"b-b7797ab3","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-15d91905","text":"Let us help you regain the joy of hearing and the quality of life you deserve.","marks":[]}]}],"badge_1":{"id":"media-homepage-badge-american-academy-of-audiology","provider":"local","filename":"cf0c55f6-american-academy-of-audiology.webp","mimeType":"image/webp","width":340,"height":240,"alt":"American Academy of Audiology logo","meta":{"storageKey":"homepage/cf0c55f6-american-academy-of-audiology.webp","caption":null,"blurhash":null,"dominantColor":null},"src":"/_emdash/api/media/file/homepage/cf0c55f6-american-academy-of-audiology.webp"},"badge_2":{"id":"media-homepage-badge-academy-of-doctors-of-audiology","provider":"local","filename":"a717e552-academy-of-doctors-of-audiology.webp","mimeType":"image/webp","width":340,"height":240,"alt":"Academy of Doctors of Audiology logo","meta":{"storageKey":"homepage/a717e552-academy-of-doctors-of-audiology.webp","caption":null,"blurhash":null,"dominantColor":null},"src":"/_emdash/api/media/file/homepage/a717e552-academy-of-doctors-of-audiology.webp"},"badge_3":{"id":"media-homepage-badge-asha","provider":"local","filename":"81b6f248-asha.webp","mimeType":"image/webp","width":340,"height":240,"alt":"ASHA logo with face profiles and soundwave icon","meta":{"storageKey":"homepage/81b6f248-asha.webp","caption":null,"blurhash":null,"dominantColor":null},"src":"/_emdash/api/media/file/homepage/81b6f248-asha.webp"},"badge_4":{"id":"media-homepage-badge-ihs","provider":"local","filename":"90fe12a0-ihs.png","mimeType":"image/png","width":340,"height":240,"alt":"IHS logo with heartbeat line through letters","meta":{"storageKey":"homepage/90fe12a0-ihs.png","caption":null,"blurhash":null,"dominantColor":null},"src":"/_emdash/api/media/file/homepage/90fe12a0-ihs.png"},"testimonial_eyebrow_text":"What Our Patients Are Saying","testimonial_h2_title":"Client Testimonials","testimonial_body_content":[{"_type":"block","_key":"b-cda50aef","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3d25c433","text":"Your hearing health is our top priority, and we are dedicated to providing compassionate care. Hear from our patients in Lutz, FL, about their experiences with our services!","marks":[]}]}],"faq_h2_title":"Frequently Asked Questions","faq_body_content":[{"_type":"block","_key":"b-f4a1b7c9","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-5c2768f9","text":"Can''t find the answers you''re looking for?\nReach out us.","marks":[]}]}],"faq_cta_url":"/contact/","faq_items":[{"question":"How do I know if I need a hearing aid?","answer":"If you''re experiencing difficulty hearing in conversations, particularly in noisy environments, frequently turning up the volume on the TV or radio, or feeling isolated from social interactions, it may be time to consider a hearing test. An audiologist can evaluate your hearing and help determine if a hearing aid is necessary."},{"question":"What is the difference between hearing aids and personal sound amplification products (PSAPs)?","answer":"Hearing aids are FDA-approved devices specifically designed for people with hearing loss. They are customizable, programmed by an audiologist, and regulated for medical use. PSAPs, on the other hand, are general amplifiers intended for individuals without hearing loss and do not offer the same level of customization or professional support."},{"question":"Can I get a hearing aid without a hearing test?","answer":"Yes, you can purchase over-the-counter (OTC) hearing aids without a hearing test. However, these devices are typically intended for adults with mild to moderate hearing loss. A hearing test with an audiologist ensures that you get a personalized solution that addresses your specific needs, including identifying any underlying medical conditions."},{"question":"How can hearing aids help with tinnitus?","answer":"Hearing aids can help mask the ringing or buzzing associated with tinnitus by amplifying external sounds, making the internal noise less noticeable. Some hearing aids are specifically designed to include features that provide sound therapy to help alleviate tinnitus symptoms."}]}',NULL,'2026-05-21 10:14:08');
