INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services-block-012','audiology-services-block-012','published',NULL,NULL,'2026-05-20T20:45:00.348Z','2026-05-20T20:45:00.348Z','2026-05-20T20:45:00.348Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Hearing ProtectionNoise can sneak up on your ears and cause lasting damage. At J','audiology-services','rich_text','[{"_type":"block","_key":"b-uj7qy0jj","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-14xgcuj7","text":"Hearing Protection","marks":[]}]},{"_type":"block","_key":"b-dz5r4yut","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-zgjcdwd5","text":"Noise can sneak up on your ears and cause lasting damage. At JC Audiology, we provide a wide selection of hearing protection. Whether it''s for music, water activities, work, or recreation, hearing protection help you enjoy life while keeping your hearing healthy.","marks":[]}]}]','','27fbf67',12);
