INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__hearing-aid-fittings-block-003','audiology-services__hearing-aid-fittings-block-003','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Why a Professional Hearing Aid Fitting ImportantA good fitting helps you hear be','audiology-services__hearing-aid-fittings','rich_text','[{"_type":"block","_key":"b-fvmmwemf","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-injtxre4","text":"Why a Professional Hearing Aid Fitting Important","marks":[]}]},{"_type":"block","_key":"b-ohdi7t6y","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-p6l4xz07","text":"A good fitting helps you hear better in many everyday situations. When hearing aids are properly adjusted, you can understand speech more clearly, background noise is easier to ignore, and sounds feel natural.","marks":[]}]},{"_type":"block","_key":"b-x7q3rqk4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-zdohjyvm","text":"Our audiologists at JC Audiology make sure your hearing aids work the best they can for you.","marks":[]}]}]','','7b393fc',3);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__hearing-aid-fittings-block-004','audiology-services__hearing-aid-fittings-block-004','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Divider','audiology-services__hearing-aid-fittings','divider','[]','','a37fdfb',4);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__hearing-aid-fittings-block-005','audiology-services__hearing-aid-fittings-block-005','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Why Should an Audiologist Fit Your Hearing AidsAudiologists are experts in heari','audiology-services__hearing-aid-fittings','rich_text','[{"_type":"block","_key":"b-pamnztjg","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-v5iqx01z","text":"Why Should an Audiologist Fit Your Hearing Aids","marks":[]}]},{"_type":"block","_key":"b-jybq2qym","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-cvh3ilhg","text":"Audiologists are experts in hearing health. They know how to set up your hearing aids just right. If hearing aids aren’t fitted properly, they might feel uncomfortable or sound strange.","marks":[]}]},{"_type":"block","_key":"b-f70dps24","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-at89gvaf","text":"At JC Audiology, we make sure your hearing aids fit your ears perfectly and feel good all day long.","marks":[]}]}]','','ff66d44',5);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__hearing-aid-fittings-block-006','audiology-services__hearing-aid-fittings-block-006','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Divider','audiology-services__hearing-aid-fittings','divider','[]','','748db25',6);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__hearing-aid-fittings-block-007','audiology-services__hearing-aid-fittings-block-007','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'What Happens During a Hearing Aid FittingDuring your appointment, the audiologis','audiology-services__hearing-aid-fittings','rich_text','[{"_type":"block","_key":"b-4kgw4m4w","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-tve3x6td","text":"What Happens During a Hearing Aid Fitting","marks":[]}]},{"_type":"block","_key":"b-z5yglg6h","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-cal7vfpc","text":"During your appointment, the audiologist will review your hearing test results and explain how hearing aids can help you. You’ll pick a hearing aid that fits your needs and lifestyle.","marks":[]}]},{"_type":"block","_key":"b-0ll74btg","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6kmil29c","text":"Your hearing aids will then be programmed using special software to match your hearing loss. We’ll use a test called Real Ear Measurement (REM), where a tiny microphone is placed in your ear to check that your hearing aids are giving the right amount of sound.","marks":[]}]},{"_type":"block","_key":"b-9wcfm2tk","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-wnw9zro9","text":"You’ll also learn how to put in, take out, clean, and care for your hearing aids. Follow-up visits will be scheduled to adjust your hearing aids based on how they work for you in everyday life.","marks":[]}]}]','','7c0fe7e',7);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__hearing-aid-fittings-block-008','audiology-services__hearing-aid-fittings-block-008','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Divider','audiology-services__hearing-aid-fittings','divider','[]','','3a34b54',8);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__hearing-aid-fittings-block-009','audiology-services__hearing-aid-fittings-block-009','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'What to Expect After Your First FittingYour first fitting is an important step, ','audiology-services__hearing-aid-fittings','rich_text','[{"_type":"block","_key":"b-mlulvyap","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-o18xymoh","text":"What to Expect After Your First Fitting","marks":[]}]},{"_type":"block","_key":"b-fb91ajxb","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-d7l11kcb","text":"Your first fitting is an important step, but it takes time to get used to hearing aids. You might notice sounds you haven’t heard in a while (like footsteps or clocks ticking) and your own voice may sound different. This is normal, and your brain will get used to it over time.","marks":[]}]},{"_type":"block","_key":"b-qvje5dom","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-jcea34s1","text":"We’ll support you through this process and make any needed adjustments to help you feel comfortable and confident.","marks":[]}]},{"_type":"block","_key":"b-6gb2pz44","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-bssuf8mq","text":"What Is Real Ear Measurement (REM)","marks":[]}]},{"_type":"block","_key":"b-ts9dubn0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-k4j99f1v","text":"REM is a special test that checks how your hearing aids deliver sound inside your ear. A tiny microphone is placed in your ear canal to measure the sound levels.","marks":[]}]},{"_type":"block","_key":"b-tok6q666","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-wr7hmf0d","text":"This helps your audiologist fine-tune your hearing aids so they fit your ear perfectly and give you the best sound quality.","marks":[]}]}]','','498e1cd',9);
