INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__hearing-aid-fittings-block-012','audiology-services__hearing-aid-fittings-block-012','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Adjusting to Hearing AidsWhen you start wearing hearing aids, your brain needs t','audiology-services__hearing-aid-fittings','rich_text','[{"_type":"block","_key":"b-pd8ui66i","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-xd22hkwr","text":"Adjusting to Hearing Aids","marks":[]}]},{"_type":"block","_key":"b-glgmg3i8","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-cfgo2j6g","text":"When you start wearing hearing aids, your brain needs time to adjust. It’s perfectly normal if you feel that sounds might seem louder or some things or voices might sound strange.","marks":[]}]},{"_type":"block","_key":"b-dhe31ry5","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-lwj6yobe","text":"Tips to Help You Adjust:","marks":["strong"]}]},{"_type":"block","_key":"b-yvphssp7","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-v5mr53d1","text":"Wear your hearing aids for a few hours each day at first, then slowly wear them longer.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-j12mlwax","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-evzkq8l9","text":"Start in quiet places before trying louder environments.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-uzesa9ua","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2eca7gaj","text":"Be patient. Getting used to hearing aids can take a few weeks.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-v56m71v4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-mgwqxq4l","text":"Regular use and support from your audiologist will help you get the best results.","marks":[]}]}]','','560b03d',12);
