INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__hearing-tests-block-001','audiology-services__hearing-tests-block-001','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'JC Audiology provides comprehensive hearing tests in Lutz, FL.Hearing tests help','audiology-services__hearing-tests','rich_text','[{"_type":"block","_key":"b-wnmawxzn","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8prbq5ui","text":"JC Audiology provides comprehensive hearing tests in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-jn7rbnib","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ppjbk6mg","text":"Hearing tests help us get a bigger and clearer picture of one’s hearing health. Through hearing tests, audiologists and hearing aid specialists can spot or confirm any issues that might be affecting your communication.","marks":[]}]},{"_type":"block","_key":"b-bxemmpqx","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3fqs3x73","text":"At JC Audiology, we use advanced diagnostic tools to assess your hearing and provide personalized solutions.","marks":[]}]},{"_type":"block","_key":"b-4w87tzpn","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-csqfoq8d","text":"Our expert audiologist and hearing aid specialist in Lutz, FL, is committed to guiding you through every stage of your hearing health journey.","marks":[]}]},{"_type":"block","_key":"b-2x1dt3tx","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-fajtrsnl","text":"Let’s help you achieve hearing with comfort and clarity!","marks":[]}]}]','','c992a54',1);
