INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__hearing-tests-block-003','audiology-services__hearing-tests-block-003','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'When Should You Get Your Hearing Tested?If you recently noticed changes in your ','audiology-services__hearing-tests','rich_text','[{"_type":"block","_key":"b-1zg39ak2","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-0z0b9sn6","text":"When Should You Get Your Hearing Tested?","marks":[]}]},{"_type":"block","_key":"b-rs0muefg","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-pvkrg7qm","text":"If you recently noticed changes in your hearing, it’s time for a test.","marks":[]}]},{"_type":"block","_key":"b-s7uflcjc","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-k3q5ojti","text":"Hearing loss often happens gradually, so early signs can be easy to miss.","marks":[]}]},{"_type":"block","_key":"b-bpkkrsmy","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-58ra6uf0","text":"You might find it tough to follow speech in noisy places. You may find yourself asking people more often to repeat themselves. Or you may feel like everyone is mumbling or eating their words.","marks":[]}]},{"_type":"block","_key":"b-jqisxd6a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-fxkotdnu","text":"This is where hearing tests come in. Getting your hearing tested by an audiologist or hearing aid specialist ensures an accurate diagnosis.","marks":[]}]},{"_type":"block","_key":"b-z6ip5cab","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9adjx0ae","text":"JC Audiology provides hearing tests in Lutz, FL.","marks":[]}]}]','','62d1625',3);
