INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__hearing-tests-block-009','audiology-services__hearing-tests-block-009','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Schedule Your Hearing Test in Lutz, FLGetting your hearing tested is the first s','audiology-services__hearing-tests','rich_text','[{"_type":"block","_key":"b-zl04scds","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-jx2c0lae","text":"Schedule Your Hearing Test in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-lnno3lds","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-52fzjslh","text":"Getting your hearing tested is the first step to better hearing.","marks":[]}]},{"_type":"block","_key":"b-lk8z08ph","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-pv0mpag1","text":"Let our experienced audiologist and hearing aid specialist help you understand your hearing!","marks":[]}]},{"_type":"block","_key":"b-16jhb7zu","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-7he7sxku","text":"Call us today to book your hearing test in Lutz, FL!","marks":[]}]}]','','a912d87',9);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__real-ear-measurement-block-001','audiology-services__real-ear-measurement-block-001','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'JC Audiology provides real ear measurements as part of hearing aid fitting best ','audiology-services__real-ear-measurement','rich_text','[{"_type":"block","_key":"b-7jo69jio","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-302q7ihl","text":"JC Audiology provides real ear measurements as part of hearing aid fitting best practices in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-wi6js8yx","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ns5tddku","text":"Real Ear Measurement, or REM, is one of the most important steps in making sure your hearing aids give you the clearest and most comfortable sound possible.","marks":[]}]},{"_type":"block","_key":"b-l1s7yv4u","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1epq6mxh","text":"Everyone’s ears are shaped differently. Some are narrow, some are wider, and some have twists and turns. Because of these differences, sound travels through each person’s ear in a unique way.","marks":[]}]},{"_type":"block","_key":"b-nrp88apt","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3i8q1csn","text":"At JC Audiology, our audiologists and hearing aid specialists use REM to see exactly how sound behaves inside your ear canal. Once we have this information, we can adjust your hearing aids so they match your exact hearing needs. This means you can hear speech more clearly, enjoy everyday sounds, and listen more comfortably in noisy places.","marks":[]}]}]','','491a408',1);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__real-ear-measurement-block-002','audiology-services__real-ear-measurement-block-002','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Divider','audiology-services__real-ear-measurement','divider','[]','','ff71b15',2);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__real-ear-measurement-block-003','audiology-services__real-ear-measurement-block-003','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Why Is REM Important?REM is often called the gold standard for hearing aid fitti','audiology-services__real-ear-measurement','rich_text','[{"_type":"block","_key":"b-zsz45j32","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-aplkfth9","text":"Why Is REM Important?","marks":[]}]},{"_type":"block","_key":"b-ouoqb0at","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-utjzjtx9","text":"REM is often called the gold standard for hearing aid fittings because it makes the process much more accurate than using factory settings or “best guess” adjustments.","marks":[]}]},{"_type":"block","_key":"b-gprc4zmw","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-djlgqq8o","text":"Without REM, your hearing aids might be too loud, too soft, or not give you the clarity you need in conversations. This can lead to frustration, listening fatigue, or the feeling that your hearing aids just aren’t working as well as they should.","marks":[]}]}]','','af21f03',3);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__real-ear-measurement-block-004','audiology-services__real-ear-measurement-block-004','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Accordion Group 1','audiology-services__real-ear-measurement','accordion_group','[]','audiology-services__real-ear-measurement-accordion-01','a290443',4);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__real-ear-measurement-block-005','audiology-services__real-ear-measurement-block-005','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Divider','audiology-services__real-ear-measurement','divider','[]','','77c0764',5);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__real-ear-measurement-block-006','audiology-services__real-ear-measurement-block-006','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Why Real Ear Measurement Is Better Than Automatic ProgrammingMost hearing aids t','audiology-services__real-ear-measurement','rich_text','[{"_type":"block","_key":"b-s848szzj","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-4perjhmp","text":"Why Real Ear Measurement Is Better Than Automatic Programming","marks":[]}]},{"_type":"block","_key":"b-mt16iqft","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-reukxtsp","text":"Most hearing aids today come with automatic programming, also known as first fit.","marks":[]},{"_type":"span","_key":"s-xnmz7crp","text":"This refers to preset settings of hearing devices. These settings don’t factor in the exact shape and size of your ears.","marks":[]}]},{"_type":"block","_key":"b-soaieb1g","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8hp9ca4f","text":"Think of it as buying shoes in your size without actually trying them on. They might fit okay, but they won’t give a perfect fit!","marks":[]}]},{"_type":"block","_key":"b-88im4jd3","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-k5akvknl","text":"REM, on the other hand, is like having your shoes custom-fitted. It measures sound in your ears, not in a test box or computer simulation. By making adjustments based on these real measurements, we can improve your sound quality, comfort, and ability to follow conversations.","marks":[]}]}]','','4566653',6);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__real-ear-measurement-block-007','audiology-services__real-ear-measurement-block-007','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Divider','audiology-services__real-ear-measurement','divider','[]','','b2f15b0',7);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__real-ear-measurement-block-008','audiology-services__real-ear-measurement-block-008','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Hearing Aid Fitting in Lutz, FLAt JC Audiology, we believe every hearing aid fit','audiology-services__real-ear-measurement','rich_text','[{"_type":"block","_key":"b-vzfmj653","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-wkrycfbs","text":"Hearing Aid Fitting in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-mwdizlyj","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-09r9gspf","text":"At JC Audiology, we believe every hearing aid fitting should include Real Ear Measurement.","marks":[]}]},{"_type":"block","_key":"b-mqvwbpo1","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-oewisvdv","text":"Whether you are getting your first pair of hearing aids or replacing older ones, this process helps you get the most from your investment in better hearing.","marks":[]}]},{"_type":"block","_key":"b-lo8k6l2k","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-bunmq34q","text":"Our audiologist and hearing aid specialist are trained to make precise adjustments using REM so that your devices match your unique hearing needs. We’re here to make sure you hear your best, every day, in every situation.","marks":[]}]},{"_type":"block","_key":"b-4atdoqvl","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-gj10465k","text":"Call JC Audiology today to schedule your professional hearing aid fitting with Real Ear Measurement in Lutz, FL!","marks":[]}]}]','','3093478',8);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__sensorineural-hearing-loss-block-001','audiology-services__sensorineural-hearing-loss-block-001','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'JC Audiology provides sensorineural hearing loss evaluation and treatment in Lut','audiology-services__sensorineural-hearing-loss','rich_text','[{"_type":"block","_key":"b-aza52z2f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-4jjt4hv2","text":"JC Audiology provides sensorineural hearing loss evaluation and treatment in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-xzp6iiyc","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9bh8m31f","text":"Sensorineural hearing loss, or SNHL, happens when there is damage to the inner ear or to the hearing nerve that sends sound signals to your brain. This kind of hearing loss often makes soft sounds hard to hear and can make louder sounds seem unclear, fuzzy, or muffled.","marks":[]}]},{"_type":"block","_key":"b-7jtoykez","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-w9k4y9o8","text":"Inside your inner ear are tiny hair cells that help you hear. Once these hair cells are damaged, they cannot grow back. This is why SNHL is usually permanent.","marks":[]}]}]','','d3629a1',1);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__sensorineural-hearing-loss-block-002','audiology-services__sensorineural-hearing-loss-block-002','published',NULL,NULL,'2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z','2026-05-20T20:45:00.349Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Divider','audiology-services__sensorineural-hearing-loss','divider','[]','','fae65ab',2);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__sensorineural-hearing-loss-block-003','audiology-services__sensorineural-hearing-loss-block-003','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Why Getting Treatment MattersIf SNHL is not treated, it can make it harder to en','audiology-services__sensorineural-hearing-loss','rich_text','[{"_type":"block","_key":"b-3jfvgx3w","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-r7071xrj","text":"Why Getting Treatment Matters","marks":[]}]},{"_type":"block","_key":"b-k80v2rm8","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2l9a9xal","text":"If SNHL is not treated, it can make it harder to enjoy conversations, take part in social activities, and stay connected with friends and family. Over time, untreated hearing loss can cause frustration, loneliness, and even memory or thinking problems.","marks":[]}]},{"_type":"block","_key":"b-gu52dm1k","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-630evm50","text":"The good news is that with the right care, many people can improve their hearing and enjoy life more.","marks":[]}]},{"_type":"block","_key":"b-4dlg0sg6","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-529lpvtz","text":"At JC Audiology, our audiologist and hearing aid specialist provide expert testing and treatment for sensorineural hearing loss in Lutz, FL.","marks":[]}]}]','','ae52210',3);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__sensorineural-hearing-loss-block-004','audiology-services__sensorineural-hearing-loss-block-004','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Accordion Group 1','audiology-services__sensorineural-hearing-loss','accordion_group','[]','audiology-services__sensorineural-hearing-loss-accordion-01','cd86693',4);
