INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__sensorineural-hearing-loss-block-006','audiology-services__sensorineural-hearing-loss-block-006','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'What Causes Sensorineural Hearing Loss?SNHL can be caused by many things that ha','audiology-services__sensorineural-hearing-loss','rich_text','[{"_type":"block","_key":"b-ux98iseg","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-dms9r0g0","text":"What Causes Sensorineural Hearing Loss?","marks":[]}]},{"_type":"block","_key":"b-5hdi9b71","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9cr0tzib","text":"SNHL can be caused by many things that harm the inner ear or hearing nerve, including:","marks":[]}]},{"_type":"block","_key":"b-qm2rm563","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-fqzksi8q","text":"Aging","marks":["strong"]},{"_type":"span","_key":"s-11nxbefv","text":" – As we get older, the tiny hair cells in our ears can wear out.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-0sqkmjdv","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-otpbykr3","text":"Loud noise","marks":["strong"]},{"_type":"span","_key":"s-mw98kqxm","text":" – Long-term exposure to loud sounds or one very loud noise (like a gunshot or explosion) can cause permanent damage.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-e1hc2g6c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-j7kwqo01","text":"Genetics","marks":["strong"]},{"_type":"span","_key":"s-4g8p56xk","text":" – Some people are born with hearing problems or develop them earlier in life because of inherited traits.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-emj0qf88","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-5j2o2ac0","text":"Certain medications","marks":["strong"]},{"_type":"span","_key":"s-81cgudqc","text":" – Some drugs, called “ototoxic” medicines, can harm hearing. These can include certain antibiotics, chemotherapy drugs, or large doses of aspirin.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-eo1j9ofp","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-345nsre3","text":"Head injuries","marks":["strong"]},{"_type":"span","_key":"s-fpmrm4om","text":" – Trauma to the head or skull can damage the hearing nerve or the cochlea in the inner ear.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-bykltld3","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b8q2nikz","text":"Infections","marks":["strong"]},{"_type":"span","_key":"s-6m7csonu","text":" – Illnesses like mumps, measles, meningitis, or other infections can injure the inner ear.","marks":[]}],"listItem":"bullet","level":1}]','','e546af2',6);
