INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__sensorineural-hearing-loss-block-011','audiology-services__sensorineural-hearing-loss-block-011','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Sensorineural Hearing Loss Care in Lutz, FLAt JC Audiology, we are dedicated to ','audiology-services__sensorineural-hearing-loss','rich_text','[{"_type":"block","_key":"b-0hieg4cv","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-trmsywqc","text":"Sensorineural Hearing Loss Care in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-x1qeguix","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-wtbgt81t","text":"At JC Audiology, we are dedicated to helping you hear your best. Our audiologist and hearing aid specialist offer complete hearing tests, accurate diagnosis, and personalized treatment plans for sensorineural hearing loss.","marks":[]}]},{"_type":"block","_key":"b-a3gx2xat","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9k5g3upg","text":"We use the latest technology to help improve your hearing and make it easier to connect with the people and activities you love.","marks":[]}]},{"_type":"block","_key":"b-7182hmf0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-st19mci5","text":"Call JC Audiology today to schedule your professional hearing evaluation in Lutz, FL.","marks":[]}]}]','','2ea4816',11);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__tinnitus-evaluation-support-block-001','audiology-services__tinnitus-evaluation-support-block-001','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'JC Audiology provides expert tinnitus evaluations and support in Lutz, FL.Hearin','audiology-services__tinnitus-evaluation-support','rich_text','[{"_type":"block","_key":"b-wsuvfyh9","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3v4vra89","text":"JC Audiology provides expert tinnitus evaluations and support in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-28d33dmw","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-z3kczygt","text":"Hearing phantom sounds or ringing in the ears can be disturbing, distressing, or downright distracting. At JC Audiology, we provide tinnitus evaluations and personalized treatment and management to help reduce the effects of ringing, buzzing, clicking, or hissing in your ears.","marks":[]}]},{"_type":"block","_key":"b-qdffo98n","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-vr93jka5","text":"If you or a loved one experiences ringing in the ears or related hearing issues, our audiologist in Lutz, FL is here to help you find relief.","marks":[]}]}]','','4af42cf',1);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__tinnitus-evaluation-support-block-002','audiology-services__tinnitus-evaluation-support-block-002','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Divider','audiology-services__tinnitus-evaluation-support','divider','[]','','c23d510',2);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__tinnitus-evaluation-support-block-003','audiology-services__tinnitus-evaluation-support-block-003','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'What Causes Tinnitus?Tinnitus can develop or be triggered for many reasons.One o','audiology-services__tinnitus-evaluation-support','rich_text','[{"_type":"block","_key":"b-xgv1q5da","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-xnd4mldu","text":"What Causes Tinnitus?","marks":[]}]},{"_type":"block","_key":"b-iyhqmu6f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-gyztlr08","text":"Tinnitus can develop or be triggered for many reasons.","marks":[]}]},{"_type":"block","_key":"b-r18glatb","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-nostfh74","text":"One of the most common causes is hearing loss.","marks":[]}]},{"_type":"block","_key":"b-0071hmfu","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-rn4ojm6o","text":"When the brain has issues receiving sound input from the ears, it may compensate by generating phantom sounds like ringing or buzzing.","marks":[]}]},{"_type":"block","_key":"b-yzr7touu","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-zhcwsnav","text":"Repeated exposure to loud noises can also damage the auditory system and lead to tinnitus.","marks":[]}]},{"_type":"block","_key":"b-971sb8oa","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-or9mbxug","text":"A blockage from excess earwax can also trigger tinnitus. When impacted earwax is pressed against the eardrum, a sensation of ringing or fullness in the ear may be experienced.","marks":[]}]},{"_type":"block","_key":"b-5cjdhuag","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6izuh2ir","text":"Underlying health issues such as TMJ dysfunction, high blood pressure, or ear infections may also trigger tinnitus.","marks":[]}]},{"_type":"block","_key":"b-88ie04hd","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e3d7bew7","text":"Ringing in the ears may also be a side-effect of certain medications.","marks":[]}]}]','','59f1e95',3);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__tinnitus-evaluation-support-block-004','audiology-services__tinnitus-evaluation-support-block-004','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Divider','audiology-services__tinnitus-evaluation-support','divider','[]','','860949d',4);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__tinnitus-evaluation-support-block-005','audiology-services__tinnitus-evaluation-support-block-005','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Tinnitus Evaluations in Lutz, FLAt JC Audiology, our audiologist or hearing aid ','audiology-services__tinnitus-evaluation-support','rich_text','[{"_type":"block","_key":"b-7muw60ek","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-y317izff","text":"Tinnitus Evaluations in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-q1sgpwpz","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-29yc5ra7","text":"At JC Audiology, our audiologist or hearing aid specialist will conduct a thorough assessment to help identify potential causes.","marks":[]}]},{"_type":"block","_key":"b-ac655hd0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9ipvjmjd","text":"During your tinnitus evaluation, we’ll begin by discussing your symptoms, asking you when the phantom sounds occur, how frequently they happen, and how they affect you and your daily life.","marks":[]}]},{"_type":"block","_key":"b-23e5esig","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b8q9nqj4","text":"A physical examination of your ears may also be performed. This is to check for possible wax buildup, blockages, perforations, or signs of infection.","marks":[]}]},{"_type":"block","_key":"b-yn3besk0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-h35mfoe8","text":"Since tinnitus is linked to hearing loss, hearing tests may also be performed to measure your ability to detect speech and tones.","marks":[]}]}]','','c793686',5);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('audiology-services__tinnitus-evaluation-support-block-006','audiology-services__tinnitus-evaluation-support-block-006','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Divider','audiology-services__tinnitus-evaluation-support','divider','[]','','f22a207',6);
