INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('custom-hearing-protection-block-001','custom-hearing-protection-block-001','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'JC Audiology provides custom hearing protection in Lutz, FL.At JC Audiology in L','custom-hearing-protection','rich_text','[{"_type":"block","_key":"b-rjv1nm9f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8j5dw0h1","text":"JC Audiology provides custom hearing protection in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-8fox4t7t","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-xn29uwcv","text":"At JC Audiology in Lutz, FL, we believe that protecting your hearing is just as important as treating hearing loss. Once hearing is damaged, it cannot be restored naturally. Taking the necessary steps to safeguard it now is an investment in your lifelong hearing health.","marks":[]}]},{"_type":"block","_key":"b-6oakr86q","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-lx7roijc","text":"Whether you spend your days around loud machinery, attend live concerts, enjoy hunting trips, swim regularly, or simply want a better night’s sleep, the right hearing protection can make a huge difference. Our experienced audiologist and hearing aid specialist work together to provide both custom-fit and ready-made hearing protection designed for your comfort, safety, and lifestyle needs. From soft sleep plugs to advanced digital shooting protection, we’ll help you choose the perfect solution.","marks":[]}]}]','','2edd671',1);
