efs":[],"children":[{"_type":"span","_key":"s-r4vg5umh","text":"Industrial & Construction Work: Durable custom plugs and earmuffs to protect against workplace noise.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-zyb21l08","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0zci77iy","text":"Surfing: Surf plugs shield your ears from wind and cold water to help prevent surfer’s ear.","marks":[]}],"listItem":"bullet","level":1}]','','15000f5',5);
