INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('hearing-aids-products-block-013','hearing-aids-products-block-013','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Assistive Listening Devices (ALDs)ALDs help you hear better in certain situation','hearing-aids-products','rich_text','[{"_type":"block","_key":"b-i68itxas","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-j0hyorkh","text":"Assistive Listening Devices (ALDs)","marks":[]}]},{"_type":"block","_key":"b-06tvw5ty","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1qfj2dag","text":"ALDs help you hear better in certain situations-like watching TV, going to a meeting, or talking on the phone. They work with or without hearing aids and make sound clearer by reducing background noise. Examples include:","marks":[]}]},{"_type":"block","_key":"b-8jpwfyo0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9q1iq11t","text":"TV Streamers: Send TV sound straight to your hearing aids","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-7yjyq63r","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ajtjfxbd","text":"FM Systems: Make a teacher’s or speaker’s voice clearer in class or meetings","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-47nduvef","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-sf827xni","text":"Personal Amplifiers: Handheld devices for one-on-one or small group chats","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-p9wvho1k","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-l9a9hmgc","text":"Hearing Loop Systems: Installed in public places and work with telecoil hearing aids","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-2qnle26q","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-aib9vkty","text":"Bluetooth Microphones: Clip-on mics that stream a person’s voice directly to your aids","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-f0izsc9u","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-5uxd4p60","text":"Frequently Asked Questions","marks":[]}]}]','','04e9d34',13);
