INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('hearing-aids-products-block-016','hearing-aids-products-block-016','published',NULL,NULL,'2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z','2026-05-20T20:45:00.350Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Hearing Aids and Custom Hearing Protection in Lutz, FLIf you need hearing aids, ','hearing-aids-products','rich_text','[{"_type":"block","_key":"b-z39s3idt","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-n5ngoa0k","text":"Hearing Aids and Custom Hearing Protection in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-77c6ts9g","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-gb7pl16y","text":"If you need hearing aids, custom ear protection, or help with your current devices, JC Audiology is here for you. We’ll help you choose the right solution so you can hear and live better every day.","marks":[]}]},{"_type":"block","_key":"b-zpi97gqv","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-gqtkekeq","text":"Call us today to schedule your appointment!","marks":[]}]}]','','de02051',16);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('hearing-aids-products__hearing-aid-alternatives-block-001','hearing-aids-products__hearing-aid-alternatives-block-001','published',NULL,NULL,'2026-05-20T20:45:00.351Z','2026-05-20T20:45:00.351Z','2026-05-20T20:45:00.351Z',NULL,NULL,1,NULL,NULL,'en',NULL,'JC Audiology offers assistive listening devices in Lutz, FL.At JC Audiology, we ','hearing-aids-products__hearing-aid-alternatives','rich_text','[{"_type":"block","_key":"b-pchz51mu","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-udqtmfgm","text":"JC Audiology offers assistive listening devices in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-29osswsg","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ddg6l6lb","text":"At JC Audiology, we understand that even the most advanced hearing aids sometimes need extra support. Even the most powerful hearing aids may still need an extra boost, especially in places with lots of background noise, long distances between you and the speaker, or challenging acoustics.","marks":[]}]},{"_type":"block","_key":"b-yxjfivnf","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-daywjc6v","text":"Whether you’re trying to follow a conversation in a busy restaurant, listen to a lecture, hear a sermon at church, or enjoy your favorite TV show at home, Assistive Listening Devices (ALDs) can make it easier to hear clearly and comfortably.","marks":[]}]},{"_type":"block","_key":"b-p8o2f9pv","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-pvf3hu24","text":"Our audiologist and hearing aid specialist work together to help you explore, choose, and use the right ALD for your lifestyle. These helpful tools can work alongside your hearing aids or be used on their own, giving you more confidence and comfort in your daily communication.","marks":[]}]}]','','79db5a4',1);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('hearing-aids-products__hearing-aid-alternatives-block-002','hearing-aids-products__hearing-aid-alternatives-block-002','published',NULL,NULL,'2026-05-20T20:45:00.351Z','2026-05-20T20:45:00.351Z','2026-05-20T20:45:00.351Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Divider','hearing-aids-products__hearing-aid-alternatives','divider','[]','','940efaf',2);
INSERT INTO "ec_service_content_blocks" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","service_slug","block_type","content","accordion_group_key","source_element_id","sort_order") VALUES('hearing-aids-products__hearing-aid-alternatives-block-003','hearing-aids-products__hearing-aid-alternatives-block-003','published',NULL,NULL,'2026-05-20T20:45:00.351Z','2026-05-20T20:45:00.351Z','2026-05-20T20:45:00.351Z',NULL,NULL,1,NULL,NULL,'en',NULL,'Why Use an Assistive Listening Device?Hearing aids are excellent for everyday si','hearing-aids-products__hearing-aid-alternatives','rich_text','[{"_type":"block","_key":"b-hnwwmlod","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-pnm87u3u","text":"Why Use an Assistive Listening Device?","marks":[]}]},{"_type":"block","_key":"b-ff0kpqy9","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-835g690m","text":"Hearing aids are excellent for everyday situations, but they may still face challenges in places like theaters, classrooms, houses of worship, or large gatherings. Meanwhile, ALDs are task-specific devices designed specifically to improve sound clarity in various listening environments. They can:","marks":[]}]},{"_type":"block","_key":"b-jkascrvq","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-nympxin9","text":"Enhance speech understanding in noisy spaces so you can follow conversations without guessing.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-0kmmctke","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-jtsgawxy","text":"Improve listening over distance, making it easier to hear a speaker from across a large room.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-ng6nw83r","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0jdsfw87","text":"Reduce background distractions, allowing you to focus on the sound you want to hear.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-qvx83agg","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ch42ogt6","text":"Make TV shows, phone calls, and public announcements clearer, so you can stay connected without strain.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-ofrj3ggj","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f8m5fnr0","text":"In a nutshell, ALDs help you enjoy activities and social events with less fatigue and more confidence.","marks":[]}]}]','','1c0873e',3);
