INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","route","meta_title","meta_description","body_content") VALUES('audiology-services','audiology-services','published',NULL,NULL,'2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z',NULL,NULL,1,NULL,NULL,NULL,NULL,'Audiology Services','/audiology-services/','Audiology Services','JC Audiology provides expert hearing care to help you stay connected to the sounds that matter most.','[{"_type":"block","_key":"ejhcz2qgz","style":"normal","children":[{"_type":"span","_key":"b1rp7v2zk","text":"JC Audiology provides expert hearing care to help you stay connected to the sounds that matter most."}]},{"_type":"block","_key":"pg0449i35","style":"normal","children":[{"_type":"span","_key":"yp2uax4gp","text":"From comprehensive hearing evaluations, hearing aid fittings, and excellent after-care services, our Lutz, FL, audiologists are here to support you with compassionate and personalized hearing care."}]},{"_type":"block","_key":"gwiafkig6","style":"h2","children":[{"_type":"span","_key":"ytkofijmo","text":"Audiology Services in Lutz, FL"}]},{"_type":"block","_key":"rmtuzld02","style":"h3","children":[{"_type":"span","_key":"7bfn4ngvu","text":"Hearing Evaluations"}]},{"_type":"block","_key":"2l69qsy4o","style":"normal","children":[{"_type":"span","_key":"wl7ng536s","text":"At JC Audiology, your journey to better hearing starts with a thorough hearing evaluation."}]},{"_type":"block","_key":"ugxxh6qqj","style":"normal","children":[{"_type":"span","_key":"phhgip8yt","text":"Our Lutz, FL audiologist and hearing aid specialist use safe, non-invasive tests to check how well you hear."}]},{"_type":"block","_key":"pgwdtvzci","style":"normal","children":[{"_type":"span","_key":"oxxrmp2fd","text":"Which hearing test is the best?","marks":["strong"]}]},{"_type":"block","_key":"zaamd2610","style":"normal","children":[{"_type":"span","_key":"dqt9cshbu","text":"The right hearing test depends on your needs or concerns. When needed, a comprehensive hearing evaluation may be performed. Below are some of the most common hearing tests:"}]},{"_type":"block","_key":"b37vfd2og","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"w6rax8ct9","text":"Pure-tone audiometry"}]},{"_type":"block","_key":"7er47m0ac","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"zxqak85n2","text":"Speech audiometry"}]},{"_type":"block","_key":"yajn2nkru","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"n351ly8ie","text":"Tympanometry"}]},{"_type":"block","_key":"sw3ctioun","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"b8h2mpyg5","text":"Auditory brainstem response (ABR)"}]},{"_type":"block","_key":"9sx51gzf0","style":"h4","children":[{"_type":"span","_key":"8ov09nf6u","text":"Can I test my own hearing?"}]},{"_type":"block","_key":"rt8rucgs2","style":"normal","children":[{"_type":"span","_key":"dohkil3sc","text":"You "},{"_type":"span","_key":"9qc1ppicd","text":"can","marks":["em"]},{"_type":"span","_key":"lag2p9o75","text":" test your own hearing through online hearing tests and apps that offer basic screening. However, these tests don’t replace the accuracy of a professional hearing test. Getting a professional hearing test from an audiologist is still the best option."}]},{"_type":"block","_key":"nff2icuzf","style":"h4","children":[{"_type":"span","_key":"8six5tqaf","text":"Are online hearing tests any good?"}]},{"_type":"block","_key":"nhuyzmlk3","style":"normal","children":[{"_type":"span","_key":"ow9p60sr3","text":"Again, online hearing tests can give you a general idea of how well you hear, but they cannot replace a full evaluation by an audiologist."}]},{"_type":"block","_key":"0p2d0oe1z","style":"normal","children":[{"_type":"span","_key":"l20ic3ea6","text":"Online hearing tests just check if you can hear tones through headphones or speakers. They can’t identify the exact type or cause of hearing loss, assess how clearly you understand speech, and detect underlying medical conditions that may be affecting your hearing."}]},{"_type":"block","_key":"jq4z4phk5","style":"normal","children":[{"_type":"span","_key":"2585rc60o","text":"At JC Audiology, we offer accurate, comprehensive testing to help you hear your best."}]},{"_type":"block","_key":"icjouaxhl","style":"h3","children":[{"_type":"span","_key":"kcqvw5ddo","text":"Tinnitus Evaluations and Treatment"}]},{"_type":"block","_key":"2bcmwc4we","style":"normal","children":[{"_type":"span","_key":"drxn17sba","text":"If you are hearing ringing, buzzing, or other disturbing sounds in your ears, you just might be dealing with tinnitus."}]},{"_type":"block","_key":"57lx06qqx","style":"normal","children":[{"_type":"span","_key":"bisjfot60","text":"At JC Audiology, we provide thorough evaluations to determine the cause of your tinnitus. We also offer personalized treatment plans to help reduce the symptoms and improve your overall quality of life."}]},{"_type":"block","_key":"awc2e4nvi","style":"h4","children":[{"_type":"span","_key":"x1q231697","text":"Should I go to an audiologist for tinnitus?"}]},{"_type":"block","_key":"wgsmk0zcz","style":"normal","children":[{"_type":"span","_key":"jfx1olbhl","text":"Yes! An audiologist is trained to evaluate and treat tinnitus. If you\"re hearing phantom sounds or the typical Sringing in the ears⬝, an audiologist at JC Audiology can perform a thorough examination to identify potential triggers and determine whether your tinnitus is connected to hearing loss."}]},{"_type":"block","_key":"pbf0qx0og","style":"normal","children":[{"_type":"span","_key":"4cpff4n05","text":"Based on the results, we may recommend helpful tools like sound therapy, hearing aids with built-in masking features, or relaxation techniques to address tinnitus symptoms. We’ll also teach you how to manage the daily effects of tinnitus on your focus, sleep, and emotional well-being. "}]},{"_type":"block","_key":"bdxpu1o5r","style":"h4","children":[{"_type":"span","_key":"v3hfu6kmy","text":"Is tinnitus a brain problem?"}]},{"_type":"block","_key":"x68ak56x0","style":"normal","children":[{"_type":"span","_key":"pdb223b7n","text":"While tinnitus often begins with the ears, it also involves the brain’s auditory system. When hearing loss or damage limits the sound input to the brain, the brain may compensate by creating its own sound. This is where tinnitus enters the scene."}]},{"_type":"block","_key":"pfce41ah2","style":"normal","children":[{"_type":"span","_key":"qfdbjp48d","text":"Many treatments for tinnitus are programmed to reduce the brain’s perception of that sound. Approaches like sound therapy, hearing aids, or cognitive behavioral therapy (CBT) help retrain your brain and reduce how noticeable the ringing or buzzing becomes."}]},{"_type":"block","_key":"dm55mphbg","style":"h4","children":[{"_type":"span","_key":"yqe54sup0","text":"What happens if tinnitus is not treated?"}]},{"_type":"block","_key":"p2bvivlz4","style":"normal","children":[{"_type":"span","_key":"w1wptkvmx","text":"Over time, untreated tinnitus may increase stress, anxiety, or frustration. Many people with tinnitus struggle to fall asleep or stay focused during the day."}]},{"_type":"block","_key":"3f75myjpi","style":"normal","children":[{"_type":"span","_key":"6uiz9xj4d","text":"If tinnitus is linked to untreated hearing loss, ignoring it can also lead to worsening hearing problems. By addressing tinnitus early, you can improve your comfort and prevent tinnitus from interfering with daily activities. Let our Lutz, FL audiologists guide you toward tinnitus relief!"}]},{"_type":"block","_key":"vcxuazjvy","style":"h2","children":[{"_type":"span","_key":"irgfuk760","text":"Hearing Aid Services"}]},{"_type":"block","_key":"1v1uffnwn","style":"normal","children":[{"_type":"span","_key":"88zhhglxq","text":"Our friendly and compassionate team from JC Audiology is with you every step of your hearing journey. From your first appointment to follow-up appointments, you can count on our unwavering expertise and care. We want you to enjoy the best performance from your hearing aids. We offer a wide selection of "},{"_type":"span","_key":"py6ltm0xw","text":"hearing aids in Lutz, FL","marks":["g74xd8jgc"]},{"_type":"span","_key":"omgn9sot9","text":"."}],"markDefs":[{"_type":"link","_key":"g74xd8jgc","href":"../index.html","blank":false}]},{"_type":"block","_key":"zvc5aucmz","style":"h3","children":[{"_type":"span","_key":"dxz0clc7q","text":"Hearing Aid Fittings","marks":["strong"]}]},{"_type":"block","_key":"0dzaape8e","style":"normal","children":[{"_type":"span","_key":"p01blb5cp","text":"Hearing aids, no matter how Ssmart⬝ they are designed to be, are not merely Splug and play⬝ devices. A proper fit is essential for comfort and better hearing. Our audiologists at JC Audiology tailor your hearing aids to your unique hearing profile. We understand that every hearing loss is unique, and we make sure that we perform real ear measurements to ensure each patient gets the best hearing improvement possible!"}]},{"_type":"block","_key":"d30tppqx0","style":"h4","children":[{"_type":"span","_key":"hbajnr9si","text":"How long does it take to get fitted for a hearing aid?"}]},{"_type":"block","_key":"jl5drrpsu","style":"normal","children":[{"_type":"span","_key":"zelhjd6eg","text":"The hearing aid fitting process typically takes about one to two hours. After completing a thorough hearing evaluation, our audiologist will discuss your results and recommend hearing aids that best fit your hearing needs, lifestyle, and preferences."}]},{"_type":"block","_key":"9psmteu2h","style":"normal","children":[{"_type":"span","_key":"dxdzq9jo3","text":"Once a hearing aid is chosen, an audiologist will program it with precise measurements (including real-ear measurements) to ensure optimal sound quality and performance."}]},{"_type":"block","_key":"wsugnlfhy","style":"normal","children":[{"_type":"span","_key":"9hq6sbdgk","text":"We will also show you how to properly insert, remove, and care for your new device, answering any questions you may have."}]},{"_type":"block","_key":"q8pp0cjil","style":"normal","children":[{"_type":"span","_key":"61yag29nh","text":"While the hearing aid fitting is usually completed in a single visit, follow-up appointments are expected. These follow-up appointments ensure comfort and are aimed to assist you in adjusting to amplified sounds over time."}]},{"_type":"block","_key":"4yb3ynhni","style":"h4","children":[{"_type":"span","_key":"hcb062luo","text":"How does an audiologist fit a hearing aid?"}]},{"_type":"block","_key":"ufdfan27u","style":"normal","children":[{"_type":"span","_key":"acg6xz60h","text":"The process of hearing aid fitting begins after a complete hearing evaluation. Based on the hearing test result, an audiologist will select the most appropriate hearing aid model and program it to meet your hearing profile."}]},{"_type":"block","_key":"tmxeot74e","style":"normal","children":[{"_type":"span","_key":"1ydf5yp9o","text":"During the fitting session, an audiologist will perform real-ear measurements to ensure the hearing aid provides the correct amplification for your ear canal’s acoustics. The audiologist will also adjust the physical fit of the device."}]},{"_type":"block","_key":"pywnwytmw","style":"normal","children":[{"_type":"span","_key":"vu2uheb3g","text":"When the right (and most comfortable) fit is achieved, you’ll be taught how to insert and remove the hearing aid, clean and maintain it. This will also be the perfect time to discuss any related apps or accessories."}]},{"_type":"block","_key":"no424dsme","style":"h4","children":[{"_type":"span","_key":"kos3exc09","text":"Can you get a hearing aid without a test?"}]},{"_type":"block","_key":"8qgevvvcv","style":"normal","children":[{"_type":"span","_key":"q48d3idli","text":"Yes, you can purchase over-the-counter (OTC) hearing aids without a hearing test. However, OTC hearing aids don’t offer the same personalized fitting or professional support as prescription hearing aids provided by an audiologist."}]},{"_type":"block","_key":"k6wy7ipqx","style":"normal","children":[{"_type":"span","_key":"0sqfwi948","text":"By having a professional hearing evaluation at JC Audiology, you’ll receive expert advice, a customized solution, and the ability to identify any underlying medical conditions that could affect your hearing."}]},{"_type":"block","_key":"9sptyr11c","style":"normal","children":[{"_type":"span","_key":"ram3gyr99","text":"If you’re uncertain about your hearing, starting with a comprehensive diagnostic test is the best way to ensure you get the right care."}]},{"_type":"block","_key":"2gbqsw0sy","style":"h3","children":[{"_type":"span","_key":"6u26mrrp9","text":"Hearing Aid Repair and Cleaning"}]},{"_type":"block","_key":"ex7ij7ih5","style":"normal","children":[{"_type":"span","_key":"yf7h84np4","text":"Are your hearing aids not working as they should? We can help! Our audiologist and hearing aid specialists are trained to evaluate hearing aid issues and perform minor repairs in-office."}]},{"_type":"block","_key":"gvvvion6l","style":"h4","children":[{"_type":"span","_key":"8b861kagr","text":"What are the common problems that require hearing aid repair?"}]},{"_type":"block","_key":"xc94o50lb","style":"normal","children":[{"_type":"span","_key":"3plqwof44","text":"Some common issues that may need repair include:"}]},{"_type":"block","_key":"sz1zhonfd","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"mdstf4ymp","text":"No sound or low volume"}]},{"_type":"block","_key":"8hkct64ak","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"xvy32qnxp","text":"Distorted or fuzzy sound"}]},{"_type":"block","_key":"gfti0jnw2","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"4y7zbvz59","text":"Feedback or whistling"}]},{"_type":"block","_key":"1f17e19e6","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ivk83lnx7","text":"Visible damage"}]},{"_type":"block","_key":"ac5q0rd3f","style":"h4","children":[{"_type":"span","_key":"g46duhspe","text":"How long does it take to repair a hearing aid?"}]},{"_type":"block","_key":"1ql53v2v1","style":"normal","children":[{"_type":"span","_key":"q6cm6s56c","text":"The turnaround time for hearing aid repair depends on the issue. Minor fixes, such as replacing wax guards or cleaning tubing, can be completed in-house within a few minutes."}]},{"_type":"block","_key":"yk9uxyovx","style":"normal","children":[{"_type":"span","_key":"7n2bp51bv","text":"However, if your device has bigger issues that need manufacturer service, repairs might take several days to two weeks. "}]},{"_type":"block","_key":"02g5e276f","style":"h4","children":[{"_type":"span","_key":"1sxd9dkls","text":"Can I fix my hearing aid at home?"}]},{"_type":"block","_key":"q4tupu37d","style":"normal","children":[{"_type":"span","_key":"tn26do9wf","text":"Technically, yes, you can fix some minor hearing aid issues at home. However, more complex device issues should be handled by a professional."}]},{"_type":"block","_key":"iu2h6fov5","style":"normal","children":[{"_type":"span","_key":"mekrr3tif","text":"If your hearing aid isn’t working properly, you can run basic troubleshooting. Most manufacturers also provide troubleshooting guides in their user manuals or apps."}]},{"_type":"block","_key":"uibs7596s","style":"normal","children":[{"_type":"span","_key":"ygficwzm9","text":"If your hearing device still isn’t working even after troubleshooting, it would be best to contact your audiologist or hearing aid provider."}]},{"_type":"block","_key":"4jyh31i8m","style":"h3","children":[{"_type":"span","_key":"urf4r8j4q","text":"Hearing Protection"}]},{"_type":"block","_key":"h0g1pby5z","style":"normal","children":[{"_type":"span","_key":"py283rqos","text":"Noise can sneak up on your ears and cause lasting damage. At JC Audiology, we provide a wide selection of hearing protection. Whether it’s for music, water activities, work, or recreation, hearing protection help you enjoy life while keeping your hearing healthy."}]},{"_type":"block","_key":"t5abtiuog","style":"h4","children":[{"_type":"span","_key":"h1uxndvwm","text":"Why should I use hearing protection?"}]},{"_type":"block","_key":"9v0hoascn","style":"normal","children":[{"_type":"span","_key":"ydpyqk13y","text":"Exposure to loud sounds can permanently damage your hearing. Wearing proper protection reduces your risk of damage and helps you maintain your hearing health for the long run."}]},{"_type":"block","_key":"pxrvejtfy","style":"h4","children":[{"_type":"span","_key":"g0h822s9y","text":"Are custom earplugs better than store-bought ones?"}]},{"_type":"block","_key":"ke8biaty8","style":"normal","children":[{"_type":"span","_key":"up6tkkkwd","text":"Yes. Custom earplugs are made to fit the unique ear shape so they provide a more secure and comfortable fit compared to generic options. The snug fit also helps block out noise or water more effectively."}]},{"_type":"block","_key":"nquaoi8ry","style":"normal","children":[{"_type":"span","_key":"ax76mq9kd","text":"Another benefit of custom earplugs is the opportunity for customization. If you want reliable performance, comfort, and long-term value, custom earplugs are worth the investment."}]},{"_type":"block","_key":"fi2nofnw3","style":"normal","children":[{"_type":"span","_key":"8k62mtwim","text":"Our Lutz, FL audiologist and hearing aid specialist can help you choose the right type and ensure the perfect fit."}]},{"_type":"block","_key":"wgsr0dsmi","style":"h4","children":[{"_type":"span","_key":"ohog9vu7z","text":"Can I still hear people talking with earplugs in?"}]},{"_type":"block","_key":"paeunyy99","style":"normal","children":[{"_type":"span","_key":"6y1zwozzg","text":"Yes, many custom earplugs are smartly designed to reduce loud background noise while still letting speech remain clear. They’re a great choice for musicians or anyone who needs to protect their hearing without losing the ability to communicate."}]}]');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","route","meta_title","meta_description","body_content") VALUES('audiology-services__hearing-aid-fittings','audiology-services__hearing-aid-fittings','published',NULL,NULL,'2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z',NULL,NULL,1,NULL,NULL,NULL,NULL,'Hearing Aid Fittings','/audiology-services/hearing-aid-fittings/','Hearing Aid Fittings','Experience precise hearing aid fittings for comfort and performance. Schedule your personalized fitting with our certified audiologists today.','[{"_type":"block","_key":"b-07cbcab0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0353b579","text":"JC Audiology provides expert hearing aid fittings in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-fd4c0876","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-96a9d577","text":"Hearing aids are not just designed to make sounds louder. They actually need to be carefully set up by an audiologist or hearing aid specialist to match your own hearing. A professional hearing aid fitting helps you hear clearly and naturally.","marks":[]}]},{"_type":"block","_key":"b-9f8e20c6","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a5bd22c4","text":"At JC Audiology, our skilled audiologist uses the latest tools to adjust your hearing aids so they feel comfortable and sound great for your specific hearing needs.","marks":[]}]},{"_type":"block","_key":"b-26099110","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-52d342ef","text":"Why a Professional Hearing Aid Fitting Important","marks":[]}]},{"_type":"block","_key":"b-a52ed992","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-bbe6870e","text":"A good fitting helps you hear better in many everyday situations. When hearing aids are properly adjusted, you can understand speech more clearly, background noise is easier to ignore, and sounds feel natural.","marks":[]}]},{"_type":"block","_key":"b-9c2a2cab","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-74bc3c05","text":"Our audiologists at JC Audiology make sure your hearing aids work the best they can for you.","marks":[]}]},{"_type":"block","_key":"b-2ca7c810","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-370f2930","text":"Why Should an Audiologist Fit Your Hearing Aids","marks":[]}]},{"_type":"block","_key":"b-e8b0a852","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-4d19b837","text":"Audiologists are experts in hearing health. They know how to set up your hearing aids just right. If hearing aids aren’t fitted properly, they might feel uncomfortable or sound strange.","marks":[]}]},{"_type":"block","_key":"b-b6e85b8e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-5515f731","text":"At JC Audiology, we make sure your hearing aids fit your ears perfectly and feel good all day long.","marks":[]}]},{"_type":"block","_key":"b-6e3d5854","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-82913f05","text":"What Happens During a Hearing Aid Fitting","marks":[]}]},{"_type":"block","_key":"b-d99e5243","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ccd58f61","text":"During your appointment, the audiologist will review your hearing test results and explain how hearing aids can help you. You’ll pick a hearing aid that fits your needs and lifestyle.","marks":[]}]},{"_type":"block","_key":"b-ad7c8809","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8f833e86","text":"Your hearing aids will then be programmed using special software to match your hearing loss. We’ll use a test called Real Ear Measurement (REM), where a tiny microphone is placed in your ear to check that your hearing aids are giving the right amount of sound.","marks":[]}]},{"_type":"block","_key":"b-bbf044c2","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8b26ff57","text":"You’ll also learn how to put in, take out, clean, and care for your hearing aids. Follow-up visits will be scheduled to adjust your hearing aids based on how they work for you in everyday life.","marks":[]}]},{"_type":"block","_key":"b-40ea85e5","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-e7cce6c0","text":"What to Expect After Your First Fitting","marks":[]}]},{"_type":"block","_key":"b-21265021","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-092c026a","text":"Your first fitting is an important step, but it takes time to get used to hearing aids. You might notice sounds you haven’t heard in a while (like footsteps or clocks ticking) and your own voice may sound different. This is normal, and your brain will get used to it over time.","marks":[]}]},{"_type":"block","_key":"b-77a396a3","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a1e3c3d7","text":"We’ll support you through this process and make any needed adjustments to help you feel comfortable and confident.","marks":[]}]},{"_type":"block","_key":"b-7207ae44","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-e1c9b2fc","text":"What Is Real Ear Measurement (REM)","marks":[]}]},{"_type":"block","_key":"b-23c0ed28","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1f9cdc58","text":"REM is a special test that checks how your hearing aids deliver sound inside your ear. A tiny microphone is placed in your ear canal to measure the sound levels.","marks":[]}]},{"_type":"block","_key":"b-aab2527c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2ce85806","text":"This helps your audiologist fine-tune your hearing aids so they fit your ear perfectly and give you the best sound quality.","marks":[]}]},{"_type":"block","_key":"b-4c0c9d98","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-531efc24","text":"Why Real Ear Measurement Matters","marks":[]}]},{"_type":"block","_key":"b-5a7c5530","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a53281fa","text":"Everyone’s ears are different. REM makes sure your hearing aids match your ear’s unique shape and hearing needs. This means clearer speech, better comfort, and happier hearing.","marks":[]}]},{"_type":"block","_key":"b-62208fcb","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-da99c77e","text":"At JC Audiology, we always include REM as part of your fitting to help you get the most from your hearing aids.","marks":[]}]},{"_type":"block","_key":"b-3713bb13","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-8de1f350","text":"Adjusting to Hearing Aids","marks":[]}]},{"_type":"block","_key":"b-d8c7ffc3","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b6395586","text":"When you start wearing hearing aids, your brain needs time to adjust. It’s perfectly normal if you feel that sounds might seem louder or some things or voices might sound strange.","marks":[]}]},{"_type":"block","_key":"b-ed9f3208","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-37a8377b","text":"Tips to Help You Adjust:","marks":["strong"]}]},{"_type":"block","_key":"b-4e3bea33","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-d889a1d7","text":"Wear your hearing aids for a few hours each day at first, then slowly wear them longer.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-6ee0e7f3","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-60a32170","text":"Start in quiet places before trying louder environments.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-7a63f30a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-4b7e25ee","text":"Be patient. Getting used to hearing aids can take a few weeks.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-269e2370","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e49acf41","text":"Regular use and support from your audiologist will help you get the best results.","marks":[]}]},{"_type":"block","_key":"b-25dee82b","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-a74db87c","text":"Why Follow-Up Visits Are Important","marks":[]}]},{"_type":"block","_key":"b-ddd48fdf","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c9767180","text":"After your first fitting, follow-up visits help us make changes based on your experience. We adjust your hearing aids to make sure they fit well and sound great in your daily life.","marks":[]}]},{"_type":"block","_key":"b-e2b76f21","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-32b8cc88","text":"Hearing Aid Fitting FAQs","marks":[]}]},{"_type":"block","_key":"b-b9413917","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-43cb86ed","text":"Are hearing aid fittings covered by insurance?","marks":[]}]},{"_type":"block","_key":"b-81a38d8e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e253413d","text":"It depends on your plan. Medicare usually does not cover hearing aids, but some private insurance or veterans’ benefits might. Check with your provider for details.","marks":[]}]},{"_type":"block","_key":"b-5a480087","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-e9c13ff6","text":"How can I make my hearing aids more comfortable?","marks":[]}]},{"_type":"block","_key":"b-85413d88","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-7b896da6","text":"If your hearing aids feel uncomfortable, tell your audiologist. We can adjust the fit, try different ear tips, or make custom molds to help.","marks":[]}]},{"_type":"block","_key":"b-d9193bb1","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-a8937649","text":"How long does a hearing aid fitting take?","marks":[]}]},{"_type":"block","_key":"b-b67fa683","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-fe6a76ea","text":"The first fitting usually takes about an hour. You’ll likely need a few follow-up visits to fine-tune the fit and settings.","marks":[]}]},{"_type":"block","_key":"b-3543b277","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-deb86906","text":"Schedule Your Hearing Aid Fitting in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-810a734a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-383c2a35","text":"Our goal at JC Audiology is to help you hear your best with hearing aids that fit well, feel comfortable, and work great for you.","marks":[]}]},{"_type":"block","_key":"b-0357abdb","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b562584c","text":"Call us today to book your hearing aid fitting in Lutz, FL!","marks":[]}]}]');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","route","meta_title","meta_description","body_content") VALUES('audiology-services__hearing-aid-services','audiology-services__hearing-aid-services','published',NULL,NULL,'2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z',NULL,NULL,1,NULL,NULL,NULL,NULL,'Hearing Aid Services','/audiology-services/hearing-aid-services/','Hearing Aid Services','Get expert hearing aid services including adjustments, repairs, and maintenance. Keep your devices performing their best and book service today.','[{"_type":"block","_key":"b-a2a4c5e0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f16674bb","text":"JC Audiology provides expert hearing aid services in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-b5f25355","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-38623b9b","text":"Hearing loss isn’t always obvious. It can sneak up on you like a quiet whisper you can’t quite catch. If you find yourself struggling to hear in noisy places, constantly cranking up the volume on the TV, or missing out on conversations, our audiologist and hearing aid specialists in Lutz, FL are to help!","marks":[]}]},{"_type":"block","_key":"b-165de909","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3eeda357","text":"At JC Audiology, we offer more than just hearing aids.","marks":[]}]},{"_type":"block","_key":"b-cc2c39bf","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e103b6bb","text":"We are committed to offering personalized care and support. We want to help you hear better and live better.","marks":[]}]},{"_type":"block","_key":"b-d0837790","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0391e084","text":"Our team of expert audiologists in Lutz, FL, is dedicated to making sure you choose the right hearing solution so that you ","marks":[]},{"_type":"span","_key":"s-f546a898","text":"hear for life!","marks":["em"]}]},{"_type":"block","_key":"b-7ec9c252","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-645d31ef","text":"Whether it’s your first time to use hearing aids or looking to improve your current experience, we’ll guide you through every step of the process.","marks":[]}]},{"_type":"block","_key":"b-fb638301","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-04e0cb7c","text":"Why Choose Professional Hearing Aid Services?","marks":[]}]},{"_type":"block","_key":"b-a47850f4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ff693886","text":"When you choose professional hearing aid services, you’re not just buying a device; you’re getting a partner in your hearing journey.","marks":[]}]},{"_type":"block","_key":"b-0f306dc7","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-db611b4f","text":"Our audiologist and hearing aid specialist at JC Audiology don’t just hand you a hearing aid. We create a custom solution based on your hearing profile, lifestyle, budget, and preferences.","marks":[]}]},{"_type":"block","_key":"b-28052a43","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-5d2a3aa9","text":"Hearing Aid Selection","marks":[]}]},{"_type":"block","_key":"b-2522c5bf","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-4f2e60cf","text":"Finding the best hearing aid is not as easy as picking out groceries. It’s about working with an audiologist or hearing aid specialist who will take into account your hearing profile and hearing concerns.","marks":[]}]},{"_type":"block","_key":"b-f0d42604","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8815e15e","text":"At JC Audiology, it’s all about what works for you.","marks":[]}]},{"_type":"block","_key":"b-a80ed9e5","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-182ab441","text":"Our team will recommend hearing aids based on your hearing loss, daily activities, and budget.","marks":[]}]},{"_type":"block","_key":"b-9c3df5e7","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-31b50ba5","text":"Hearing Test: Where It All Begins","marks":[]}]},{"_type":"block","_key":"b-6423e0a9","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c50c9201","text":"Better hearing begins with a comprehensive hearing evaluation. Our tests include:","marks":[]}]},{"_type":"block","_key":"b-10d46b09","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1846fb12","text":"Pure-Tone Audiometry","marks":["strong"]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-dfedb878","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-079620eb","text":"Speech Audiometry","marks":["strong"]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-12b9bf37","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-17184060","text":"Tympanometry","marks":["strong"]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-099ec1a1","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-3b202bed","text":"Hearing Aid Styles We Offer","marks":[]}]},{"_type":"block","_key":"b-d0bc8e59","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6b8fbf10","text":"Completely-in-the-Canal (CIC)","marks":["strong"]},{"_type":"span","_key":"s-19e8f4f5","text":": Tiny and nearly invisible, perfect for mild to moderate hearing loss.","marks":[]}]},{"_type":"block","_key":"b-0ac944b8","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-18a2777a","text":"Receiver-in-the-Canal (RIC)","marks":["strong"]},{"_type":"span","_key":"s-e3c6b0bd","text":": Small and discreet, offering clear sound for mild to severe hearing loss.","marks":[]}]},{"_type":"block","_key":"b-127483ed","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c9186d9a","text":"In-the-Canal (ITC)","marks":["strong"]},{"_type":"span","_key":"s-ea4af5d3","text":": Slightly larger, with more features but still discreet.","marks":[]}]},{"_type":"block","_key":"b-3ca6ad62","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8f00d888","text":"In-the-Ear (ITE)","marks":["strong"]},{"_type":"span","_key":"s-21a9cb57","text":": Easy to handle, fitting inside the outer ear.","marks":[]}]},{"_type":"block","_key":"b-97b1cbb4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8db9dfa4","text":"Behind-the-Ear (BTE)","marks":["strong"]},{"_type":"span","_key":"s-80f475fd","text":": Powerful, flexible, and great for most types of hearing loss.","marks":[]}]},{"_type":"block","_key":"b-599a6303","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-27af6789","text":"Precise Fitting, Programming and Adjustments","marks":[]}]},{"_type":"block","_key":"b-06d42726","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9b2dd6d3","text":"Once you’ve chosen your hearing aids, we will make sure that enjoy a secure and comfortable fit. During hearing aid fitting, we want to ensure that you experience zero feedback, whistling, and discomfort. Our aim is to give you the best hearing improvement possible!","marks":[]}]},{"_type":"block","_key":"b-5fdae6e2","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-69f21398","text":"Your journey with us doesn’t end when you step out of our clinic. We understand that hearing needs change over time, and so do your listening environments.","marks":[]}]},{"_type":"block","_key":"b-b7bee493","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-39f69ec1","text":"Our audiologist and hearing aid specialist will adjust and fine-tune your hearing aids whenever needed.","marks":[]}]},{"_type":"block","_key":"b-3f2d11a4","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-7d6f2707","text":"Education & Support","marks":[]}]},{"_type":"block","_key":"b-0b1bd663","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-d9df97aa","text":"Done with hearing aid fitting? Our care for you doesn’t end there! We’re here to make sure you succeed with your hearing aids.","marks":[]}]},{"_type":"block","_key":"b-ebfff93d","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-35e4f12a","text":"We’ll teach you how to insert and remove your devices, how to change or charge your batteries, and how to clean your hearing aids properly. We’ll also share with you communication strategies so you can enjoy and be fully confident with your new hearing aids.","marks":[]}]},{"_type":"block","_key":"b-1753b675","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-9852f9a5","text":"Real Ear Measurements","marks":[]}]},{"_type":"block","_key":"b-b6fa9a65","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e23fdd3d","text":"Each ear is unique and has its own shape. Real Ear Measurements (REM) ensure your hearing aids deliver the best possible sound for your unique ear. A small microphone is placed in your ear canal to ensure the devices are amplifying sound properly for your ear’s individual acoustics.","marks":[]}]},{"_type":"block","_key":"b-ead72f78","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-d2aa7aad","text":"It’s all about making sure your hearing aids are just right.","marks":[]}]},{"_type":"block","_key":"b-25bbd350","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-2698dcac","text":"Hearing Aid Repairs and Maintenance","marks":[]}]},{"_type":"block","_key":"b-7149e866","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-4f3dc4ac","text":"Hearing aids need a little TLC from time to time. At JC Audiology, we offer quick repairs and maintenance to keep your devices working like new.","marks":[]}]},{"_type":"block","_key":"b-f55067c4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a90dda2c","text":"We handle most repairs in-house, and if your hearing aids need more advanced attention, we’ll coordinate with the manufacturer on your behalf. And even if you didn’t buy your hearing aids from us, we’re still happy to service them.","marks":[]}]},{"_type":"block","_key":"b-1a883a9b","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-1323da21","text":"Hearing Aid Services in Lutz, FL","marks":["strong"]}]},{"_type":"block","_key":"b-5939a8bf","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-07ebb91e","text":"At JC Audiology, we’re passionate about helping you hear better and live better. Giving you the opportunity to hear for life is our goal!","marks":[]}]},{"_type":"block","_key":"b-53e0155f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b93411dd","text":"From your first visit to hearing aid adjustments, we’re here for you. Trust us to be your source of expert advice, personalized care, and high-quality hearing solutions in Lutz, FL and nearby communities.","marks":[]}]},{"_type":"block","_key":"b-fed2ca7b","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-02449efb","text":"Ready to hear the world more clearly? Give us a call today to schedule your consultation!","marks":[]}]}]');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","route","meta_title","meta_description","body_content") VALUES('audiology-services__hearing-tests','audiology-services__hearing-tests','published',NULL,NULL,'2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z',NULL,NULL,1,NULL,NULL,NULL,NULL,'Hearing Tests','/audiology-services/hearing-tests/','Hearing Tests','Discover comprehensive hearing tests to assess your hearing health. Learn what to expect and schedule your hearing evaluation with us today.','[{"_type":"block","_key":"b-4e312937","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c7025a71","text":"JC Audiology provides comprehensive hearing tests in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-7bb76ab4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-feeed28e","text":"Hearing tests help us get a bigger and clearer picture of one’s hearing health. Through hearing tests, audiologists and hearing aid specialists can spot or confirm any issues that might be affecting your communication.","marks":[]}]},{"_type":"block","_key":"b-2d94922c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-24d4ec99","text":"At JC Audiology, we use advanced diagnostic tools to assess your hearing and provide personalized solutions.","marks":[]}]},{"_type":"block","_key":"b-7a70ebd1","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b95662d3","text":"Our expert audiologist and hearing aid specialist in Lutz, FL, is committed to guiding you through every stage of your hearing health journey.","marks":[]}]},{"_type":"block","_key":"b-26094e77","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9239f8a6","text":"Let’s help you achieve hearing with comfort and clarity!","marks":[]}]},{"_type":"block","_key":"b-c4a2f328","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-16c8641c","text":"When Should You Get Your Hearing Tested?","marks":[]}]},{"_type":"block","_key":"b-680be040","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1ac95eb3","text":"If you recently noticed changes in your hearing, it’s time for a test.","marks":[]}]},{"_type":"block","_key":"b-bf264104","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-92f15cf0","text":"Hearing loss often happens gradually, so early signs can be easy to miss.","marks":[]}]},{"_type":"block","_key":"b-2d5e22b5","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1ead1e8f","text":"You might find it tough to follow speech in noisy places. You may find yourself asking people more often to repeat themselves. Or you may feel like everyone is mumbling or eating their words.","marks":[]}]},{"_type":"block","_key":"b-bb2f77ce","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b8309efc","text":"This is where hearing tests come in. Getting your hearing tested by an audiologist or hearing aid specialist ensures an accurate diagnosis.","marks":[]}]},{"_type":"block","_key":"b-d1767251","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-d6425f6c","text":"JC Audiology provides hearing tests in Lutz, FL.","marks":[]}]},{"_type":"block","_key":"b-c4166569","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-6cc41a93","text":"Hearing Tests We Offer at JC Audiology","marks":[]}]},{"_type":"block","_key":"b-47053c52","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-aa59395d","text":"We provide a full range of hearing tests to get a clear picture of your hearing health. Some of our commonly performed hearing tests include:","marks":[]}]},{"_type":"block","_key":"b-4b3d44ef","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-95c35ab3","text":"Pure-Tone Audiometry","marks":["strong"]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-8ee08734","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-52bba1d5","text":"Speech Audiometry","marks":["strong"]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-a1063969","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ab440975","text":"Tympanometry","marks":["strong"]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-1f88c0bb","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-b6f3eaf9","text":"What to Expect During Your Hearing Test","marks":[]}]},{"_type":"block","_key":"b-f9185f77","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f73a6664","text":"Our comprehensive hearing tests in Tampa include a quick, non-invasive exam and a full set of listening checks that usually take 30–45 minutes.","marks":[]}]},{"_type":"block","_key":"b-895a49f0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-5d20174c","text":"We’ll start by reviewing your medical history, your hearing concerns, and the situations where you notice trouble, so we have a clear baseline for your overall hearing health.","marks":[]}]},{"_type":"block","_key":"b-fc2a08f1","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f72bd848","text":"Next, we’ll examine your ears for issues like earwax buildup or signs of infection.","marks":[]}]},{"_type":"block","_key":"b-ec0597e9","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-97a61fd1","text":"During the test itself, you’ll listen through headphones to tones and speech at different pitches and volumes, and you’ll respond each time you hear them. Afterward, we’ll explain your results and review the next steps, if any are needed.","marks":[]}]},{"_type":"block","_key":"b-dcafdb70","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-725b99a5","text":"Your Hearing Test Results","marks":[]}]},{"_type":"block","_key":"b-d4431a14","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ea293b37","text":"After testing, an audiologist or hearing aid specialist will explain your results using an audiogram.","marks":[]}]},{"_type":"block","_key":"b-6d25ce61","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a1d6b945","text":"If hearing loss is detected, we’ll discuss treatment options. These may include hearing aids, sound therapy, cochlear implants, assistive listening devices, or medical referrals.","marks":[]}]},{"_type":"block","_key":"b-15606ac1","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c35c17e1","text":"At JC Audiology, our goal is to help you hear more clearly and enjoy better communication every day.","marks":[]}]},{"_type":"block","_key":"b-c61e9014","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-24a2f7e5","text":"Frequently Asked Questions About Hearing Tests","marks":[]}]},{"_type":"block","_key":"b-065901a1","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-eae94c16","text":"Can I test my own hearing?","marks":[]}]},{"_type":"block","_key":"b-c599afde","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e84c9acd","text":"Online screenings are available but can’t replace the accuracy of a professional hearing test.","marks":[]}]},{"_type":"block","_key":"b-dbc69f62","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-4416330a","text":"Are hearing tests safe?","marks":[]}]},{"_type":"block","_key":"b-a46dc757","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0dd224b3","text":"Yes! They’re completely safe, painless, and non-invasive.","marks":[]}]},{"_type":"block","_key":"b-9b555d34","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-634175f5","text":"Are online hearing tests reliable?","marks":[]}]},{"_type":"block","_key":"b-45318a72","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-687a73f7","text":"Online hearing tests or apps may provide a general idea of your hearing. But there’s a catch – these online tests lack the detailed accuracy of an audiologist’s evaluation.","marks":[]}]},{"_type":"block","_key":"b-74fc60e7","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-922b4251","text":"All testing at JC Audiology is done in a state of the art sound treated room that is calibrated and continually certified, and provides the most optimal hearing test accuracy possible.","marks":[]}]},{"_type":"block","_key":"b-8572e62e","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-b701dc10","text":"Can I take a hearing test on my phone?","marks":[]}]},{"_type":"block","_key":"b-0b8660f3","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-cae7d80c","text":"Some apps offer basic screenings, but they cannot diagnose hearing loss or its causes like a professional can.","marks":[]},{"_type":"span","_key":"s-765b6f07","text":"All testing at JC Audiology is done in a state of the art sound treated room that is calibrated and continually certified, and provides the most optimal hearing test accuracy possible.","marks":[]}]},{"_type":"block","_key":"b-0c85d381","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-a6942832","text":"How often should I get a hearing test?","marks":[]}]},{"_type":"block","_key":"b-0fc1860d","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c17b2443","text":"If your hearing is normal, every 3 to 5 years is enough. If you have hearing loss, use hearing aids, or face frequent noise exposure, yearly testing is recommended.","marks":[]}]},{"_type":"block","_key":"b-57651c08","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-4e8b898d","text":"Schedule Your Hearing Test in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-d1ccff4c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b5f86ca6","text":"Getting your hearing tested is the first step to better hearing.","marks":[]}]},{"_type":"block","_key":"b-98449ae7","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b9031e38","text":"Let our experienced audiologist and hearing aid specialist help you understand your hearing!","marks":[]}]},{"_type":"block","_key":"b-fc2ccf63","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3c1080fb","text":"Call us today to book your hearing test in Lutz, FL!","marks":[]}]}]');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","route","meta_title","meta_description","body_content") VALUES('audiology-services__real-ear-measurement','audiology-services__real-ear-measurement','published',NULL,NULL,'2026-05-21T06:06:26.428Z','2026-05-21T06:32:31.573Z','2026-05-21T06:06:26.428Z',NULL,NULL,8,'01KS4JT4KF2F1HFAA4RKG3SX95',NULL,NULL,NULL,'Real Ear Measurement','/audiology-services/real-ear-measurement/','Real Ear Measurement','JC Audiology provides real ear measurements as part of hearing aid fitting best practices in Lutz, FL.','[{"_type":"block","_key":"buhy4b6rj","style":"normal","children":[{"_type":"span","_key":"ocdrca1ua","text":"JC Audiology provides real ear measurements as part of hearing aid fitting best practices in Lutz, FL.","marks":["strong","em"]}]},{"_type":"block","_key":"be84k2ztm","style":"normal","children":[{"_type":"span","_key":"9agyzx8he","text":"Real Ear Measurement, or REM, is one of the most important steps in making sure your hearing aids give you the clearest and most comfortable sound possible."}]},{"_type":"block","_key":"pymfgbmq9","style":"normal","children":[{"_type":"span","_key":"gz6na0oa0","text":"Everyone’s ears are shaped differently. Some are narrow, some are wider, and some have twists and turns. Because of these differences, sound travels through each person’s ear in a unique way."}]},{"_type":"block","_key":"dhnp063n7","style":"normal","children":[{"_type":"span","_key":"kka6ez435","text":"At JC Audiology, our audiologists and hearing aid specialists use REM to see exactly how sound behaves inside your ear canal. Once we have this information, we can adjust your hearing aids so they match your exact hearing needs. This means you can hear speech more clearly, enjoy everyday sounds, and listen more comfortably in noisy places."}]},{"_type":"block","_key":"0anezy5yo","style":"h2","children":[{"_type":"span","_key":"8ld62kyqr","text":"Why Is REM Important?"}]},{"_type":"block","_key":"aode7ypfb","style":"normal","children":[{"_type":"span","_key":"djfbd8d78","text":"REM is often called the gold standard for hearing aid fittings because it makes the process much more accurate than using factory settings or “best guess” adjustments."}]},{"_type":"block","_key":"xffoyo8v8","style":"normal","children":[{"_type":"span","_key":"be243p6gc","text":"Without REM, your hearing aids might be too loud, too soft, or not give you the clarity you need in conversations. This can lead to frustration, listening fatigue, or the feeling that your hearing aids just aren’t working as well as they should."}]},{"_type":"block","_key":"hegpj9ssh","style":"h3","children":[{"_type":"span","_key":"cqj0h17yi","text":"How Does Real Ear Measurement Work?"}]},{"_type":"block","_key":"xdlvzqij1","style":"normal","children":[{"_type":"span","_key":"9dm2ofrbe","text":"The process is simple and comfortable. First, the audiologist or hearing aid specialist will gently place a very thin probe microphone in your ear canal. This is done while you are wearing your hearing aid. The microphone sits close to your eardrum but does not touch it, so you should not feel any pain."}]},{"_type":"block","_key":"8ok1uigzp","style":"normal","children":[{"_type":"span","_key":"1ep0rwwyk","text":"Next, a speaker nearby plays different test sounds. The microphone measures how these sounds behave inside your ear canal. This gives us a real ear response, which is like a fingerprint of your ear’s unique acoustics."}]},{"_type":"block","_key":"4sqtjpheu","style":"normal","children":[{"_type":"span","_key":"g8v1k5d5b","text":"We then compare these measurements to your ideal hearing levels, based on your hearing test results. If your hearing aids are not delivering the right amount of amplification, we make changes on the spot. You can hear the difference instantly."}]},{"_type":"block","_key":"ram9735c1","style":"normal","children":[{"_type":"span","_key":"rhh3dmkbg","text":"Once everything sounds balanced, we verify the results one last time to ensure accuracy."}]},{"_type":"block","_key":"tso0veynu","style":"h2","children":[{"_type":"span","_key":"yplfdxxv9","text":"Why Real Ear Measurement Is Better Than Automatic Programming"}]},{"_type":"block","_key":"ehy00xav7","style":"normal","children":[{"_type":"span","_key":"j03bccfdp","text":"Most hearing aids today come with automatic programming, also known as first fit.This refers to preset settings of hearing devices. These settings don’t factor in the exact shape and size of your ears."}]},{"_type":"block","_key":"ws7lvich7","style":"normal","children":[{"_type":"span","_key":"og6rg3t94","text":"Think of it as buying shoes in your size without actually trying them on. They might fit okay, but they won’t give a perfect fit!"}]},{"_type":"block","_key":"6y4oa3049","style":"normal","children":[{"_type":"span","_key":"dd2ubu609","text":"REM, on the other hand, is like having your shoes custom-fitted. It measures sound in your ears, not in a test box or computer simulation. By making adjustments based on these real measurements, we can improve your sound quality, comfort, and ability to follow conversations."}]},{"_type":"block","_key":"ys85veelm","style":"h2","children":[{"_type":"span","_key":"tbimhbszx","text":"Hearing Aid Fitting in Lutz, FL"}]},{"_type":"block","_key":"u6j0yhkbs","style":"normal","children":[{"_type":"span","_key":"2taan6qn9","text":"At JC Audiology, we believe every hearing aid fitting should include Real Ear Measurement."}]},{"_type":"block","_key":"6z6pk56rg","style":"normal","children":[{"_type":"span","_key":"zzadpp6z4","text":"Whether you are getting your first pair of hearing aids or replacing older ones, this process helps you get the most from your investment in better hearing."}]},{"_type":"block","_key":"qnadtnfkl","style":"normal","children":[{"_type":"span","_key":"yfhy96j5a","text":"Our audiologist and hearing aid specialist are trained to make precise adjustments using REM so that your devices match your unique hearing needs. We’re here to make sure you hear your best, every day, in every situation."}]},{"_type":"block","_key":"p7p7b8dyl","style":"normal","children":[{"_type":"span","_key":"xo9pdwqea","text":"Call JC Audiology today to schedule your professional hearing aid fitting with Real Ear Measurement in Lutz, FL!"}]}]');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","route","meta_title","meta_description","body_content") VALUES('audiology-services__sensorineural-hearing-loss','audiology-services__sensorineural-hearing-loss','published',NULL,NULL,'2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z',NULL,NULL,1,NULL,NULL,NULL,NULL,'Sensorineural Hearing Loss Evaluation and Treatment','/audiology-services/sensorineural-hearing-loss/','Sensorineural Hearing Loss Evaluation and Treatment','JC Audiology provides sensorineural hearing loss evaluation and treatment in Lutz, FL.','[{"_type":"block","_key":"b-eecb9c9e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c7f01d3a","text":"JC Audiology provides sensorineural hearing loss evaluation and treatment in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-2acb3fbb","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a590cc83","text":"Sensorineural hearing loss, or SNHL, happens when there is damage to the inner ear or to the hearing nerve that sends sound signals to your brain. This kind of hearing loss often makes soft sounds hard to hear and can make louder sounds seem unclear, fuzzy, or muffled.","marks":[]}]},{"_type":"block","_key":"b-46b6505c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-817d0ee6","text":"Inside your inner ear are tiny hair cells that help you hear. Once these hair cells are damaged, they cannot grow back. This is why SNHL is usually permanent.","marks":[]}]},{"_type":"block","_key":"b-01ef0623","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-949df10a","text":"Why Getting Treatment Matters","marks":[]}]},{"_type":"block","_key":"b-4e114b5d","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ae4369bd","text":"If SNHL is not treated, it can make it harder to enjoy conversations, take part in social activities, and stay connected with friends and family. Over time, untreated hearing loss can cause frustration, loneliness, and even memory or thinking problems.","marks":[]}]},{"_type":"block","_key":"b-aa880289","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c7299869","text":"The good news is that with the right care, many people can improve their hearing and enjoy life more.","marks":[]}]},{"_type":"block","_key":"b-1a027a27","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f21bc5cd","text":"At JC Audiology, our audiologist and hearing aid specialist provide expert testing and treatment for sensorineural hearing loss in Lutz, FL.","marks":[]}]},{"_type":"block","_key":"b-dd99bc85","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-cdeb6e09","text":"Signs You Might Have Sensorineural Hearing Loss","marks":[]}]},{"_type":"block","_key":"b-5ffb707c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-06bdfe07","text":"SNHL can happen slowly over time or all at once. Some common signs include:","marks":[]}]},{"_type":"block","_key":"b-15cf470a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a8bb18e7","text":"Trouble hearing soft voices or whispers","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-c54cb5ab","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8fa78f55","text":"Feeling like people are mumbling","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-9117231e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0ffa1b34","text":"Often asking others to repeat themselves","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-c4d76dc9","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6f51dcea","text":"Difficulty understanding speech in noisy places","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-5f795a47","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f0f7c594","text":"Hearing ringing, buzzing, or hissing sounds (tinnitus)","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-2fdb9132","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0bb3603b","text":"Hearing better in one ear than the other","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-922396b0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-cfa761c2","text":"Sounds seem far away or unclear","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-19e2f24a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f3e242c2","text":"Difficulty hearing high-pitched sounds like birds or children’s voices","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-73be0208","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2fa77666","text":"If you notice any of these signs, it’s time to schedule a hearing check with an audiologist or hearing aid specialist at JC Audiology.","marks":[]}]},{"_type":"block","_key":"b-2f7bbdbc","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-3b1fea85","text":"What Causes Sensorineural Hearing Loss?","marks":[]}]},{"_type":"block","_key":"b-70030c81","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-828393ef","text":"SNHL can be caused by many things that harm the inner ear or hearing nerve, including:","marks":[]}]},{"_type":"block","_key":"b-b15bfcc7","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-24a6bf6f","text":"Aging","marks":["strong"]},{"_type":"span","_key":"s-c85a9731","text":" – As we get older, the tiny hair cells in our ears can wear out.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-6a2d6d94","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6dc33001","text":"Loud noise","marks":["strong"]},{"_type":"span","_key":"s-118b1352","text":" – Long-term exposure to loud sounds or one very loud noise (like a gunshot or explosion) can cause permanent damage.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-d32a20c8","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-4fbf1ae3","text":"Genetics","marks":["strong"]},{"_type":"span","_key":"s-d189fa34","text":" – Some people are born with hearing problems or develop them earlier in life because of inherited traits.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-2b1100f2","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-23650178","text":"Certain medications","marks":["strong"]},{"_type":"span","_key":"s-1f8f2586","text":" – Some drugs, called “ototoxic” medicines, can harm hearing. These can include certain antibiotics, chemotherapy drugs, or large doses of aspirin.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-a3a160a8","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-013ae621","text":"Head injuries","marks":["strong"]},{"_type":"span","_key":"s-b183bc84","text":" – Trauma to the head or skull can damage the hearing nerve or the cochlea in the inner ear.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-bb15ff1b","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2536b0bc","text":"Infections","marks":["strong"]},{"_type":"span","_key":"s-387df2c3","text":" – Illnesses like mumps, measles, meningitis, or other infections can injure the inner ear.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-06b6c30f","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-83946c17","text":"How We Diagnose and Treat SNHL","marks":[]}]},{"_type":"block","_key":"b-d394797b","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-39e4695e","text":"At JC Audiology, we start with a complete hearing test to see what type of hearing loss you have and how severe it is. If we find that you have SNHL, we’ll discuss treatment options that fit your needs, lifestyle, and goals.","marks":[]}]},{"_type":"block","_key":"b-a68c0f30","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-0fb30e8d","text":"Hearing Solutions For SNHL","marks":[]}]},{"_type":"block","_key":"b-3d4f3292","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ff0bf404","text":"Hearing Aids","marks":["strong"]},{"_type":"span","_key":"s-76495910","text":" – Great for mild to moderate SNHL. Today’s devices can have features like Bluetooth streaming, rechargeable batteries, and special microphones that make it easier to hear in noisy places.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-3e8e98c9","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9e3cbcdc","text":"Cochlear Implants","marks":["strong"]},{"_type":"span","_key":"s-dccab8df","text":" – Used for severe hearing loss when hearing aids are no longer enough. These devices send sound signals directly to the hearing nerve.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-4e22b00c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-fabb8b19","text":"Bone-Anchored Hearing Aids (BAHA)","marks":["strong"]},{"_type":"span","_key":"s-a8cd2364","text":" – Helpful for some people with hearing loss in one ear or mixed hearing loss. They send sound through the bone instead of the ear canal.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-46268fdc","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f6c585e4","text":"Our audiologists and hearing aid specialists will help you choose the option that gives you the clearest sound and most comfort.","marks":[]}]},{"_type":"block","_key":"b-00bcfc55","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-45f25efa","text":"Can SNHL Be Cured?","marks":[]}]},{"_type":"block","_key":"b-118025f5","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b9e2e6a9","text":"Right now, there is no cure for SNHL because the damaged hair cells in the ear do not grow back. But with early treatment (using hearing aids, cochlear implants, or other devices), you can greatly improve your ability to hear and stay active in conversations.","marks":[]}]},{"_type":"block","_key":"b-0b48d125","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-f8e05227","text":"How to Protect Your Hearing","marks":[]}]},{"_type":"block","_key":"b-ecf11dfe","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-667b1780","text":"While not all SNHL can be prevented, you can lower your risk by:","marks":[]}]},{"_type":"block","_key":"b-7ce4b342","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-78498296","text":"Wearing hearing protection","marks":["strong"]},{"_type":"span","_key":"s-d634877e","text":" – Use earplugs or earmuffs at concerts, when using loud tools, or around loud machinery.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-7e609dfb","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-330210ea","text":"Keeping volume safe","marks":["strong"]},{"_type":"span","_key":"s-65fc9675","text":" – Follow the 60/60 rule: listen at no more than 60% volume for no more than 60 minutes at a time.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-35c3f50e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1f57f5bd","text":"Taking breaks","marks":["strong"]},{"_type":"span","_key":"s-98d8900b","text":" – Give your ears time to rest from headphones or earbuds.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-9ecc4896","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-783c4c27","text":"Being aware of medications","marks":["strong"]},{"_type":"span","_key":"s-df023ce0","text":" – Ask your doctor if your medicine could affect your hearing.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-c860624f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1143305f","text":"Getting regular hearing check-ups","marks":["strong"]},{"_type":"span","_key":"s-c8ffb828","text":" – Early testing can find problems before they get worse.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-3a556211","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-06fefef4","text":"Sensorineural Hearing Loss Care in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-664f47e7","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e69496c8","text":"At JC Audiology, we are dedicated to helping you hear your best. Our audiologist and hearing aid specialist offer complete hearing tests, accurate diagnosis, and personalized treatment plans for sensorineural hearing loss.","marks":[]}]},{"_type":"block","_key":"b-bcfe3151","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9650c031","text":"We use the latest technology to help improve your hearing and make it easier to connect with the people and activities you love.","marks":[]}]},{"_type":"block","_key":"b-69af1fbd","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-502d08a8","text":"Call JC Audiology today to schedule your professional hearing evaluation in Lutz, FL.","marks":[]}]}]');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","route","meta_title","meta_description","body_content") VALUES('audiology-services__tinnitus-evaluation-support','audiology-services__tinnitus-evaluation-support','published',NULL,NULL,'2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z',NULL,NULL,1,NULL,NULL,NULL,NULL,'Tinnitus Evaluation and Support','/audiology-services/tinnitus-evaluation-support/','Tinnitus Evaluation and Support','JC Audiology provides expert tinnitus evaluations and support in Lutz, FL.','[{"_type":"block","_key":"b-947d836b","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3a51a8c7","text":"JC Audiology provides expert tinnitus evaluations and support in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-2be32d31","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2c2c3bea","text":"Hearing phantom sounds or ringing in the ears can be disturbing, distressing, or downright distracting. At JC Audiology, we provide tinnitus evaluations and personalized treatment and management to help reduce the effects of ringing, buzzing, clicking, or hissing in your ears.","marks":[]}]},{"_type":"block","_key":"b-01148784","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6c3ba2bb","text":"If you or a loved one experiences ringing in the ears or related hearing issues, our audiologist in Lutz, FL is here to help you find relief.","marks":[]}]},{"_type":"block","_key":"b-f3cf7d3f","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-00be7dae","text":"What Causes Tinnitus?","marks":[]}]},{"_type":"block","_key":"b-853979c9","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3c10c361","text":"Tinnitus can develop or be triggered for many reasons.","marks":[]}]},{"_type":"block","_key":"b-cad878f7","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-94fa07e4","text":"One of the most common causes is hearing loss.","marks":[]}]},{"_type":"block","_key":"b-00490c3a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3222e2c3","text":"When the brain has issues receiving sound input from the ears, it may compensate by generating phantom sounds like ringing or buzzing.","marks":[]}]},{"_type":"block","_key":"b-8d433063","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-33949eb0","text":"Repeated exposure to loud noises can also damage the auditory system and lead to tinnitus.","marks":[]}]},{"_type":"block","_key":"b-dbf1cd21","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-76f7f1f2","text":"A blockage from excess earwax can also trigger tinnitus. When impacted earwax is pressed against the eardrum, a sensation of ringing or fullness in the ear may be experienced.","marks":[]}]},{"_type":"block","_key":"b-9ff93e83","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0ca61de6","text":"Underlying health issues such as TMJ dysfunction, high blood pressure, or ear infections may also trigger tinnitus.","marks":[]}]},{"_type":"block","_key":"b-bce5c839","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-754b96aa","text":"Ringing in the ears may also be a side-effect of certain medications.","marks":[]}]},{"_type":"block","_key":"b-361779d0","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-910e8ed2","text":"Tinnitus Evaluations in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-8f551763","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-29f23830","text":"At JC Audiology, our audiologist or hearing aid specialist will conduct a thorough assessment to help identify potential causes.","marks":[]}]},{"_type":"block","_key":"b-7769110c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3ffa22df","text":"During your tinnitus evaluation, we’ll begin by discussing your symptoms, asking you when the phantom sounds occur, how frequently they happen, and how they affect you and your daily life.","marks":[]}]},{"_type":"block","_key":"b-e4bc14d5","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3d7b5d65","text":"A physical examination of your ears may also be performed. This is to check for possible wax buildup, blockages, perforations, or signs of infection.","marks":[]}]},{"_type":"block","_key":"b-d3179439","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6e1ccf66","text":"Since tinnitus is linked to hearing loss, hearing tests may also be performed to measure your ability to detect speech and tones.","marks":[]}]},{"_type":"block","_key":"b-9ec9849b","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-fbe6aea4","text":"Tinnitus Treatment Options at JC Audiology","marks":["strong"]}]},{"_type":"block","_key":"b-b6fce4af","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3a309528","text":"While there’s no exact cure for tinnitus yet, there are plenty of ways to manage the symptoms.","marks":[]}]},{"_type":"block","_key":"b-7367d5bf","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-a4b7818a","text":"Sound Therapy","marks":[]}]},{"_type":"block","_key":"b-8d420fb5","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-645491b9","text":"Sound therapy involves gentle background sounds to help your brain tune out the ringing. Think of white noise machines that create a steady, calming hum.","marks":[]}]},{"_type":"block","_key":"b-b44e18f2","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e6c812fa","text":"Nature sounds like wind blowing, ocean waves or rainfall work great, too. Even better, many modern hearing aids come with built-in sound masking features that quietly soothe your tinnitus throughout the day.","marks":[]}]},{"_type":"block","_key":"b-907cfde1","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-dc1bc7d2","text":"Hearing Aids","marks":[]}]},{"_type":"block","_key":"b-bf48a4fd","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2c404eed","text":"If your tinnitus tags along with hearing loss, hearing aids can be a real game-changer. They make everyday sounds louder and clearer, helping your brain focus on real noise instead of the ringing. Plus, lots of hearing aids include special tinnitus masking programs designed just for this. JC Audiology offers a wide selection of hearing aids in Lutz, FL.","marks":[]}]},{"_type":"block","_key":"b-3c130d04","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-00812ead","text":"Stress Management & Counseling","marks":[]}]},{"_type":"block","_key":"b-802de7e4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-10e7ad33","text":"Tinnitus and stress often feed off each other. That’s why we recommend activities that calm your mind, like deep breathing, yoga, or light exercise. ","marks":[]}]},{"_type":"block","_key":"b-e0d2be29","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-4257fad9","text":"Lifestyle Changes","marks":[]}]},{"_type":"block","_key":"b-38db7ebf","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-d21c43a7","text":"Small changes can add up and give you tinnitus relief!","marks":[]}]},{"_type":"block","_key":"b-749566bd","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-22265a24","text":"Cutting back on caffeine and alcohol, protecting your ears in noisy places, staying away from and getting good sleep all support tinnitus relief. Mindfulness and relaxation practices also help lower tinnitus’ volume, so you feel more in control every day.","marks":[]}]},{"_type":"block","_key":"b-57549fdc","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-603f7e2a","text":"Frequently Asked Questions About Tinnitus","marks":[]}]},{"_type":"block","_key":"b-a983b0b6","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-4651da5e","text":"Will tinnitus go away on its own?","marks":[]}]},{"_type":"block","_key":"b-a4c798c6","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-16ad9719","text":"Sometimes, yes! If caused by a temporary issue like loud noise exposure or earwax buildup, it might fade with time. If it lasts more than a few weeks, it’s time to get checked by a professional.","marks":[]}]},{"_type":"block","_key":"b-a38e765c","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-37350066","text":"Can stress make tinnitus worse?","marks":[]}]},{"_type":"block","_key":"b-d568f690","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3cafabec","text":"Definitely. Stress and anxiety can make tinnitus feel louder and more annoying. Managing stress often helps reduce how much you notice it.","marks":[]}]},{"_type":"block","_key":"b-37e93ef5","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-8f03fc61","text":"Is tinnitus always caused by hearing loss?","marks":[]}]},{"_type":"block","_key":"b-c97b17e5","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-32c5cc2e","text":"Not always. While tinnitus often comes with hearing loss, you can have tinnitus and normal hearing too. A hearing test will help figure out what’s going on.","marks":[]}]},{"_type":"block","_key":"b-6e47eef1","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-40fb0632","text":"Do hearing aids help with tinnitus?","marks":[]}]},{"_type":"block","_key":"b-66de0bdc","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c559d89b","text":"Yes! Hearing aids can improve how well you hear real sounds and help mask the ringing inside your ears. Many come with special features made just for tinnitus relief.","marks":[]}]},{"_type":"block","_key":"b-62754cd3","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-4718170d","text":"Can ear wax be the reason for my tinnitus?","marks":[]}]},{"_type":"block","_key":"b-eb37258a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ed405b27","text":"It ","marks":[]},{"_type":"span","_key":"s-c1321394","text":"could","marks":["em"]},{"_type":"span","_key":"s-fe3cca6d","text":" be. Too much earwax can block sounds and cause ringing. If wax is the culprit, safely removing it can often clear up your tinnitus quickly. It would be best to see an audiologist if you are experiencing tinnitus so you can get an accurate diagnosis and the exact triggers can be identified and addressed.","marks":[]}]},{"_type":"block","_key":"b-62d7c0ec","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-9bd95a51","text":"Schedule Your Tinnitus Evaluation in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-08ded9fe","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-77c11e00","text":"Tinnitus doesn’t have to put your hearing and enjoyment on the line.","marks":[]}]},{"_type":"block","_key":"b-2fa1fbc6","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-40dca061","text":"JC Audiology provides tinnitus evaluations and customized tinnitus support approaches designed to help you manage your symptoms.","marks":[]}]},{"_type":"block","_key":"b-946118ce","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-12461ad2","text":"Contact us today to schedule your tinnitus evaluation in Lutz, FL!","marks":[]}]}]');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","route","meta_title","meta_description","body_content") VALUES('custom-hearing-protection','custom-hearing-protection','published',NULL,NULL,'2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z',NULL,NULL,1,NULL,NULL,NULL,NULL,'Custom Hearing Protection','/custom-hearing-protection/','Custom Hearing Protection','Protect your hearing with custom hearing protection for work, music, or sports. Learn about your options and order custom protection today.','[{"_type":"block","_key":"b-c62a6ada","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2ec08daa","text":"JC Audiology provides custom hearing protection in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-04f33b3b","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a256b7d1","text":"At JC Audiology in Lutz, FL, we believe that protecting your hearing is just as important as treating hearing loss. Once hearing is damaged, it cannot be restored naturally. Taking the necessary steps to safeguard it now is an investment in your lifelong hearing health.","marks":[]}]},{"_type":"block","_key":"b-1d359e4d","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b0c89d03","text":"Whether you spend your days around loud machinery, attend live concerts, enjoy hunting trips, swim regularly, or simply want a better night’s sleep, the right hearing protection can make a huge difference. Our experienced audiologist and hearing aid specialist work together to provide both custom-fit and ready-made hearing protection designed for your comfort, safety, and lifestyle needs. From soft sleep plugs to advanced digital shooting protection, we’ll help you choose the perfect solution.","marks":[]}]},{"_type":"block","_key":"b-5c6b336b","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-b732217d","text":"Types of Hearing Protection We Offer","marks":[]}]},{"_type":"block","_key":"b-cf5d25f3","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-4b8a4395","text":"Ready-Made Hearing Protection","marks":[]}]},{"_type":"block","_key":"b-f24ca045","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-72742e2e","text":"These affordable, pre-formed options are quick to use and great for many everyday situations.","marks":[]}]},{"_type":"block","_key":"b-3e5d35b0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f3abd0da","text":"Earplugs: Inserted into the ear canal to reduce noise in loud places like concerts or busy events.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-f2d9aa19","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ab334de6","text":"Semi-Insert Earplugs: Connected by a flexible band and rest at the ear canal entrance for easy removal.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-677c6be4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-777d46d6","text":"Earmuffs: Cover the whole ear to block sound from the outside.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-59351d0b","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-654a6604","text":"Note: Ready-made options are convenient, but may not fit as securely or comfortably as custom-made products.","marks":["em"]}]},{"_type":"block","_key":"b-228ea9ac","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-c55caee2","text":"Custom Hearing Protection","marks":[]}]},{"_type":"block","_key":"b-f43b98da","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-cfa41532","text":"Custom protection is molded to the exact shape of your ear, giving you a personalized fit, long-lasting comfort, and top-level noise reduction.","marks":[]}]},{"_type":"block","_key":"b-19cd402c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8392aca6","text":"Custom Earplugs: Great for workers, musicians, and anyone regularly around loud sounds.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-afe956ef","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-d91ca1f8","text":"Impulse Filter Earplugs: Perfect for hunting and shooting-block dangerous gunshot noise while letting you hear softer sounds like voices or movement.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-cedb0845","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-89982566","text":"Sleep Plugs: Soft and flexible earplugs that help reduce snoring and nighttime noise so you can sleep better.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-eaf087ba","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-4875abc5","text":"In-Ear Monitors (IEMs): High-quality sound devices for musicians and performers that allow clear listening without damaging volume levels.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-dfce3397","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-de6c1128","text":"Digital Hearing Protection (SoundGear): Advanced devices for shooters, hunters, and industrial workers that respond instantly to sudden loud sounds.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-003e2be9","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-4d165a44","text":"Hearing Protection for Your Lifestyle","marks":[]}]},{"_type":"block","_key":"b-8bca2717","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e0dd28ca","text":"Music & Performing: Custom musician plugs and IEMs that lower volume while still keeping sound quality clear.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-a138e71f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1f35c2c7","text":"Hunting & Shooting: Smart plugs and digital devices that block loud blasts while keeping you aware of your surroundings.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-f733cb44","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1e54c7cd","text":"Swimming & Water Sports: Custom swim plugs that help prevent swimmer’s ear and keep water out.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-0d8ee769","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-12c539d4","text":"Sleeping: Sleep plugs to block snoring and neighborhood noise for better rest.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-3e6050af","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3c76ee0b","text":"Industrial & Construction Work: Durable custom plugs and earmuffs to protect against workplace noise.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-dc170031","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f00f0e99","text":"Surfing: Surf plugs shield your ears from wind and cold water to help prevent surfer’s ear.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-3eda8cef","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-e9a20e48","text":"Types of Custom Ear Mold Materials","marks":[]}]},{"_type":"block","_key":"b-ded81c88","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-934bf540","text":"Custom ear molds are made from different materials, offering varying levels of comfort, protection, and durability.","marks":[]}]},{"_type":"block","_key":"b-759f2e34","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8567b0ac","text":"They are used for hearing aids, sleep plugs, musician monitors, etc.","marks":[]}]},{"_type":"block","_key":"b-7b86fe4c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c86e6804","text":"Each type offers varying levels of comfort, protection, and durability.","marks":[]}]},{"_type":"block","_key":"b-34f56568","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-688ebeb4","text":"Acrylic: Hard, smooth, and easy to clean.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-d094e02d","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3c37a9f8","text":"Vinyl: Soft and gentle.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-abbece51","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b8efd2da","text":"Silicone: Flexible and water-resistant.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-5b93ff16","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-49cc83fc","text":"How Custom Ear Molds Are Made","marks":[]}]},{"_type":"block","_key":"b-0526e522","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-61de2455","text":"Getting custom hearing protection is quick and painless:","marks":[]}]},{"_type":"block","_key":"b-e576c013","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8ed78896","text":"Our audiologist or hearing aid specialist takes an impression of your ear using soft material.","marks":[]}],"listItem":"number","level":1},{"_type":"block","_key":"b-4fef4cec","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-5bf325bf","text":"The mold is sent to a specialized lab.","marks":[]}],"listItem":"number","level":1},{"_type":"block","_key":"b-4de51397","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a27168f9","text":"Your product is made in your chosen material for a perfect fit.","marks":[]}],"listItem":"number","level":1},{"_type":"block","_key":"b-340ce812","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b8eb5272","text":"The result is comfortable, effective protection that you can wear for hours without discomfort.","marks":[]}]},{"_type":"block","_key":"b-bec2288f","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-07587124","text":"How Long Do Custom Earplugs Last?","marks":[]}]},{"_type":"block","_key":"b-25588c5e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1d09a0d5","text":"With good care, custom earplugs can last 3 to 5 years. Their life span depends on how often you use them, how you clean them, and whether your ears change shape over time. We recommend occasional fit checks to make sure they still work properly.","marks":[]}]},{"_type":"block","_key":"b-e0782f1c","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-32f43b63","text":"FAQs About Custom Hearing Protection","marks":[]}]},{"_type":"block","_key":"b-9aed7bb9","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-988771e9","text":"How do I clean my custom earplugs or molds?","marks":[]}]},{"_type":"block","_key":"b-3ecbbf1e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f89ccdf7","text":"Wipe them with a soft, dry cloth after each use. For a deeper clean, use mild soap and warm water, then let them dry completely before wearing. Avoid harsh cleaners.","marks":[]}]},{"_type":"block","_key":"b-dfb52cb4","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-77831802","text":"Can I wear custom plugs with other safety gear like helmets?","marks":[]}]},{"_type":"block","_key":"b-6e7888ac","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0b2e1ea5","text":"Yes. Custom plugs fit entirely in the ear, so they work well under helmets and other headgear.","marks":[]}]},{"_type":"block","_key":"b-76156465","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-0b584500","text":"Will custom earplugs completely block all sound?","marks":[]}]},{"_type":"block","_key":"b-d6e68f18","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-bf0ed58d","text":"No. They are designed to reduce harmful noise while letting you hear safe, important sounds like speech or alarms.","marks":[]}]},{"_type":"block","_key":"b-3ad7558e","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-a93c8db7","text":"Hearing Protection in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-46415753","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-7e8a32be","text":"If you work, play, or sleep in noisy environments, JC Audiology in Lutz, FL can help you protect your hearing.","marks":[]}]},{"_type":"block","_key":"b-3a4717df","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-38dd8889","text":"We offer both ready-made and custom solutions, made for your exact needs, activities, and comfort.","marks":[]}]},{"_type":"block","_key":"b-d5f835a0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-aaa635da","text":"Call us today to schedule your appointment and explore our full range of hearing protection options.","marks":[]}]}]');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","route","meta_title","meta_description","body_content") VALUES('hearing-aids-products','hearing-aids-products','published',NULL,NULL,'2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z',NULL,NULL,1,NULL,NULL,NULL,NULL,'Hearing Aids & Products','/hearing-aids-products/','Hearing Aids &amp; Products','Browse quality hearing aids from trusted brands with support from our audiologists. Find the right hearing solution and contact us to get started.','[{"_type":"block","_key":"xvimzk7at","style":"normal","children":[{"_type":"span","_key":"82spuijy6","text":"JC Audiology provides quality hearing aids and products in Lutz, FL.","marks":["strong","em"]}]},{"_type":"block","_key":"4ko2bv1tn","style":"normal","children":[{"_type":"span","_key":"5e4juhdcy","text":"At JC Audiology, we want you to hear for life. Hearing your best helps you live your best! That’s why we are proud to offer and service many of today’s most trusted hearing aid brands."}]},{"_type":"block","_key":"it2i5zd58","style":"normal","children":[{"_type":"span","_key":"luds089qd","text":"Whether you already wear hearing aids or are just starting to explore your options, our caring audiologist and hearing aid specialist in Lutz, FL are here to help."}]},{"_type":"block","_key":"lh8rg3bpm","style":"normal","children":[{"_type":"span","_key":"zrim6x65x","text":"We work with a variety of reliable hearing aid brands to make sure you get the right technology for your needs, your lifestyle, and your comfort."}]},{"_type":"block","_key":"z5fy6yxnx","style":"h2","children":[{"_type":"span","_key":"mmx5l53lc","text":"Hearing Aid Brands We Offer"}]},{"_type":"block","_key":"fqhzmto7a","style":"h3","children":[{"_type":"span","_key":"366end7oj","text":"Oticon Hearing Aids"}]},{"_type":"block","_key":"hzqxwy3pc","style":"normal","children":[{"_type":"span","_key":"rufpa2i75","text":"Oticon has been creating hearing solutions for more than 100 years. Their BrainHearing™ technology helps your brain process sound more easily, so you feel less tired and hear more clearly, even in noisy places. Models like Oticon Intent and Oticon Real offer Bluetooth, tinnitus relief, and a natural, comfortable listening experience. Oticon Intent 2, released in late 2024, builds on their Intent line with even better sound clarity and personalized listening."}]},{"_type":"block","_key":"pu4vu7xb9","style":"h3","children":[{"_type":"span","_key":"fao9sod6k","text":"Widex Hearing Aids"}]},{"_type":"block","_key":"w3dgck10n","style":"normal","children":[{"_type":"span","_key":"2txiy8ce6","text":"Widex is known for clear, natural sound. Their hearing aids process sound quickly with almost no delay. Popular models like Widex Moment and Widex SmartRIC help with tinnitus through Zen Therapy and work easily with smartphones for custom adjustments. Widex Allure, launched in early 2025, brings a new chip and the world’s first cloud-based fitting software (Compass Cloud) for a more natural hearing experience."}]},{"_type":"block","_key":"pic37f2in","style":"h3","children":[{"_type":"span","_key":"cc51bg8ad","text":"Phonak Hearing Aids"}]},{"_type":"block","_key":"u4ty0vgxx","style":"normal","children":[{"_type":"span","_key":"0lu6sg7u2","text":"Phonak is a worldwide leader in hearing technology. Models like Phonak Lumity make speech clearer, while Phonak Naída provides strong amplification for people with severe hearing loss. The Phonak Audéo Sphere Infinio uses a deep neural network chip for excellent speech clarity, even in noisy places. Many Phonak aids are rechargeable, stream through Bluetooth, and resist water for daily convenience. Looking for the latest Phonak device? The Infinio platform was expanded in January 2025 with new custom in-the-ear models: Virto Titanium Infinio and Virto 10 NW O Infinio."}]},{"_type":"block","_key":"czb1dgctl","style":"h3","children":[{"_type":"span","_key":"oud8qnbr0","text":"Starkey Hearing Aids"}]},{"_type":"block","_key":"ts43f7b4f","style":"normal","children":[{"_type":"span","_key":"rst3mt0dn","text":"Starkey hearing aids combine great sound with wellness features such as fall alerts, activity tracking, and tinnitus relief. Models like Starkey Genesis AI and Evolv AI allow hands-free calling, app control, and come with rechargeable options—perfect for active lifestyles. The Edge AI line brings AI sound processing with an ultra-fast neuroprocessor chip and easier wireless streaming via LE Audio."}]},{"_type":"block","_key":"7h74uey6d","style":"h3","children":[{"_type":"span","_key":"a8ccrkkki","text":"ReSound Hearing Aids"}]},{"_type":"block","_key":"dl5e1fkk7","style":"normal","children":[{"_type":"span","_key":"9mgzj17v2","text":"ReSound devices provide natural sound and strong wireless performance. Models like ReSound Vivia and ReSound ONE have personal sound settings, help you hear better in noisy places, and include tinnitus management. Many are rechargeable and work with iOS and Android for streaming. ReSound Vivia, launched in early February 2025, uses Deep Neural Network (DNN) artificial intelligence to improve hearing in noisy places. The ReSound Enzo IA, the world’s smallest rechargeable Super Power hearing aid, ideal for severe to profound loss."}]},{"_type":"block","_key":"kkoklglg4","style":"h3","children":[{"_type":"span","_key":"lpcshb7mo","text":"Unitron Hearing Aids"}]},{"_type":"block","_key":"rnljxwyfz","style":"normal","children":[{"_type":"span","_key":"jmlrkmz9v","text":"Unitron focuses on comfort and easy use. Their technology changes with your surroundings for smoother listening. The Unitron Blu line includes Bluetooth streaming, app adjustments, and rechargeable batteries. The Smile platform is the newest batch for Unitron. It uses AI-powered sound tuning, improved Bluetooth, and a comfy design for an easy hearing experience."}]},{"_type":"block","_key":"ii8elgxdc","style":"h3","children":[{"_type":"span","_key":"011bnaiix","text":"Signia Hearing Aids"}]},{"_type":"block","_key":"orxw7vegc","style":"normal","children":[{"_type":"span","_key":"htkt80g9o","text":"Signia blends sleek design with strong performance. Models like Pure Charge&Go and Silk X offer clear speech in noise, Bluetooth connection, and discreet styles. Some have Own Voice Processing (OVP) so your voice sounds more natural to you. The Integrated Xperience (IX) platform includes popular models like Styletto AX, Pure Charge&Go AX, and Motion Charge&Go X."}]},{"_type":"block","_key":"0651s31bb","style":"h2","children":[{"_type":"span","_key":"nj1znb9o2","text":"Frequently Asked Questions"}]},{"_type":"block","_key":"dlyuun0ly","style":"h3","children":[{"_type":"span","_key":"4tfcqwoye","text":"Which hearing aids are the most advanced?"}]},{"_type":"block","_key":"vfi42f1ns","style":"normal","children":[{"_type":"span","_key":"nxhn4nzfp","text":"The best hearing aid for you depends on your hearing needs and lifestyle. Many top models have speech clarity features, rechargeability, Bluetooth, and noise reduction."}]},{"_type":"block","_key":"8s0ziaa6g","style":"h3","children":[{"_type":"span","_key":"t3e91cogo","text":"Which brands help with tinnitus?"}]},{"_type":"block","_key":"viq6ze2hf","style":"normal","children":[{"_type":"span","_key":"s2em9q98i","text":"Oticon, Widex, and Starkey have special sound therapy programs to ease ringing in the ears."}]},{"_type":"block","_key":"3g7401mab","style":"h3","children":[{"_type":"span","_key":"rgbgkim4f","text":"What hearing aids work best for severe hearing loss?"}]},{"_type":"block","_key":"l1npft16i","style":"normal","children":[{"_type":"span","_key":"w11mclokd","text":"Powerful models from Oticon, Phonak, and Starkey are great for people with severe hearing loss."}]},{"_type":"block","_key":"pkjzmtyqj","style":"h2","children":[{"_type":"span","_key":"6vnhi1nt3","text":"Custom Hearing Protection"}]},{"_type":"block","_key":"neadrdqef","style":"normal","children":[{"_type":"span","_key":"1sxpfbk0w","text":"We make custom-molded earplugs for work, hobbies, and daily life. They’re great for concerts, riding motorcycles, construction work, or sleeping. Custom plugs fit comfortably and reduce harmful noise without blocking all sounds."}]},{"_type":"block","_key":"p3ldwjm2e","style":"h2","children":[{"_type":"span","_key":"t5q0k46dc","text":"Custom Ear Molds"}]},{"_type":"block","_key":"oru7uwg8l","style":"normal","children":[{"_type":"span","_key":"89a7lrg7z","text":"Custom ear molds are shaped just for your ears, giving you a better fit and improved sound quality. They work well for hearing aids, in ear monitors (IEM) for musicians, headsets, and swim and sleep plugs."}]},{"_type":"block","_key":"jrmznr3su","style":"normal","children":[{"_type":"span","_key":"at78nybro","text":"With the right ear molds, you can enjoy perfect fit with less chances of whistling, improved comfort, and confidence that your device stays put all day."}]},{"_type":"block","_key":"7gaj0epl5","style":"h3","children":[{"_type":"span","_key":"0skd7o7ev","text":"Frequently Asked Questions"}]},{"_type":"block","_key":"af52hsbu7","style":"h3","children":[{"_type":"span","_key":"pkegnn2ow","text":"Is it safe to sleep with earplugs?"}]},{"_type":"block","_key":"mtr9h13t2","style":"normal","children":[{"_type":"span","_key":"cvx0c8pn6","text":"Yes, it is safe. Just make sure they are clean and fit well."}]},{"_type":"block","_key":"btqv5c2no","style":"h3","children":[{"_type":"span","_key":"xujxptdsv","text":"How long do custom ear molds last?"}]},{"_type":"block","_key":"0tkk9iuiw","style":"normal","children":[{"_type":"span","_key":"ihqximt25","text":"Usually 2–5 years, depending on care and changes in your ears."}]},{"_type":"block","_key":"04tpl59rc","style":"h3","children":[{"_type":"span","_key":"boyid3wdk","text":"How do I clean my custom earplugs or ear molds?"}]},{"_type":"block","_key":"lunypv74x","style":"normal","children":[{"_type":"span","_key":"89v73akqv","text":"Wipe them daily with a soft, dry cloth. For a deeper clean, use mild soap and warm water, making sure they are completely dry before using them again. Avoid harsh chemicals, as they can damage the material."}]},{"_type":"block","_key":"5lf0dif2s","style":"h2","children":[{"_type":"span","_key":"iud3iekee","text":"Assistive Listening Devices (ALDs)"}]},{"_type":"block","_key":"b09tb6kpx","style":"normal","children":[{"_type":"span","_key":"3zuedaz1s","text":"ALDs help you hear better in certain situations-like watching TV, going to a meeting, or talking on the phone. They work with or without hearing aids and make sound clearer by reducing background noise. Examples include:"}]},{"_type":"block","_key":"va0jrzgvi","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ffr4hq2cc","text":"TV Streamers: Send TV sound straight to your hearing aids"}]},{"_type":"block","_key":"7lhnm01x3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"sxil326ks","text":"FM Systems: Make a teacher’s or speaker’s voice clearer in class or meetings"}]},{"_type":"block","_key":"mpxwg88jx","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"1clurzksf","text":"Personal Amplifiers: Handheld devices for one-on-one or small group chats"}]},{"_type":"block","_key":"slcqom0k7","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"nwji9mrnj","text":"Hearing Loop Systems: Installed in public places and work with telecoil hearing aids"}]},{"_type":"block","_key":"op2q4fht8","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"0q37goqx0","text":"Bluetooth Microphones: Clip-on mics that stream a person’s voice directly to your aids"}]},{"_type":"block","_key":"1305fbk77","style":"h3","children":[{"_type":"span","_key":"a8d02ilxe","text":"Frequently Asked Questions"}]},{"_type":"block","_key":"o4pt6zp1x","style":"h3","children":[{"_type":"span","_key":"ixbjd0zl3","text":"What is the most common type of ALD?"}]},{"_type":"block","_key":"l5kpht79v","style":"normal","children":[{"_type":"span","_key":"svt5sdmmz","text":"TV streamers and personal amplifiers are very popular because they make voices and sound clearer at home, especially when there’s background noise."}]},{"_type":"block","_key":"pa96ub945","style":"h3","children":[{"_type":"span","_key":"t3cscpgh5","text":"Can I use my smartphone as an ALD?"}]},{"_type":"block","_key":"9l1nen9rr","style":"normal","children":[{"_type":"span","_key":"r613xredm","text":"Yes. Some hearing aids work with smartphone features like Apple’s Live Listen, which turns your phone into a microphone and sends sound directly to your hearing aids."}]},{"_type":"block","_key":"yfhn9jrrk","style":"h3","children":[{"_type":"span","_key":"g71b2tlq7","text":"Do ALDs work without hearing aids?"}]},{"_type":"block","_key":"17j1u4911","style":"normal","children":[{"_type":"span","_key":"0bm9a83t9","text":"Yes. While many ALDs connect to hearing aids, some (like personal amplifiers) can be used with regular headphones or earbuds."}]},{"_type":"block","_key":"53zm40gcb","style":"h2","children":[{"_type":"span","_key":"2ye8ienxl","text":"Hearing Aids and Custom Hearing Protection in Lutz, FL"}]},{"_type":"block","_key":"iozf7mph9","style":"normal","children":[{"_type":"span","_key":"4ekgrrysq","text":"If you need hearing aids, custom ear protection, or help with your current devices, JC Audiology is here for you. We’ll help you choose the right solution so you can hear and live better every day."}]},{"_type":"block","_key":"b00cxeswd","style":"normal","children":[{"_type":"span","_key":"1m9bufkis","text":"Call us today to schedule your appointment!"}]}]');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","route","meta_title","meta_description","body_content") VALUES('hearing-aids-products__hearing-aid-alternatives','hearing-aids-products__hearing-aid-alternatives','published',NULL,NULL,'2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z',NULL,NULL,1,NULL,NULL,NULL,NULL,'Hearing Aid Alternatives: Assistive Listening Devices','/hearing-aids-products/hearing-aid-alternatives/','Hearing Aid Alternatives: Assistive Listening Devices','Explore hearing aid alternatives like assistive listening devices tailored to your needs. Learn your options and contact us to find the right solution.','[{"_type":"block","_key":"b-af33cc0c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-bda82c1b","text":"JC Audiology offers assistive listening devices in Lutz, FL.","marks":["em","strong"]}]},{"_type":"block","_key":"b-336e450f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-5f136d27","text":"At JC Audiology, we understand that even the most advanced hearing aids sometimes need extra support. Even the most powerful hearing aids may still need an extra boost, especially in places with lots of background noise, long distances between you and the speaker, or challenging acoustics.","marks":[]}]},{"_type":"block","_key":"b-0263fadc","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9903b36b","text":"Whether you’re trying to follow a conversation in a busy restaurant, listen to a lecture, hear a sermon at church, or enjoy your favorite TV show at home, Assistive Listening Devices (ALDs) can make it easier to hear clearly and comfortably.","marks":[]}]},{"_type":"block","_key":"b-5fe40381","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a0ec3225","text":"Our audiologist and hearing aid specialist work together to help you explore, choose, and use the right ALD for your lifestyle. These helpful tools can work alongside your hearing aids or be used on their own, giving you more confidence and comfort in your daily communication.","marks":[]}]},{"_type":"block","_key":"b-4caa3580","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-7f4f49f3","text":"Why Use an Assistive Listening Device?","marks":[]}]},{"_type":"block","_key":"b-af8349aa","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-339f3b72","text":"Hearing aids are excellent for everyday situations, but they may still face challenges in places like theaters, classrooms, houses of worship, or large gatherings. Meanwhile, ALDs are task-specific devices designed specifically to improve sound clarity in various listening environments. They can:","marks":[]}]},{"_type":"block","_key":"b-6ffca93b","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-be9f0f38","text":"Enhance speech understanding in noisy spaces so you can follow conversations without guessing.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-58044636","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9e1cae8e","text":"Improve listening over distance, making it easier to hear a speaker from across a large room.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-0c631edd","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8229056d","text":"Reduce background distractions, allowing you to focus on the sound you want to hear.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-20545a02","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-5ced5f73","text":"Make TV shows, phone calls, and public announcements clearer, so you can stay connected without strain.","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-0be02b3e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6ee7223f","text":"In a nutshell, ALDs help you enjoy activities and social events with less fatigue and more confidence.","marks":[]}]},{"_type":"block","_key":"b-ffea29c7","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-bd803fb0","text":"Common Types of Assistive Listening Devices","marks":[]}]},{"_type":"block","_key":"b-de649c84","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-6c021e5c","text":"Hearing Loop (Induction) Systems","marks":[]}]},{"_type":"block","_key":"b-d601b9ba","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2ec3406f","text":"Hearing loop systems send sound through electromagnetic signals directly to hearing aids or cochlear implants equipped with telecoils (T-coils). They work well in public venues like churches, theaters, and auditoriums, providing clear sound without extra background noise and allowing for hands-free listening.","marks":[]}]},{"_type":"block","_key":"b-e7775e02","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-42b366bb","text":"Infrared Systems","marks":[]}]},{"_type":"block","_key":"b-3ca80782","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2cd4e8b1","text":"Infrared systems use invisible light waves to send sound to a personal receiver. They are usually paired with headphones or a neck loop. Infrared systems are great for private settings such as home TV listening or courtrooms, where privacy is important and radio interference is not an issue.","marks":[]}]},{"_type":"block","_key":"b-5de181a8","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-8685c349","text":"FM Systems","marks":[]}]},{"_type":"block","_key":"b-ad0db54e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ea0092aa","text":"FM systems send sound via radio waves from a microphone worn by a speaker to a receiver used by the listener. They are popular in classrooms, meetings, and group activities, as they make speech clearer and easier to follow over distance.","marks":[]}]},{"_type":"block","_key":"b-d7a6f474","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-58dfd03d","text":"Personal Amplifiers","marks":[]}]},{"_type":"block","_key":"b-6941e460","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-2e021a72","text":"Small and portable, personal amplifiers use a microphone and headset to boost nearby sounds. They are ideal for one-on-one conversations, quiet group settings, or watching television at home without increasing the volume for everyone else.","marks":[]}]},{"_type":"block","_key":"b-1c147987","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-86f87820","text":"TV Listening Systems","marks":[]}]},{"_type":"block","_key":"b-4adc1352","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9ae55250","text":"These devices stream audio from your TV straight to your hearing aids or wireless headphones. Whether they use Bluetooth, infrared, or radio frequency, they provide clear sound without needing to raise the TV volume.","marks":[]}]},{"_type":"block","_key":"b-17004248","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-6b6511c1","text":"Alerting Devices","marks":[]}]},{"_type":"block","_key":"b-afbd86b1","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-11fff4b1","text":"As their name implies, alerting devices help individuals stay or be aware of important sounds. They may use flashing lights, vibrations, or loud tones to signal events or important alarms. Alerting devices can be connected with smartphones or smart home systems.","marks":[]}]},{"_type":"block","_key":"b-ced3630f","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-1d94ff5e","text":"FAQs About Assistive Listening Devices","marks":[]}]},{"_type":"block","_key":"b-94da9c22","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-9cb1404c","text":"What is the most commonly used ALD?","marks":[]}]},{"_type":"block","_key":"b-27c218d7","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-7b968453","text":"FM systems are among the most popular, especially in classrooms or group environments, because they deliver the speaker’s voice directly to the listener.","marks":[]}]},{"_type":"block","_key":"b-36adf9dd","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-9c332f6d","text":"Can ALDs replace hearing aids?","marks":[]}]},{"_type":"block","_key":"b-950eb5ee","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-59f01030","text":"ALDs can help people with mild hearing loss, but they are not a replacement for hearing aids if you have moderate to severe hearing loss. Most people benefit from using ALDs alongside their hearing aids.","marks":[]}]},{"_type":"block","_key":"b-9eb3e079","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-51076081","text":"Why use an ALD if I already have hearing aids?","marks":[]}]},{"_type":"block","_key":"b-f322a3dc","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-141f2403","text":"Even top-quality hearing aids can struggle in noisy or large spaces. ALDs focus on the sound you want to hear, improving clarity and reducing listening fatigue.","marks":[]}]},{"_type":"block","_key":"b-3ca29ad2","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-e1601e10","text":"Are ALDs easy to set up?","marks":[]}]},{"_type":"block","_key":"b-e0bd8a81","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9e274ef9","text":"Yes. Most ALDs are user-friendly and come with simple instructions. At JC Audiology, we can set them up for you and show you exactly how to use them.","marks":[]}]},{"_type":"block","_key":"b-e4185e85","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-092bbd96","text":"Can I take my ALD anywhere?","marks":[]}]},{"_type":"block","_key":"b-f7a04d00","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f2194a44","text":"Many ALDs are portable and can be used in multiple settings, but some (like hearing loops) are installed in specific locations. We can help you choose the right type for your needs.","marks":[]}]},{"_type":"block","_key":"b-915da1dc","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-bee2c27e","text":"Assistive Listening Devices in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-cf7c9e8d","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-411c8304","text":"If you want to make listening easier in challenging environments, JC Audiology is here to help.","marks":[]}]},{"_type":"block","_key":"b-c0a79b27","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9681133c","text":"Our Lutz, FL audiologist and hearing aid specialist will walk you through your ALD options, recommend devices that match your lifestyle, and ensure you know how to use them effectively.","marks":[]}]},{"_type":"block","_key":"b-2163fb72","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f8ebbde6","text":"Call us today to schedule your consultation and take the next step toward clearer, more comfortable listening.","marks":[]}]}]');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","route","meta_title","meta_description","body_content") VALUES('hearing-aids-products__hearing-aid-batteries','hearing-aids-products__hearing-aid-batteries','published',NULL,NULL,'2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z','2026-05-21T06:06:26.428Z',NULL,NULL,1,NULL,NULL,NULL,NULL,'Hearing Aid Batteries','/hearing-aids-products/hearing-aid-batteries/','Hearing Aid Batteries','JC Audiology provides hearing aid batteries in Lutz, FL, to ensure that your hearing devices always function at their best.','[{"_type":"block","_key":"b-47b19c2a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-5642abe8","text":"JC Audiology provides hearing aid batteries in Lutz, FL, to ensure that your hearing devices always function at their best.","marks":["em","strong"]}]},{"_type":"block","_key":"b-f79147a1","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c1a0df91","text":"Hearing aid batteries give your hearing aids the power they need to work. Without them, your hearing aids couldn’t make sounds louder, stream music, connect to Bluetooth, or help with ringing in the ears (tinnitus).","marks":[]}]},{"_type":"block","_key":"b-0b132265","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-d49b9b86","text":"You can choose disposable batteries that you replace, or rechargeable batteries you charge each night. ","marks":[]}]},{"_type":"block","_key":"b-89a3418c","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-bcd84f4f","text":"Types of Hearing Aid Batteries","marks":[]}]},{"_type":"block","_key":"b-059afb82","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-a8b2d33c","text":"Disposable Zinc-Air Batteries","marks":[]}]},{"_type":"block","_key":"b-22760a36","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-06c56656","text":"These are commonly referred to as “button” batteries. They are known to have a long shelf life.","marks":[]}]},{"_type":"block","_key":"b-a41cd0d8","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b25ca65f","text":"Disposable batteries can work for many days before needing to be replaced.","marks":[]}]},{"_type":"block","_key":"b-886819f0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-391b60fb","text":"They are color-coded based on their sizes.","marks":[]}]},{"_type":"block","_key":"b-59c5cca1","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-88125056","text":"Size 10 (Yellow)","marks":["strong"]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-ad1c0360","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-65ebb0e1","text":"Size 312 (Brown)","marks":["strong"]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-ce4ee962","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f3064c68","text":"Size 13 (Orange)","marks":["strong"]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-67b0bdb9","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-bc348136","text":"Size 675 (Blue)","marks":["strong"]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-407d6c31","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-04a8fb97","text":"Rechargeable Lithium-Ion Batteries","marks":[]}]},{"_type":"block","_key":"b-43f2f284","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b796856e","text":"These are built into many new hearing aids. They can provide all-day power (around 18-30 hours) and are recommended for individuals with dexterity (vision or hand) issues.","marks":[]}]},{"_type":"block","_key":"b-638193eb","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-aaa7a47c","text":"Rechargeable hearing aid batteries are also preferred by eco-conscious people since they can just be recharged every now and then.","marks":[]}]},{"_type":"block","_key":"b-3eb3a99f","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-9c5b3a7b","text":"Silver-Zinc Rechargeable Batteries","marks":[]}]},{"_type":"block","_key":"b-3e35971f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-52ec3635","text":"Less common, but some hearing aids still use them. They can be taken out and replaced when needed. Most companies now use lithium-ion instead.","marks":[]}]},{"_type":"block","_key":"b-1233054e","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-f13c62b4","text":"Which Battery Should You Choose?","marks":[]}]},{"_type":"block","_key":"b-04194f65","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-605744b7","text":"It depends on your hearing aid, your daily routine, and what feels easiest for you. At JC Audiology, we can help you pick the right one.","marks":[]}]},{"_type":"block","_key":"b-45a8b161","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-1abe6e8a","text":"Tips for Making Batteries Last Longer","marks":[]}]},{"_type":"block","_key":"b-c1347778","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a53608ec","text":"For Disposable Batteries:","marks":["strong"]}]},{"_type":"block","_key":"b-8967f593","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a42e8e8e","text":"Wait 5 minutes after removing the tab before use","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-5d6b9439","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a71c3808","text":"Store in a cool, dry place (not in the fridge)","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-bb57d739","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-13632f89","text":"Open the battery door at night","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-3e36640d","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-aa37a340","text":"Keep batteries clean and dry","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-7aaf27c4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-cb602dcd","text":"Carry extras in their case, not loose in your pocket","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-f99c7a32","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6d764306","text":"For Rechargeable Batteries:","marks":["strong"]}]},{"_type":"block","_key":"b-093853e1","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-9717a349","text":"Charge every night","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-7c592423","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-1fd6705d","text":"Use the charger made for your aids","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-2674af5a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3ba3a2bf","text":"Keep charger and aids dry","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-775156b3","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f77f3329","text":"Turn off if you’re not using them for a while","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-fade43a5","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-6a219625","text":"How to Know When to Change Your Battery","marks":[]}]},{"_type":"block","_key":"b-d1f1b5cf","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e2769b31","text":"Your hearing aid may beep, flash a light, or give a spoken warning when the battery is low.","marks":[]},{"_type":"span","_key":"s-38754455","text":"You might also notice that the sounds coming from the hearing aids are weaker or unclear.","marks":[]}]},{"_type":"block","_key":"b-d4a6a83a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-66834f5d","text":"If your hearing aids suddenly lose power or the volume becomes intermittent, it might be time for you to open a fresh battery pack.","marks":[]}]},{"_type":"block","_key":"b-a34cf6ca","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-7ef8973d","text":"Troubleshooting Battery Problems","marks":[]}]},{"_type":"block","_key":"b-5c3946f3","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-73c9a323","text":"If your hearing aid isn’t working, here’s a quick check:","marks":[]}]},{"_type":"block","_key":"b-c588f871","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-070370ef","text":"Is the battery the right size?","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-6da448e4","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3b56fdc2","text":"Is the battery door fully closed?","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-da7ec213","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-70be5756","text":"Are the battery contacts clean and dry?","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-19b2aeb9","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6ada750a","text":"Is the battery fresh or fully charged?","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-43a76914","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-5fd3361a","text":"If these steps don’t help, bring your hearing aid to JC Audiology for a quick check.","marks":[]}]},{"_type":"block","_key":"b-17d5e8be","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-554e2a7a","text":"Frequently Asked Questions","marks":[]}]},{"_type":"block","_key":"b-8d0474a3","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-9def706f","text":"Which type lasts longer?","marks":[]}]},{"_type":"block","_key":"b-790fc6bf","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-6d183d30","text":"Disposable batteries last for several days, while rechargeable batteries last all day and can be used for years before needing replacement.","marks":[]}]},{"_type":"block","_key":"b-2ce6da23","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-6527efd5","text":"Are rechargeables better for the environment?","marks":[]}]},{"_type":"block","_key":"b-2b07278d","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-17e081af","text":"Yes. They reduce the number of batteries that end up in landfills.","marks":[]}]},{"_type":"block","_key":"b-5472afc2","style":"h3","markDefs":[],"children":[{"_type":"span","_key":"s-956adfb6","text":"Can I switch my hearing aids from disposable to rechargeable?","marks":[]}]},{"_type":"block","_key":"b-3f656be2","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-fa52390e","text":"It depends on your hearing aid model. Ask an audiologist or hearing aid specialist to find out.","marks":[]}]},{"_type":"block","_key":"b-a4ed8ffb","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-39d1da19","text":"Hearing Aid Batteries in Lutz, FL","marks":[]}]},{"_type":"block","_key":"b-339deacc","style":"normal","markDefs":[{"_key":"link-844801e4","_type":"link","href":"../../index.html"}],"children":[{"_type":"span","_key":"s-9790bce6","text":"Need batteries for your hearing aids? Aside from offering a wide selection of ","marks":[]},{"_type":"span","_key":"s-09a65e11","text":"hearing aids in Lutz, FL","marks":["link-844801e4"]},{"_type":"span","_key":"s-e0bc710b","text":", JC Audiology has both disposable and rechargeable options for many models. Our hearing experts can help you choose the right size and type for your needs.","marks":[]}]},{"_type":"block","_key":"b-65f5a3f7","style":"normal","markDefs":[{"_key":"link-7da421cf","_type":"link","href":"../../contact/index.html"}],"children":[{"_type":"span","_key":"s-e86c9c19","text":"Call us","marks":["link-7da421cf"]},{"_type":"span","_key":"s-82001c4e","text":" or visit today to stock up!","marks":[]}]}]');
INSERT INTO "ec_staff_profile_pages" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","staff_profile_slug","route","meta_title","meta_description","content_body") VALUES('judith-l-reese-ph-d','judith-l-reese-ph-d','published',NULL,NULL,'2026-05-21T11:21:21.273Z','2026-05-21T11:21:21.273Z','2026-05-21T11:21:21.273Z',NULL,NULL,1,NULL,NULL,'en',NULL,'judith-l-reese-ph-d','/judith-l-reese-ph-d/','Judith L. Reese, Ph.D.','Judith L. Reese,Ph. D is an audiologist providing hearing tests, hearing aids, tinnitus evaluation and treatment, aural rehabilitation, and education on','[{"_type":"block","_key":"b-0a2bb7b0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-046059b8","text":"Judith L. Reese,Ph. D is an audiologist providing hearing tests, hearing aids, tinnitus evaluation and treatment, aural rehabilitation, and education on hearing loss prevention in Lutz, FL.","marks":["strong","em"]}]},{"_type":"block","_key":"b-27792af2","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ad4302ef","text":"Dr. Judith Reese, Ph.D., is a nationally-known audiologist who is highly respected by her academic peers, hearing aid manufacturers, fellow private practice audiologists, and most importantly, her patients. She has dedicated her career to improving hearing health in the Tampa Bay area, helping people reconnect with the sounds and moments that matter most.","marks":[]}]},{"_type":"block","_key":"b-9473f7d9","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-aa5cc948","text":"Decades of Experience in Hearing Care","marks":["strong"]}]},{"_type":"block","_key":"b-0f49ea71","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-ec0fe191","text":"Dr. Reese has worked with people who are hard of hearing in the Tampa Bay area since 1990. From 1995 to 2005, she served as a clinical audiologist with the Veterans Administration, earning the ","marks":[]},{"_type":"span","_key":"s-c893d735","text":"2004 Outstanding Performance Award","marks":["strong"]},{"_type":"span","_key":"s-24c972e5","text":" for exceeding performance standards and contributing to the VA’s mission.","marks":[]}]},{"_type":"block","_key":"b-4fa62d11","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-8f3291f6","text":"Before that, she worked in local nursing homes, providing aural rehabilitation for residents with hearing loss or deafness, and trained families and nursing staff on how to communicate effectively with them.","marks":[]}]},{"_type":"block","_key":"b-9109cf3e","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-da6473b0","text":"Academic Excellence and Research Recognition","marks":["strong"]}]},{"_type":"block","_key":"b-43ae43b2","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-3265a43a","text":"Dr. Reese earned her Ph.D. from the University of South Florida, completing an interdisciplinary program in ","marks":[]},{"_type":"span","_key":"s-6eb90c64","text":"Cognitive and Neural Psychology","marks":["strong"]},{"_type":"span","_key":"s-c5f739f0","text":" and ","marks":[]},{"_type":"span","_key":"s-df32d684","text":"Communication Sciences and Disorders","marks":["strong"]},{"_type":"span","_key":"s-25d248ac","text":".","marks":[]}]},{"_type":"block","_key":"b-b1a85444","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-58428c2e","text":"She has taught audiology and speech pathology students at the University of South Florida and published several articles on hearing aid use. In 2005, ","marks":[]},{"_type":"span","_key":"s-780a387f","text":"The Hearing Journal","marks":["em"]},{"_type":"span","_key":"s-898065e1","text":" praised her research as being of primary importance to hearing aid clinicians. She has presented her findings to professionals and hearing aid users across the United States.","marks":[]}]},{"_type":"block","_key":"b-4eb94be2","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-5b5c5e53","text":"Her dedication to clinical excellence earned her recognition as ","marks":[]},{"_type":"span","_key":"s-ba38b1ba","text":"Clinician of the Year","marks":["strong"]},{"_type":"span","_key":"s-06e8578d","text":" for her work with nursing home residents.","marks":[]}]},{"_type":"block","_key":"b-ae39ed61","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-493cc208","text":"Commitment to Personalized Hearing Care","marks":["strong"]}]},{"_type":"block","_key":"b-602b2f7c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-34cbcc2b","text":"At ","marks":[]},{"_type":"span","_key":"s-d3c0f1b9","text":"JC Audiology","marks":["strong"]},{"_type":"span","_key":"s-9404067f","text":", Dr. Reese provides:","marks":[]}]},{"_type":"block","_key":"b-00a99643","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-63b0c315","text":"Comprehensive audiological evaluations in a spacious sound booth, following the standards of the American Speech-Language-Hearing Association (ASHA) and the American Academy of Audiology (AAA)","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-cac8b75c","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-650750b8","text":"Prescription and fitting of hearing aids and assistive listening devices","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-7c183da0","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f20792aa","text":"Real-ear measurements and precise hearing aid adjustments","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-721cd040","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-f12dd9b7","text":"Aural rehabilitation to improve listening skills","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-9dd545f8","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a81319bc","text":"Hearing aid repairs and supplies","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-010d3e19","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-80c47c21","text":"Education on hearing loss prevention and tinnitus management","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-cebd2f8e","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-dc58a825","text":"Her goal is to ensure every patient receives the highest level of care with solutions tailored to their hearing needs, lifestyle, and comfort.","marks":[]}]},{"_type":"block","_key":"b-358aafc1","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-a77db44d","text":"Professional Certifications and Memberships","marks":["strong"]}]},{"_type":"block","_key":"b-8831a09f","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-0bf3203b","text":"Dr. Reese is committed to ongoing learning and professional excellence. She is:","marks":[]}]},{"_type":"block","_key":"b-f1caac6d","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-30d6a90d","text":"Certified","marks":["strong"]},{"_type":"span","_key":"s-b3758cc6","text":" by the American Speech-Language-Hearing Association (ASHA)","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-702b3bdd","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-825eda20","text":"Fellow","marks":["strong"]},{"_type":"span","_key":"s-562e63e0","text":" of the American Academy of Audiology (AAA)","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-2918d675","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-15208c7e","text":"Member","marks":["strong"]},{"_type":"span","_key":"s-b818811d","text":" of the American Academy of Rehabilitative Audiology","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-c1fdf7aa","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-c988bf0b","text":"Member","marks":["strong"]},{"_type":"span","_key":"s-0cd45f4a","text":" of the Florida Speech-Language-Hearing Association","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-52f80642","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-787112e6","text":"Licensed","marks":["strong"]},{"_type":"span","_key":"s-a9d8cc1a","text":" by the State of Florida Department of Health","marks":[]}],"listItem":"bullet","level":1},{"_type":"block","_key":"b-9b3462cf","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e364dd76","text":"Adjunct Professor","marks":["strong"]},{"_type":"span","_key":"s-dba75e78","text":" at the University of South Florida","marks":[]}]}]');
INSERT INTO "ec_staff_profile_pages" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","staff_profile_slug","route","meta_title","meta_description","content_body") VALUES('ryan-nurge-has','ryan-nurge-has','published',NULL,NULL,'2026-05-21T11:21:21.273Z','2026-05-21T11:35:49.233Z','2026-05-21T11:21:21.273Z',NULL,NULL,4,'01KS552XS6AG2CS6EN20B77S2P',NULL,'en',NULL,'ryan-nurge-has','/ryan-nurge-has/','Ryan Nurge, HAS','Mr. Ryan Nurge, a Florida Licensed Hearing Aid Specialist with a reputation for quality patient care, has joined JC Audiology as a new provider of superior','[{"_type":"block","_key":"jpsy4u43p","style":"normal","children":[{"_type":"span","_key":"mcd6m4fyi","text":"Mr. Ryan Nurge, a Florida Licensed Hearing Aid Specialist with a reputation for quality patient care, has joined JC Audiology as a new provider of superior hearing care.  Mr. Nurge is a Florida native and a graduate of Florida State University.  He excels in diagnostic assessments, fitting the right hearing device for a variety of patient lifestyles and needs, and utilizing the latest technological advancements in hearing care such as live speech mapping and real ear measurement. "}]},{"_type":"block","_key":"7xbs5zhpm","style":"normal","children":[{"_type":"span","_key":"9ehzb4321","text":"Mr. Nurge, a resident of Lutz, has been responsible for providing hearing care in Florida clinics that serve thousands of patients, and has earned stellar reviews from patients who have benefited from his expertise.  When not tending to his first passion for providing improved hearing to patients, Mr. Nurge works to improve his golf game on the weekends."}]}]');
INSERT INTO "ec_staff_profile_pages" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","staff_profile_slug","route","meta_title","meta_description","content_body") VALUES('charlie-reese','charlie-reese','published',NULL,NULL,'2026-05-21T11:21:21.273Z','2026-05-21T11:21:21.273Z','2026-05-21T11:21:21.273Z',NULL,NULL,1,NULL,NULL,'en',NULL,'charlie-reese','/charlie-reese/','Charlie Reese','Charlie Reese is Listener-in-Chief at JC Audiology, where he manages the business operations, HIPAA compliance activities and patient advocacy.','[{"_type":"block","_key":"b-4ab760a1","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-cc555188","text":"Charlie Reese is Listener-in-Chief at JC Audiology, where he manages the business operations, HIPAA compliance activities and patient advocacy.","marks":[]}]},{"_type":"block","_key":"b-20bb5d47","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-e82d903e","text":"He has a Masters in Business Administration from Saint Leo University, and has served in community leadership positions as president of a variety of organizations such as the Central Pasco Chamber of Commerce (he was Chamber Member of the Year in 1997), Central Pasco Habitat for Humanity, and Leadership Tampa Bay.","marks":[]}]},{"_type":"block","_key":"b-4e3bc2ed","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-a2f8242e","text":"He served as a Community Columnist for the Tampa Tribune, and his writings have been published in numerous publications throughout the country. His marketing success over the years has earned him statewide and national awards. He currently serves as a board member with the Society of G. K. Chesterton.","marks":[]}]}]');
INSERT INTO "ec_staff_profile_pages" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","staff_profile_slug","route","meta_title","meta_description","content_body") VALUES('graciela-wentz','graciela-wentz','published',NULL,NULL,'2026-05-21T11:21:21.273Z','2026-05-21T11:21:21.273Z','2026-05-21T11:21:21.273Z',NULL,NULL,1,NULL,NULL,'en',NULL,'graciela-wentz','/graciela-wentz/','Graciela Wentz','Graciela Wentz is the JC Audiology Patient Care Coordinator.  Graciela has many years experience working in the hearing care field at another dispensing','[{"_type":"block","_key":"b-a61f7a28","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-16bfa4d4","text":"Graciela Wentz is the JC Audiology Patient Care Coordinator.  Graciela has many years experience working in the hearing care field at another dispensing office.  She is bilingual (English, Spanish), and is dedicated to helping you book your first class journey toward better hearing","marks":[]}]}]');
INSERT INTO "ec_utility_pages" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","route","meta_title","meta_description","body_content") VALUES('resources__insurance','resources__insurance','published',NULL,NULL,'2026-05-21T06:06:26.430Z','2026-05-21T06:06:26.430Z','2026-05-21T06:06:26.430Z',NULL,NULL,1,NULL,NULL,NULL,NULL,'Insurance and Billing','/resources/insurance/','Insurance and Billing','Learn more about JC Audiology’s accepted insurance plans, billing, and payments.','[{"_type":"block","_key":"b-5c5016e1","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-5b4c1d82","text":"At JC Audiology, we want your hearing care to be as simple and stress-free as possible. We work with many insurance providers and will gladly check your benefits before your appointment so you know what’s covered. Our team can also explain payment options and help you understand your costs.","marks":[]}]},{"_type":"block","_key":"b-703cc324","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-fe7fc1d9","text":"If you don’t have insurance (or choose not to use it) you have the right to a ","marks":[]},{"_type":"span","_key":"s-f90765ab","text":"Good Faith Estimate","marks":["strong"]},{"_type":"span","_key":"s-b99dd4bf","text":" so you’ll know the expected cost of your care before your visit. We believe in transparency, so there are no surprises, just clear answers and a plan that works for you.","marks":[]}]},{"_type":"block","_key":"b-c049e0fc","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b07a7351","text":"If you have questions about insurance coverage, billing, or payment options, give us a call. We’re here to help you focus on better hearing, not paperwork.","marks":[]}]},{"_type":"block","_key":"b-a79fc46f","style":"h2","markDefs":[],"children":[{"_type":"span","_key":"s-78add9e8","text":"Questions? We’re Here to Help","marks":[]}]},{"_type":"block","_key":"b-94000c3a","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-b250d9f2","text":"If you have any questions about your insurance, billing, or financing options, don’t hesitate to contact us.","marks":[]}]},{"_type":"block","_key":"b-df2dc8b9","style":"normal","markDefs":[],"children":[{"_type":"span","_key":"s-32e3bf11","text":"Call us today to learn more or to schedule an appointment!","marks":[]}]}]');
